import React, { createContext, useContext, useState, useCallback } from 'react';
import { ToastMessage, ToastType } from '../types';

interface ToastContextType {
  addToast: (message: string, type?: ToastType, manualDismiss?: boolean) => void;
  removeToast: (id: string) => void;
  toasts: ToastMessage[];
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

export const ToastProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [toasts, setToasts] = useState<ToastMessage[]>([]);

  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  const addToast = useCallback((message: string, type: ToastType = 'info', manualDismiss: boolean = false) => {
    // If critical types, force manual dismiss
    const isCritical = type === 'level-up' || type === 'error' || type === 'shadow';
    const shouldManualDismiss = manualDismiss || isCritical;

    const id = crypto.randomUUID();

    // Prevent too many toasts (Queue Limit: 3)
    setToasts(prev => {
        if (prev.length >= 3) {
            return [...prev.slice(1), { id, message, type, manualDismiss: shouldManualDismiss }];
        }
        return [...prev, { id, message, type, manualDismiss: shouldManualDismiss }];
    });

    // Note: Auto-dismiss logic is now handled in the ToastSystem component
    // to allow for pause-on-hover interaction.
  }, []);

  return (
    <ToastContext.Provider value={{ addToast, removeToast, toasts }}>
      {children}
    </ToastContext.Provider>
  );
};

export const useToast = () => {
  const context = useContext(ToastContext);
  if (!context) throw new Error("useToast must be used within a ToastProvider");
  return context;
};

import React, { useEffect, useRef, useState } from 'react';
import { useToast } from '../context/ToastContext';
import { useSettings } from '../context/SettingsContext';
import { CheckCircle, AlertCircle, Info, Trophy, X, Medal, Ghost } from 'lucide-react';
import { ToastMessage, NotificationDuration } from '../types';

// Helper to get duration in ms
const getDuration = (setting: NotificationDuration): number => {
    switch (setting) {
        case 'short': return 3000;
        case 'medium': return 5000;
        case 'long': return 8000;
        case 'persistent': return 15000; // Very long but eventually dismisses if not critical
        default: return 5000;
    }
};

const ToastItem: React.FC<{ toast: ToastMessage; onRemove: (id: string) => void; durationSetting: NotificationDuration }> = ({ toast, onRemove, durationSetting }) => {
    const [isExiting, setIsExiting] = useState(false);
    const timerRef = useRef<NodeJS.Timeout | null>(null);
    const duration = getDuration(durationSetting);

    // Critical toasts do not respect the timer setting unless explicitly dismissed
    const isManual = toast.manualDismiss || durationSetting === 'persistent';

    const startTimer = () => {
        if (isManual) return; // Don't auto-dismiss critical or strictly persistent setting

        if (timerRef.current) clearTimeout(timerRef.current);
        timerRef.current = setTimeout(() => {
            triggerExit();
        }, duration);
    };

    const triggerExit = () => {
        setIsExiting(true);
        setTimeout(() => {
            onRemove(toast.id);
        }, 400); // Match animation duration
    };

    const handleMouseEnter = () => {
        if (timerRef.current) {
            clearTimeout(timerRef.current);
            timerRef.current = null;
        }
    };

    const handleMouseLeave = () => {
        if (!isExiting) {
            startTimer();
        }
    };

    useEffect(() => {
        startTimer();
        return () => {
            if (timerRef.current) clearTimeout(timerRef.current);
        };
    }, []);

    return (
        <div 
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
            onTouchStart={handleMouseEnter} // Pause on touch
            onTouchEnd={handleMouseLeave}
            className={`
                pointer-events-auto flex items-center justify-between p-4 rounded-xl shadow-2xl border backdrop-blur-md transition-all duration-500 transform
                ${isExiting ? 'opacity-0 translate-x-10 scale-95' : 'opacity-100 translate-x-0 scale-100 animate-slide-up'}
                ${toast.type === 'success' ? 'bg-green-900/90 border-green-700 text-white' : ''}
                ${toast.type === 'error' ? 'bg-red-900/90 border-red-700 text-white shadow-[0_0_15px_rgba(220,38,38,0.4)]' : ''}
                ${toast.type === 'info' ? 'bg-neutral-900/90 border-neutral-700 text-white' : ''}
                ${toast.type === 'level-up' ? 'bg-yellow-900/90 border-yellow-600 text-white shadow-[0_0_20px_rgba(234,179,8,0.4)]' : ''}
                ${toast.type === 'badge' ? 'bg-emerald-900/90 border-emerald-600 text-white' : ''}
                ${toast.type === 'shadow' ? 'bg-purple-900/90 border-purple-600 text-white shadow-[0_0_15px_rgba(147,51,234,0.4)]' : ''}
            `}
        >
            <div className="flex items-center gap-3">
                {toast.type === 'success' && <CheckCircle className="text-green-400" size={20} />}
                {toast.type === 'error' && <AlertCircle className="text-red-400 animate-pulse" size={20} />}
                {toast.type === 'info' && <Info className="text-blue-400" size={20} />}
                {toast.type === 'level-up' && <Trophy className="text-yellow-400 animate-bounce" size={24} />}
                {toast.type === 'badge' && <Medal className="text-emerald-400 animate-pulse" size={24} />}
                {toast.type === 'shadow' && <Ghost className="text-purple-400 animate-pulse" size={24} />}

                <p className="font-bold text-sm leading-tight">{toast.message}</p>
            </div>

            <button 
                onClick={triggerExit} 
                className={`ml-3 p-1 rounded-full transition-colors ${toast.type === 'error' || toast.type === 'level-up' ? 'bg-white/10 hover:bg-white/20 text-white' : 'text-white/50 hover:text-white'}`}
            >
                <X size={18} />
            </button>
        </div>
    );
};

export const ToastSystem: React.FC = () => {
  const { toasts, removeToast } = useToast();
  const { notificationDuration } = useSettings();

  if (toasts.length === 0) return null;

  return (
    <div className="fixed top-4 left-1/2 -translate-x-1/2 z-[100] flex flex-col gap-2 w-full max-w-sm px-4 pointer-events-none">
      {toasts.map(toast => (
        <ToastItem 
            key={toast.id} 
            toast={toast} 
            onRemove={removeToast} 
            durationSetting={notificationDuration}
        />
      ))}
    </div>
  );
};

import { ToastType } from "../types";

// Debounce Tracking
const sentNotifications = new Map<string, number>();

export const NotificationService = {
  requestPermission: async (): Promise<boolean> => {
    if (!('Notification' in window)) return false;

    if (Notification.permission === 'granted') return true;

    if (Notification.permission !== 'denied') {
      const permission = await Notification.requestPermission();
      return permission === 'granted';
    }

    return false;
  },

  /**
   * Sends a notification purely to the system (Browser/OS)
   * Uses ServiceWorkerRegistration if available for better Android support.
   */
  sendExternal: async (title: string, body?: string, isCritical: boolean = false) => {
    if (!('Notification' in window)) return;

    // Debounce Check: Prevent duplicate messages within 30 seconds
    const key = `${title}:${body}`;
    const now = Date.now();
    const lastSent = sentNotifications.get(key);

    if (lastSent && (now - lastSent < 30000)) {
        return; // Skip duplicate
    }
    sentNotifications.set(key, now);

    if (Notification.permission === 'granted') {
      // Cast to 'any' to allow 'vibrate' property which is not in standard TS definition but works on Android
      const options: any = {
        body: body,
        icon: 'https://cdn-icons-png.flaticon.com/512/2991/2991195.png', // Solo Level Icon style
        badge: 'https://cdn-icons-png.flaticon.com/512/2991/2991195.png', // Android Badge
        tag: 'solo-level-game', // Prevents duplicate notifications stacking poorly
        silent: false,
        vibrate: isCritical ? [500, 200, 500] : [200, 100, 200],
        requireInteraction: isCritical // PERSISTENCE: Keeps notification until user clicks
      };

      try {
        // Method 1: Try Service Worker (Best for PWA/Android)
        if ('serviceWorker' in navigator) {
            const registration = await navigator.serviceWorker.getRegistration();
            if (registration) {
                await registration.showNotification(title, options);
                return;
            }
        }

        // Method 2: Standard Fallback
        new Notification(title, options);
      } catch (e) {
        console.error("Notification Error:", e);
      }
    }
  },

  /**
   * Smart Dispatch:
   * - If app is VISIBLE (User is looking at it) -> Show In-App Toast.
   * - If app is HIDDEN (Background tab/minimized) -> Show System Notification.
   */
  dispatch: (
    title: string, 
    body: string, 
    addToast: (msg: string, type: ToastType, manualDismiss?: boolean) => void,
    type: ToastType = 'info',
    forceExternal: boolean = false
  ) => {
    // Determine Criticality
    const isCritical = type === 'error' || type === 'level-up' || type === 'shadow';

    if (!forceExternal && document.visibilityState === 'visible') {
      // User is IN the app -> Use Toast (Internal)
      // Combine title and body for toast
      addToast(`${title}: ${body}`, type, isCritical);
    } else {
      // User is OUT of the app -> Use System Notification (External)
      NotificationService.sendExternal(title, body, isCritical);
    }
  }
};

