import { ENERGY_RECOVERY_RATE, PILLAR_BASE_RATES, DIFFICULTY_CONFIG, XP_SCALING_FACTOR, SHADOW_TASKS, DAILY_QUEST_TARGETS, ENERGY_PER_QURAN_PAGE } from '../constants';
