// Helper for safe UUID
const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
    }
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

export const HistoryEngine = {
  /**
   * Calculates the Rank Score based on the formula:
   * (totalXP * 0.4) + (tasksCompleted * 0.3) + (streakMax * 0.2) + (exerciseConsistency * 0.1)
   */
  calculateRankScore: (xp: number, tasks: number, streak: number, exerciseCount: number): number => {
    // Normalize exercise consistency (assuming 5 times a week is "perfect" for score)
    const exerciseScore = Math.min(exerciseCount * 20, 100); 

    // Simple normalization for others to keep score readable (approx 0-1000 range usually)
    const score = (xp * 0.4) + (tasks * 10 * 0.3) + (streak * 10 * 0.2) + (exerciseScore * 0.1);
    return Math.floor(score);
  },

  /**
   * Creates a Weekly Snapshot from current stats and tasks
   */
  createWeeklySnapshot: (stats: UserStats, tasks: Task[]): WeeklyHistory => {
    const endDate = new Date().toISOString().split('T')[0];
    const startDate = stats.currentWeekStart || endDate;
    const monthId = startDate.substring(0, 7); // YYYY-MM

    const totalCompletedEver = tasks.filter(t => t.completed).length || 1;
    const ratio = stats.weeklyTasksCompleted > 0 ? (stats.weeklyTasksCompleted / totalCompletedEver) : 0;

    // Estimate pillar breakdown for the week based on ratio if precise tracking isn't available
    // (In a full DB we would query by date, here we approximate for local storage efficiency)
    const getPillarCount = (p: PillarType) => Math.ceil(tasks.filter(t => t.pillar === p && t.completed).length * ratio);

    const snapshot: WeeklyHistory = {
        weekId: generateId(),
        monthId: monthId,
        weekIndexInMonth: Math.ceil(new Date(startDate).getDate() / 7),
        startDate,
        endDate,

        totalXP: stats.weeklyXpAccumulated,
        tasksCompleted: stats.weeklyTasksCompleted,
        streakMax: stats.weeklyMaxStreak,

        // New: Failure Tracking
        missedTasksCount: stats.weeklyMissedTasks || 0,
        xpLost: stats.weeklyXpLost || 0,

        statsSummary: {
            learning: getPillarCount('Learning'),
            studying: getPillarCount('Studying'),
            exercise: getPillarCount('Exercise'),
            work: getPillarCount('Work'),
            entertainment: getPillarCount('Entertainment'),
            quran: getPillarCount('Quran'),
        },

        rankScore: HistoryEngine.calculateRankScore(
            stats.weeklyXpAccumulated, 
            stats.weeklyTasksCompleted, 
            stats.weeklyMaxStreak, 
            stats.weeklyExerciseCount
        ),
        createdAt: Date.now()
    };

    return snapshot;
  },

  /**
   * Aggregates 4 weeks into a Monthly Snapshot
   */
  createMonthlySnapshot: (monthId: string, weeks: WeeklyHistory[]): MonthlyHistory => {
    if (weeks.length === 0) throw new Error("No weeks to aggregate");

    const totalXP = weeks.reduce((sum, w) => sum + w.totalXP, 0);
    const totalTasks = weeks.reduce((sum, w) => sum + w.tasksCompleted, 0);
    const rankScores = weeks.map(w => w.rankScore);
    const bestScore = Math.max(...rankScores);
    const worstScore = Math.min(...rankScores);
    const maxStreak = Math.max(...weeks.map(w => w.streakMax));

    const consistencyRate = bestScore > 0 
        ? Math.round((weeks.reduce((sum, w) => sum + w.rankScore, 0) / weeks.length) / bestScore * 100) 
        : 0;

    // Determine Rank
    let monthRank = 'Novice';
    if (totalXP > 10000) monthRank = 'Legend';
    else if (totalXP > 5000) monthRank = 'Elite Hunter';
    else if (totalXP > 2000) monthRank = 'Grinder';
    else monthRank = 'Survivor';

    // Aggregate Pillar Stats
    const summary = {
        learning: 0, studying: 0, exercise: 0, work: 0, entertainment: 0, quran: 0
    };
    weeks.forEach(w => {
        summary.learning += w.statsSummary.learning;
        summary.studying += w.statsSummary.studying;
        summary.exercise += w.statsSummary.exercise;
        summary.work += w.statsSummary.work;
        summary.entertainment += w.statsSummary.entertainment;
        summary.quran += w.statsSummary.quran;
    });

    const snapshot: MonthlyHistory = {
        monthId,
        startDate: weeks[0].startDate,
        endDate: weeks[weeks.length - 1].endDate,
        weeksIncluded: weeks.map(w => w.weekId),

        totalXP,
        averageXP: Math.round(totalXP / weeks.length),
        totalTasks,

        bestWeekRankScore: bestScore,
        worstWeekRankScore: worstScore,

        statsSummary: summary,
        streakRecord: maxStreak,
        consistencyRate,
        monthRank,
        createdAt: Date.now()
    };

    return snapshot;
  },

  /**
   * ⚡ PROCESS TIME SKIP (The Engine Core)
   * Handles catching up on missed weeks/months when the user opens the app after a long time.
   */
  processTimeSkip: (
    stats: UserStats, 
    tasks: Task[], 
    weeklyHistory: WeeklyHistory[],
    monthlyHistory: MonthlyHistory[],
    weeklyReports: WeeklyReport[],
    monthlyReports: MonthlyReport[],
    weeklyRewards: WeeklyReward[],
    monthlyRewards: MonthlyReward[]
  ) => {
    const now = new Date();
    const currentWeekStart = new Date(stats.currentWeekStart);
    const diffTime = Math.abs(now.getTime() - currentWeekStart.getTime());
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));

    // Copies to modify
    let newStats = { ...stats };
    let newWeeklyHistory = [...weeklyHistory];
    let newMonthlyHistory = [...monthlyHistory];
    let newWeeklyReports = [...weeklyReports];
    let newMonthlyReports = [...monthlyReports];
    let newWeeklyRewards = [...weeklyRewards];
    let newMonthlyRewards = [...monthlyRewards];
    let reportsGenerated = 0;

    // If more than 7 days passed, we need to close the previous week(s)
    if (diffDays >= 7) {
        // 1. Close the active week (the one stored in stats)
        const newSnapshot = HistoryEngine.createWeeklySnapshot(newStats, tasks);
        newWeeklyHistory.push(newSnapshot);

        const previousWeek = weeklyHistory.length > 0 ? weeklyHistory[weeklyHistory.length - 1] : undefined;
        const report = ReportEngine.generateWeeklyReport(newSnapshot, previousWeek);
        newWeeklyReports.push(report);
        newWeeklyRewards.push(RewardEngine.generateWeeklyReward(report));
        reportsGenerated++;

        // 2. Reset Stats for new week
        // Note: If user missed multiple weeks, we don't generate "Empty" reports for the middle weeks 
        // to avoid spamming the user with "Lazy" reports. We just jump to "Now".
        const todayStr = now.toISOString().split('T')[0];
        newStats.currentWeekStart = todayStr;
        newStats.weeklyXpAccumulated = 0;
        newStats.weeklyTasksCompleted = 0;
        newStats.weeklyMaxStreak = 0;
        newStats.weeklyExerciseCount = 0;
        newStats.weeklyMissedTasks = 0;
        newStats.weeklyXpLost = 0;

        // 3. Check for Monthly Closure
        // Group weeks by month
        const currentMonthId = now.toISOString().substring(0, 7);
        const snapshotMonthId = newSnapshot.monthId;

        // If the snapshot we just created belongs to a month that is now OVER, or we have 4+ weeks
        const weeksInSnapshotMonth = newWeeklyHistory.filter(w => w.monthId === snapshotMonthId);
        const isMonthDifferent = snapshotMonthId !== currentMonthId;

        if (weeksInSnapshotMonth.length >= 4 || isMonthDifferent) {
             // Avoid duplicate month generation
             if (!newMonthlyHistory.find(m => m.monthId === snapshotMonthId)) {
                 const newMonthlySnapshot = HistoryEngine.createMonthlySnapshot(snapshotMonthId, weeksInSnapshotMonth);
                 newMonthlyHistory.push(newMonthlySnapshot);

                 const previousMonth = monthlyHistory.length > 0 ? monthlyHistory[monthlyHistory.length - 1] : undefined;
                 const monthlyReport = ReportEngine.generateMonthlyReport(newMonthlySnapshot, previousMonth);
                 newMonthlyReports.push(monthlyReport);
                 newMonthlyRewards.push(RewardEngine.generateMonthlyReward(monthlyReport));
                 reportsGenerated++;
             }
        }
    }

    return {
        stats: newStats,
        weeklyHistory: newWeeklyHistory,
        monthlyHistory: newMonthlyHistory,
        weeklyReports: newWeeklyReports,
        monthlyReports: newMonthlyReports,
        weeklyRewards: newWeeklyRewards,
        monthlyRewards: newMonthlyRewards,
        reportsGenerated
    };
  }
};

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo, useRef } from 'react';
import { GameState, Task, UserStats, PlayerProfile, WeeklyHistory, MonthlyHistory, WeeklyReport, MonthlyReport, WeeklyReward, MonthlyReward, DailyQuestProgress, BASE_XP_PER_LEVEL, DayOfWeek } from '../types';
import { ENERGY_RECOVERY_RATE, PILLAR_BASE_RATES, DIFFICULTY_CONFIG, XP_SCALING_FACTOR, SHADOW_TASKS, DAILY_QUEST_TARGETS, ENERGY_PER_QURAN_PAGE, DAYS_OF_WEEK, XP_PENALTY_RATIO, MAX_DAILY_XP_LOSS_PERCENT } from '../constants';
import { StorageService, defaultStats } from '../services/storage';
import { HistoryEngine } from '../services/historyEngine';
import { useToast } from './ToastContext';
import { useSettings } from './SettingsContext';
import { AudioService } from '../services/audioService';

interface GameContextType extends GameState {
  createProfile: (profileData: Omit<PlayerProfile, 'createdAt'>) => void;
  updateProfile: (updates: Partial<PlayerProfile>) => void;
  addTask: (task: Partial<Task>) => void;
  editTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  reorderTasks: (reorderedTasks: Task[]) => void;
  moveTask: (taskId: string, direction: 'up' | 'down') => void;
  resetProgress: () => void;
  setWeeklyChallenge: (title: string) => void;
  completeWeeklyChallenge: () => void;
  updateDailyQuest: (type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => void;
  showLevelUpModal: boolean;
  closeLevelUpModal: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

// Helper for local date string YYYY-MM-DD
const getLocalDateString = () => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
};

// Helper for safe UUID
const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
    }
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

// 2️⃣ Time Modifier Function
const getTimeModifier = () => {
    const hour = new Date().getHours();
    if (hour >= 6 && hour < 10) return { xp: 1.15, energy: 0.85 }; // Morning Bonus
    if (hour >= 22 || hour < 4) return { xp: 0.85, energy: 1.15 }; // Night Penalty
    return { xp: 1, energy: 1 };
};

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [playerProfile, setPlayerProfile] = useState<PlayerProfile | null>(null);

  // History State
  const [weeklyHistory, setWeeklyHistory] = useState<WeeklyHistory[]>([]);
  const [monthlyHistory, setMonthlyHistory] = useState<MonthlyHistory[]>([]);
  const [weeklyReports, setWeeklyReports] = useState<WeeklyReport[]>([]);
  const [monthlyReports, setMonthlyReports] = useState<MonthlyReport[]>([]);
  const [weeklyRewards, setWeeklyRewards] = useState<WeeklyReward[]>([]);
  const [monthlyRewards, setMonthlyRewards] = useState<MonthlyReward[]>([]);

  const [isLoaded, setIsLoaded] = useState(false);
  const [showLevelUpModal, setShowLevelUpModal] = useState(false);
  const { addToast } = useToast();
  const { soundEnabled, hapticsEnabled } = useSettings();

  // Ref to track if we are currently saving to avoid loops
  const isSaving = useRef(false);

  // Helper for Sound/Haptics
  const triggerFeedback = useCallback((type: 'success' | 'hard-success' | 'error' | 'levelup' | 'click' | 'boost' | 'mystery' | 'failure') => {
      if (hapticsEnabled && navigator.vibrate) {
          if (type === 'success') navigator.vibrate(50);
          if (type === 'hard-success') navigator.vibrate([100, 50, 100]);
          if (type === 'error') navigator.vibrate([50, 50, 50]);
          if (type === 'levelup') navigator.vibrate([100, 50, 100, 50, 200]);
          if (type === 'click') navigator.vibrate(10);
          if (type === 'failure') navigator.vibrate([500, 200]);
      }

      if (soundEnabled) {
          if (type === 'success') AudioService.playTaskComplete();
          if (type === 'hard-success') AudioService.playHardTaskComplete();
          if (type === 'error') AudioService.playEnergyWarning();
          if (type === 'click') AudioService.playTaskComplete(); // Simple blip
          if (type === 'boost') AudioService.playXpGain();
          if (type === 'mystery') AudioService.playMysteryReveal();
          if (type === 'failure') AudioService.playFailure();
      }
  }, [soundEnabled, hapticsEnabled]);

  // --- 1. INITIAL LOAD & TIME TRAVEL ENGINE ---
  useEffect(() => {
    const loadedProfile = StorageService.loadProfile();
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();
    const loadedWeekly = StorageService.loadWeeklyHistory();
    const loadedMonthly = StorageService.loadMonthlyHistory();
    const loadedWeeklyReports = StorageService.loadWeeklyReports();
    const loadedMonthlyReports = StorageService.loadMonthlyReports();
    const loadedWeeklyRewards = StorageService.loadWeeklyRewards();
    const loadedMonthlyRewards = StorageService.loadMonthlyRewards();

    if (loadedProfile) setPlayerProfile(loadedProfile);
    if (loadedTasks) setTasks(loadedTasks);

    // Set history states initially
    setWeeklyHistory(loadedWeekly);
    setMonthlyHistory(loadedMonthly);
    setWeeklyReports(loadedWeeklyReports);
    setMonthlyReports(loadedMonthlyReports);
    setWeeklyRewards(loadedWeeklyRewards);
    setMonthlyRewards(loadedMonthlyRewards);

    if (loadedStats) {
        let currentStats = { ...loadedStats };
        const today = getLocalDateString();
        const nowMs = Date.now();

        // B. Energy Regeneration (Offline Calculation)
        if (currentStats.energy < currentStats.maxEnergy) {
            const lastUpdate = currentStats.lastEnergyUpdate || nowMs;
            const diffInHours = (nowMs - lastUpdate) / (1000 * 60 * 60);
            const energyRecovered = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);
            if (energyRecovered > 0) {
                currentStats.energy = Math.min(currentStats.maxEnergy, currentStats.energy + energyRecovered);
                currentStats.lastEnergyUpdate = nowMs; // Reset timer base
                // NOTE: We don't play sound on init to avoid startling user
            }
        } else {
             currentStats.lastEnergyUpdate = nowMs;
        }

        // --- NEW: MISSED TASK LOGIC (Penalty System) ---
        // This runs BEFORE we potentially reset the day/week, locking in yesterday's failures.
        let updatedTasks = loadedTasks ? [...loadedTasks] : [];
        let missedCount = 0;
        let totalXpPenalty = 0;
        let energyPenalty = 0;

        // Map DayOfWeek to index 0-6 (Saturday to Friday)
        const dayIndices = { 'Saturday': 0, 'Sunday': 1, 'Monday': 2, 'Tuesday': 3, 'Wednesday': 4, 'Thursday': 5, 'Friday': 6 };
        const currentDayName = DAYS_OF_WEEK[new Date().getDay()].id as DayOfWeek; // Correct day from system
        const currentDayIdx = dayIndices[currentDayName];

        updatedTasks = updatedTasks.map(t => {
            if (!t.completed && !t.isMissed && t.day) {
                const taskDayIdx = dayIndices[t.day];

                // If the task was scheduled for a previous day in the current cycle
                if (taskDayIdx < currentDayIdx) {
                    // Check safe window: Created < 2 hours before midnight of that day?
                    // Simplified: Check if created more than 24h ago
                    const createdAgo = nowMs - t.createdAt;
                    if (createdAgo > 24 * 60 * 60 * 1000) {
                        missedCount++;
                        const penalty = Math.ceil(t.xpReward * XP_PENALTY_RATIO);
                        totalXpPenalty += penalty;

                        // Energy penalty for high difficulty
                        if (['A', 'S'].includes(t.difficulty)) {
                            energyPenalty += 5; // Flat 5 energy penalty
                        }

                        return { ...t, isMissed: true };
                    }
                }
            }
            return t;
        });

        // Apply Penalties
        if (missedCount > 0) {
            // Cap XP loss at 25% of current XP
            const maxLoss = Math.floor(currentStats.currentXp * MAX_DAILY_XP_LOSS_PERCENT);
            const actualXpLoss = Math.min(totalXpPenalty, maxLoss);

            currentStats.currentXp = Math.max(0, currentStats.currentXp - actualXpLoss);
            currentStats.energy = Math.max(0, currentStats.energy - energyPenalty);

            // Track stats
            currentStats.weeklyMissedTasks = (currentStats.weeklyMissedTasks || 0) + missedCount;
            currentStats.weeklyXpLost = (currentStats.weeklyXpLost || 0) + actualXpLoss;

            // Delayed Toast for UI feedback after render
            setTimeout(() => {
                addToast(`⚠️ ${missedCount} مهام فائتة! -${actualXpLoss} XP`, 'error');
                triggerFeedback('failure');
            }, 2000);

            // Update tasks state immediately
            setTasks(updatedTasks);
        }

        // C. Daily Quest Reset & Streak Decay
        if (currentStats.dailyQuest?.lastResetDate !== today) {
             // Streak Logic
             const lastTaskDate = new Date(currentStats.lastTaskCompletionDate || '1970-01-01');
             const yesterday = new Date();
             yesterday.setDate(yesterday.getDate() - 1);
             const lastTaskStr = lastTaskDate.toISOString().split('T')[0];
             const yesterdayStr = yesterday.toISOString().split('T')[0];

             if (lastTaskStr !== today && lastTaskStr !== yesterdayStr) {
                 if (currentStats.streak > 0) {
                    addToast("انقطعت السلسلة! 😢", "error");
                    currentStats.streak = 0;
                 }
             }

             // Reset Daily Quest
             currentStats.dailyQuest = {
                pushups: 0, situps: 0, squats: 0, run: 0,
                isCompleted: false,
                lastResetDate: today
            };
        }
        currentStats.lastLoginDate = today;

        // D. Process Time Skip (Weekly/Monthly Reports)
        const processed = HistoryEngine.processTimeSkip(
            currentStats,
            updatedTasks,
            loadedWeekly,
            loadedMonthly,
            loadedWeeklyReports,
            loadedMonthlyReports,
            loadedWeeklyRewards,
            loadedMonthlyRewards
        );

        if (processed.reportsGenerated > 0) {
            addToast(`تم إصدار ${processed.reportsGenerated} تقارير جديدة! 📊`, 'info');
            // Trigger mystery sound for new report
            if(soundEnabled) AudioService.playMysteryReveal();

            setWeeklyHistory(processed.weeklyHistory);
            setMonthlyHistory(processed.monthlyHistory);
            setWeeklyReports(processed.weeklyReports);
            setMonthlyReports(processed.monthlyReports);
            setWeeklyRewards(processed.weeklyRewards);
            setMonthlyRewards(processed.monthlyRewards);

            // Trigger batch save
            StorageService.saveWeeklyHistory(processed.weeklyHistory);
            StorageService.saveMonthlyHistory(processed.monthlyHistory);
            StorageService.saveWeeklyReports(processed.weeklyReports);
            StorageService.saveMonthlyReports(processed.monthlyReports);
            StorageService.saveWeeklyRewards(processed.weeklyRewards);
            StorageService.saveMonthlyRewards(processed.monthlyRewards);
        }

        setStats(processed.stats);
    }

    setIsLoaded(true);
  }, []);


  // --- 2. GAME LOOP (HEARTBEAT) ---
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    const tick = () => {
        setStats(prev => {
            const now = Date.now();

            // Energy Logic
            let newEnergy = prev.energy;
            let lastUpdate = prev.lastEnergyUpdate;

            if (newEnergy < prev.maxEnergy) {
                const diffInHours = (now - lastUpdate) / (1000 * 60 * 60);
                const thresholdHours = 1 / ENERGY_RECOVERY_RATE; 

                if (diffInHours >= thresholdHours) {
                    const energyGained = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);
                    newEnergy = Math.min(prev.maxEnergy, prev.energy + energyGained);
                    lastUpdate = lastUpdate + (energyGained / ENERGY_RECOVERY_RATE) * (1000 * 60 * 60); 

                    // Sound Effect for passive restore
                    if (soundEnabled) AudioService.playEnergyRestore();
                }
            } else {
                lastUpdate = now;
            }

            if (newEnergy === prev.energy && lastUpdate === prev.lastEnergyUpdate) {
                return prev;
            }

            return {
                ...prev,
                energy: newEnergy,
                lastEnergyUpdate: lastUpdate
            };
        });
    };

    const interval = setInterval(tick, 30000); // Check every 30 seconds
    return () => clearInterval(interval);
  }, [isLoaded, playerProfile, soundEnabled]);


  // --- 3. SHADOW TASK INJECTOR ---
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    if (stats.energy < 20) {
        setTasks(currentTasks => {
            const hasShadowTask = currentTasks.some(t => t.isShadow && !t.completed);
            if (!hasShadowTask) {
                const randomShadow = SHADOW_TASKS[Math.floor(Math.random() * SHADOW_TASKS.length)];
                const shadowTask: Task = {
                    id: generateId(),
                    title: `👻 ${randomShadow.title}`,
                    description: randomShadow.description,
                    pillar: 'Entertainment',
                    completed: false,
                    energyCost: -randomShadow.energyRestore,
                    xpReward: 0,
                    difficulty: 'E',
                    createdAt: Date.now(),
                    order: -1,
                    isShadow: true
                };
                addToast("ظهرت مهمة ظل! استعد طاقتك الآن.", 'shadow');
                if (soundEnabled) AudioService.playMysteryReveal();
                return [shadowTask, ...currentTasks];
            }
            return currentTasks;
        });
    }
  }, [stats.energy, isLoaded, playerProfile, soundEnabled]); 


  // --- 4. AUTO-SAVE SYSTEM ---
  useEffect(() => {
    if (isLoaded && playerProfile && !isSaving.current) {
        isSaving.current = true;
        StorageService.saveStats(stats);
        StorageService.saveTasks(tasks);
        setTimeout(() => { isSaving.current = false; }, 100);
    }
  }, [stats, tasks, isLoaded, playerProfile]);


  // --- ACTIONS ---

  const createProfile = useCallback((data: Omit<PlayerProfile, 'createdAt'>) => {
    const newProfile: PlayerProfile = {
        ...data,
        createdAt: new Date().toISOString()
    };
    StorageService.initializeNewAccount(newProfile);
    setPlayerProfile(newProfile);
    setStats({
        ...defaultStats,
        lastLoginDate: getLocalDateString()
    });
    setTasks([]);
    triggerFeedback('success');
    addToast('أهلاً بك في رحلة التطوير! 🚀', 'success');
  }, [addToast, triggerFeedback]);

  const updateProfile = useCallback((updates: Partial<PlayerProfile>) => {
    setPlayerProfile(prev => {
        if (!prev) return null;
        const updated = { ...prev, ...updates };
        StorageService.saveProfile(updated);
        return updated;
    });
    addToast('تم تحديث البيانات', 'success');
  }, [addToast]);

  const addTask = useCallback((taskData: Partial<Task>) => {
    setTasks(prev => {
        const maxOrder = prev.length > 0 ? Math.max(...prev.map(t => t.order)) : 0;
        const pillar = taskData.pillar || 'Work';
        const difficulty = taskData.difficulty || 'D';

        const baseRates = PILLAR_BASE_RATES[pillar];
        const multiplier = DIFFICULTY_CONFIG[difficulty].multiplier;

        const newTask: Task = {
          id: generateId(),
          title: taskData.title || (pillar === 'Quran' ? 'ورد القرآن' : 'مهمة جديدة'),
          description: taskData.description || '',
          pillar: pillar,
          completed: false,
          difficulty: difficulty,
          energyCost: Math.ceil(baseRates.energy * multiplier),
          xpReward: Math.ceil(baseRates.xp * multiplier),
          dueDate: taskData.dueDate,
          day: taskData.day,
          createdAt: Date.now(),
          order: maxOrder + 1,
          pages: taskData.pages
        };
        return [...prev, newTask];
    });
    triggerFeedback('click');
    addToast('تمت إضافة المهمة بنجاح', 'success');
  }, [addToast, triggerFeedback]);

  const editTask = useCallback((id: string, updates: Partial<Task>) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;
      const pillar = updates.pillar || t.pillar;
      const difficulty = updates.difficulty || t.difficulty;
      const baseRates = PILLAR_BASE_RATES[pillar];
      const multiplier = DIFFICULTY_CONFIG[difficulty].multiplier;

      return { 
          ...t, 
          ...updates,
          energyCost: Math.ceil(baseRates.energy * multiplier),
          xpReward: Math.ceil(baseRates.xp * multiplier)
      };
    }));
    addToast('تم حفظ التعديلات', 'success');
  }, [addToast]);

  const deleteTask = useCallback((id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    addToast('تم حذف المهمة', 'info');
  }, [addToast]);

  const reorderTasks = useCallback((reorderedTasks: Task[]) => {
      setTasks(reorderedTasks);
  }, []);

  const moveTask = useCallback((taskId: string, direction: 'up' | 'down') => {
      setTasks(prevTasks => {
        const sortedTasks = [...prevTasks].sort((a, b) => a.order - b.order);
        const sortedIndex = sortedTasks.findIndex(t => t.id === taskId);
        if (sortedIndex === -1) return prevTasks;
        if (direction === 'up' && sortedIndex > 0) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex - 1].order;
            sortedTasks[sortedIndex - 1].order = tempOrder;
        } else if (direction === 'down' && sortedIndex < sortedTasks.length - 1) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex + 1].order;
            sortedTasks[sortedIndex + 1].order = tempOrder;
        }
        return [...sortedTasks];
      });
      triggerFeedback('click');
  }, [triggerFeedback]);

  const setWeeklyChallenge = useCallback((title: string) => {
    setStats(prev => ({
        ...prev,
        weeklyChallenge: {
            id: generateId(),
            title: title,
            weekStart: getLocalDateString(),
            completed: false
        }
    }));
    triggerFeedback('click');
    addToast('تم تحديد التحدي الأسبوعي! 🎯', 'info');
  }, [addToast, triggerFeedback]);

  const completeWeeklyChallenge = useCallback(() => {
    setStats(prev => {
        if (!prev.weeklyChallenge || prev.weeklyChallenge.completed) return prev;

        const bonusXP = Math.floor(prev.maxXp * 0.25);

        let currentXp = prev.currentXp + bonusXP;
        let weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + bonusXP;

        let level = prev.level;
        let maxXp = prev.maxXp;
        let didLevelUp = false;

        while (currentXp >= maxXp) {
            currentXp -= maxXp;
            level += 1;
            maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
            didLevelUp = true;
        }

        let newAttributes = { ...prev.hunterAttributes };
        if (didLevelUp) {
             newAttributes.strength += 1;
             newAttributes.intelligence += 1;
             newAttributes.vitality += 1;
             newAttributes.sense += 1;
             newAttributes.agility += 1;
        }

        if (didLevelUp) {
            setShowLevelUpModal(true);
        } else {
            addToast(`مكافأة التحدي: +${bonusXP} XP 🔥`, 'success');
            triggerFeedback('hard-success');
        }

        return {
            ...prev,
            weeklyChallenge: { ...prev.weeklyChallenge!, completed: true },
            currentXp, level, maxXp, weeklyXpAccumulated,
            hunterAttributes: newAttributes
        };
    });
  }, [addToast, triggerFeedback]);

  const closeLevelUpModal = useCallback(() => {
    setShowLevelUpModal(false);
  }, []);

  const updateDailyQuest = useCallback((type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => {
      setStats(prev => {
          if (!prev.dailyQuest || prev.dailyQuest.isCompleted) return prev;

          const newStats = { ...prev };
          newStats.dailyQuest = { ...prev.dailyQuest, [type]: Math.min(DAILY_QUEST_TARGETS[type], amount) };

          const { pushups, situps, squats, run } = newStats.dailyQuest;
          const target = DAILY_QUEST_TARGETS;

          if (pushups >= target.pushups && situps >= target.situps && squats >= target.squats && run >= target.run) {
              if (!prev.dailyQuest.isCompleted) {
                  newStats.dailyQuest.isCompleted = true;
                  newStats.energy = newStats.maxEnergy;
                  const dailyXpReward = Math.floor(prev.maxXp * 0.15);
                  newStats.currentXp += dailyXpReward;

                  newStats.hunterAttributes.strength += 2;
                  newStats.hunterAttributes.vitality += 1;

                  addToast(`مهمة يومية مكتملة! طاقة كاملة + ${dailyXpReward}XP`, 'success');
                  triggerFeedback('hard-success');
              }
          }
          triggerFeedback('click');
          return newStats;
      });
  }, [addToast, triggerFeedback]);

  const completeTask = useCallback((id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed || task.isMissed) return; // Ignore missed tasks

    if (task.isShadow) {
        setStats(prev => ({
            ...prev,
            energy: Math.min(prev.maxEnergy, prev.energy + Math.abs(task.energyCost))
        }));
        setTasks(prev => prev.filter(t => t.id !== id));
        addToast("تم استعادة بعض الطاقة! 👻", 'success');
        triggerFeedback('mystery');
        return;
    }

    const timeMod = getTimeModifier();
    const baseRates = PILLAR_BASE_RATES[task.pillar];
    const multiplier = DIFFICULTY_CONFIG[task.difficulty || 'D'].multiplier;
    const rawEnergyCost = Math.ceil(baseRates.energy * multiplier * timeMod.energy);
    const finalEnergyCost = baseRates.energy < 0 ? baseRates.energy * multiplier : rawEnergyCost; 

    if (task.pillar !== 'Quran' && finalEnergyCost > 0 && stats.energy < finalEnergyCost) {
        addToast("طاقة غير كافية! خذ استراحة.", 'error');
        triggerFeedback('error');
        return;
    }

    setTasks(currentTasks => currentTasks.map(t => t.id === id ? { ...t, completed: true } : t));

    setStats(prev => {
        const today = getLocalDateString();
        let newStreak = prev.streak;
        let lastTaskDate = prev.lastTaskCompletionDate;

        if (lastTaskDate !== today) {
            const d = new Date();
            d.setDate(d.getDate() - 1);
            const yesterdayStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
            if (lastTaskDate === yesterdayStr) newStreak += 1;
            else newStreak = 1;
            lastTaskDate = today;
        }

        let weeklyTasks = (prev.weeklyTasksCompleted || 0) + 1;
        let weeklyStreak = Math.max((prev.weeklyMaxStreak || 0), newStreak);
        let weeklyExercise = (prev.weeklyExerciseCount || 0) + (task.pillar === 'Exercise' ? 1 : 0);

        let newStats = { 
            ...prev,
            streak: newStreak,
            lastTaskCompletionDate: lastTaskDate,
            lastEnergyUpdate: Date.now(),
            weeklyTasksCompleted: weeklyTasks,
            weeklyMaxStreak: weeklyStreak,
            weeklyExerciseCount: weeklyExercise,
            hunterAttributes: { ...prev.hunterAttributes }
        };

        const attrGain = 0.5 * multiplier;
        if (task.pillar === 'Exercise') newStats.hunterAttributes.strength += attrGain;
        if (task.pillar === 'Studying' || task.pillar === 'Learning') newStats.hunterAttributes.intelligence += attrGain;
        if (task.pillar === 'Entertainment') newStats.hunterAttributes.vitality += attrGain;
        if (task.pillar === 'Quran') newStats.hunterAttributes.sense += attrGain;
        if (task.pillar === 'Work') newStats.hunterAttributes.agility += attrGain;

        let didLevelUp = false;

        if (task.pillar === 'Quran') {
            const pagesToAdd = task.pages || 1;
            newStats.quranPagesRead = (prev.quranPagesRead || 0) + pagesToAdd;
            const energyGain = pagesToAdd * ENERGY_PER_QURAN_PAGE;
            newStats.energy = Math.min(newStats.maxEnergy, prev.energy + energyGain);
            addToast(`✅ ${pagesToAdd} صفحة | +${energyGain}⚡ طاقة`, 'success');
            if(soundEnabled) AudioService.playEnergyRestore();
        } 
        else {
            newStats.energy = Math.min(newStats.maxEnergy, prev.energy - finalEnergyCost);

            let finalXpReward = Math.ceil(baseRates.xp * multiplier * timeMod.xp);
            let currentXp = prev.currentXp + finalXpReward;
            newStats.weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + finalXpReward;

            let level = prev.level;
            let maxXp = prev.maxXp;
            while (currentXp >= maxXp) {
                currentXp -= maxXp;
                level += 1;
                maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
                didLevelUp = true;
            }

            if (!didLevelUp) {
                const energyMsg = finalEnergyCost > 0 ? `-${finalEnergyCost}⚡` : `+${Math.abs(finalEnergyCost)}⚡`;
                addToast(`+${finalXpReward} XP | ${energyMsg}`, 'success');
                // Play different sound for hard tasks (B rank or higher)
                const isHard = ['B', 'A', 'S'].includes(task.difficulty);
                if (isHard) triggerFeedback('hard-success');
                else triggerFeedback('success');
            } else {
                 // Level up audio is handled in the modal for cinematic sync
                 // But we trigger the XP gain sound first
                 if(soundEnabled) AudioService.playXpGain();
            }

            newStats.currentXp = currentXp;
            newStats.level = level;
            newStats.maxXp = maxXp;
        }

        if (didLevelUp) {
            newStats.hunterAttributes.strength += 1;
            newStats.hunterAttributes.intelligence += 1;
            newStats.hunterAttributes.vitality += 1;
            newStats.hunterAttributes.sense += 1;
            newStats.hunterAttributes.agility += 1;

            setShowLevelUpModal(true);
        }

        return newStats;
    });
  }, [tasks, stats.energy, addToast, triggerFeedback, soundEnabled]);

  const resetProgress = useCallback(() => {
    if (confirm("هل أنت متأكد من حذف الحساب وإعادة البدء؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
      setWeeklyHistory([]);
      setMonthlyHistory([]);
      setWeeklyReports([]);
      setMonthlyReports([]);
      setWeeklyRewards([]);
      setMonthlyRewards([]);
      setPlayerProfile(null);
      addToast('تم إعادة تعيين الحساب', 'info');
      triggerFeedback('error');
    }
  }, [addToast, triggerFeedback]);

  const value = useMemo(() => ({
    stats,
    tasks,
    playerProfile,
    weeklyHistory,
    monthlyHistory,
    weeklyReports,
    monthlyReports,
    weeklyRewards,
    monthlyRewards,
    createProfile,
    updateProfile,
    addTask,
    editTask,
    deleteTask,
    completeTask, 
    reorderTasks,
    moveTask,
    resetProgress,
    setWeeklyChallenge,
    completeWeeklyChallenge,
    showLevelUpModal,
    closeLevelUpModal,
    updateDailyQuest
  }), [stats, tasks, playerProfile, weeklyHistory, monthlyHistory, weeklyReports, monthlyReports, weeklyRewards, monthlyRewards, createProfile, updateProfile, addTask, editTask, deleteTask, completeTask, reorderTasks, moveTask, resetProgress, setWeeklyChallenge, completeWeeklyChallenge, showLevelUpModal, closeLevelUpModal, updateDailyQuest]);

  return (
    <GameContext.Provider value={value}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { useState, useEffect } from 'react';
import { Task } from '../types';
import { CheckCircle2, Trash2, Zap, Pencil, CalendarClock, Circle, ChevronUp, ChevronDown, Moon, Sun, Ghost, XCircle, Lock } from 'lucide-react';
import { PILLARS } from '../constants';
import { useGame } from '../context/GameContext';

interface Props {
  task: Task;
  onComplete: (id: string) => void;
  onDelete: (id: string) => void;
  onEdit?: (task: Task) => void;
  canAfford: boolean;
}

export const TaskItem: React.FC<Props> = React.memo(({ task, onComplete, onDelete, onEdit, canAfford }) => {
  const { moveTask } = useGame();
  const pillarInfo = PILLARS.find(p => p.id === task.pillar);
  const [isVisible, setIsVisible] = useState(false);
  const [isCompleting, setIsCompleting] = useState(false);

  // Time Modifier Check
  const hour = new Date().getHours();
  const isMorning = hour >= 6 && hour < 10;
  const isNight = hour >= 22 || hour < 4;

  useEffect(() => {
    const timer = setTimeout(() => setIsVisible(true), 50);
    return () => clearTimeout(timer);
  }, []);

  const handleComplete = () => {
    if (task.isMissed) return;
    setIsCompleting(true);
    // Play sound logic could go here if sound was enabled
    setTimeout(() => {
        onComplete(task.id);
        setIsCompleting(false);
    }, 400); // Slightly longer for the effect
  };

  // Safe comparison for YYYY-MM-DD
  const isOverdue = React.useMemo(() => {
    if (!task.dueDate) return false;
    const now = new Date();
    const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
    return task.dueDate < todayStr;
  }, [task.dueDate]);

  // Shadow Task Styling
  if (task.isShadow) {
      return (
        <div className={`
            relative p-4 rounded-2xl border mb-3 transition-all duration-500 animate-pop
            bg-purple-900/10 border-purple-500/30 flex items-center justify-between
            ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}
            ${isCompleting ? 'scale-95 opacity-0' : 'scale-100'}
        `}>
            <div className="flex items-center gap-3">
                <div className="bg-purple-900/50 p-2 rounded-full">
                    <Ghost size={20} className="text-purple-300" />
                </div>
                <div>
                    <h4 className="font-bold text-purple-200 text-sm">{task.title}</h4>
                    <p className="text-[10px] text-purple-400">{task.description}</p>
                    <span className="text-[10px] font-bold text-green-400 mt-1 block">+{Math.abs(task.energyCost)} طاقة</span>
                </div>
            </div>
            <button
                onClick={handleComplete}
                className="bg-purple-600 text-white p-2 rounded-xl hover:bg-purple-500 transition-colors shadow-lg"
            >
                <CheckCircle2 size={20} />
            </button>
        </div>
      );
  }

  // Missed Task Styling
  if (task.isMissed) {
      return (
        <div className={`
            relative p-4 rounded-2xl border mb-3 transition-all duration-500 opacity-70 hover:opacity-100 grayscale-[0.5]
            bg-red-950/20 border-red-900/50 flex items-center justify-between
            ${isVisible ? 'translate-y-0' : 'translate-y-4'}
        `}>
            <div className="flex items-center gap-3">
                <div className="bg-red-900/20 p-2 rounded-full border border-red-900/50">
                    <XCircle size={20} className="text-red-500" />
                </div>
                <div>
                     <div className="flex items-center gap-2 mb-1">
                        <span className="text-[9px] font-black uppercase tracking-wider text-red-500 bg-red-900/20 px-1.5 rounded border border-red-900/30">MISSED</span>
                        {pillarInfo && (
                            <span className={`text-[9px] font-bold ${pillarInfo.color} opacity-60`}>{pillarInfo.label}</span>
                        )}
                    </div>
                    <h4 className="font-bold text-neutral-400 text-lg line-through decoration-red-900/50">{task.title}</h4>
                    <span className="text-[10px] font-mono text-red-400/60 mt-1 block flex items-center gap-1">
                        <Lock size={10} /> Locked
                    </span>
                </div>
            </div>

             <button
                onClick={() => {
                    if(confirm('هل تريد حذف هذه المهمة الفائتة من السجل؟')) onDelete(task.id);
                }}
                className="p-3 text-neutral-600 hover:text-red-500 hover:bg-red-900/10 rounded-xl transition-colors"
            >
                <Trash2 size={18} />
            </button>
        </div>
      );
  }

  return (
    <div 
        className={`
            relative p-4 rounded-2xl border mb-3 transition-all duration-500 group overflow-hidden
            ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}
            ${task.completed 
                ? 'bg-neutral-950/50 border-neutral-900 opacity-60 grayscale' 
                : 'bg-neutral-900 border-neutral-800 hover:border-neutral-700 shadow-md hover:shadow-xl hover:translate-x-1'}
            ${isCompleting ? 'scale-95' : 'scale-100'}
        `}
    >
      {/* Completion Flash Effect */}
      {isCompleting && (
          <div className="absolute inset-0 bg-white/20 z-20 animate-pulse pointer-events-none" />
      )}

      {/* Selection Line */}
      {!task.completed && (
        <div className={`absolute right-0 top-0 bottom-0 w-1 ${pillarInfo?.color.replace('text-', 'bg-')} opacity-0 group-hover:opacity-100 transition-opacity`} />
      )}

      <div className="flex justify-between items-start">
        <div className="flex-1 ml-2">

            {/* Meta Header */}
            <div className="flex items-center gap-2 mb-2 flex-wrap">
                {pillarInfo && (
                    <div className={`flex items-center gap-1 text-[10px] font-bold px-2 py-1 rounded-md bg-black/40 border border-neutral-800 ${pillarInfo.color}`}>
                         <pillarInfo.icon size={10} />
                        <span>{pillarInfo.label}</span>
                    </div>
                )}
                {task.dueDate && (
                     <div className={`flex items-center gap-1 text-[10px] font-bold px-2 py-1 rounded-md bg-black/40 border border-neutral-800 ${isOverdue && !task.completed ? 'text-red-500 border-red-900/50' : 'text-neutral-500'}`}>
                        <CalendarClock size={10} />
                        <span>{task.dueDate}</span>
                    </div>
                )}
                {/* Time Effect Badge */}
                {!task.completed && task.pillar !== 'Quran' && (
                    <>
                        {isMorning && <div className="flex items-center gap-1 text-[10px] font-bold px-2 py-1 rounded-md bg-yellow-500/10 border border-yellow-500/30 text-yellow-500"><Sun size={10}/> بوناس صباحي</div>}
                        {isNight && <div className="flex items-center gap-1 text-[10px] font-bold px-2 py-1 rounded-md bg-blue-900/30 border border-blue-500/30 text-blue-400"><Moon size={10}/> إرهاق ليلي</div>}
                    </>
                )}
            </div>

          <h4 className={`font-bold text-white text-lg leading-snug transition-all ${task.completed ? 'line-through text-neutral-500' : 'group-hover:text-gray-100'}`}>
            {task.title}
          </h4>
          {task.description && <p className="text-sm text-neutral-400 mt-2 leading-relaxed font-light">{task.description}</p>}

          {/* Rewards */}
          {!task.completed && (
            <div className="flex items-center mt-4 gap-3">
                <div className="flex items-center text-[10px] text-yellow-500 font-mono bg-yellow-500/10 px-2 py-1 rounded border border-yellow-500/20">
                    <Zap size={10} className="ml-1 fill-yellow-500" /> 
                    <span className="font-bold">-{task.energyCost} طاقة</span>
                </div>
                <div className="text-[10px] text-game-red font-mono font-bold bg-game-red/10 px-2 py-1 rounded border border-game-red/20">
                    +{task.xpReward} XP
                </div>
            </div>
          )}
        </div>

        {/* Actions & Reordering */}
        <div className="flex flex-col gap-1 pl-2 items-center">
            {/* Reorder Buttons (Only visible if not completed) */}
            {!task.completed && (
                <div className="flex flex-col gap-1 mb-2 opacity-50 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => moveTask(task.id, 'up')} className="p-1 hover:bg-neutral-800 rounded text-neutral-500 hover:text-white">
                        <ChevronUp size={16} />
                    </button>
                    <button onClick={() => moveTask(task.id, 'down')} className="p-1 hover:bg-neutral-800 rounded text-neutral-500 hover:text-white">
                        <ChevronDown size={16} />
                    </button>
                </div>
            )}

            {!task.completed && (
                <button
                onClick={handleComplete}
                disabled={!canAfford || isCompleting}
                className={`
                    p-3 rounded-xl transition-all duration-300 relative overflow-hidden
                    ${canAfford 
                        ? 'bg-neutral-800 text-neutral-400 hover:bg-game-red hover:text-white hover:scale-110 shadow-lg' 
                        : 'bg-neutral-900 text-neutral-700 cursor-not-allowed'}
                `}
                title={canAfford ? "إكمال المهمة" : "لا توجد طاقة كافية"}
                >
                    {isCompleting && <span className="absolute inset-0 bg-white opacity-30 animate-ping rounded-xl"></span>}
                    {canAfford ? <CheckCircle2 size={22} className={isCompleting ? 'animate-bounce' : ''} /> : <Circle size={22} className="stroke-neutral-700" />}
                </button>
            )}

            {!task.completed && onEdit && (
                <button
                    onClick={() => onEdit(task)}
                    className="p-3 text-neutral-600 hover:text-white hover:bg-neutral-800 rounded-xl transition-colors scale-90 hover:scale-100"
                >
                    <Pencil size={18} />
                </button>
            )}

            <button
                onClick={() => {
                    if(confirm('هل أنت متأكد من حذف هذه المهمة؟')) onDelete(task.id);
                }}
                className="p-3 text-neutral-600 hover:text-red-500 hover:bg-neutral-800/50 rounded-xl transition-colors scale-90 hover:scale-100"
            >
                <Trash2 size={18} />
            </button>
        </div>
      </div>
    </div>
  );
});

import React, { useState, useMemo } from 'react';
import { useGame } from '../context/GameContext';
import { useSettings } from '../context/SettingsContext';
import { DAYS_OF_WEEK } from '../constants';
import { TaskItem } from './TaskItem';
import { DayOfWeek, Task } from '../types';
import { Calendar, CheckCircle2, Coffee, Plus, Lock, AlertCircle } from 'lucide-react';
import { CircularProgress } from './CircularProgress';
import { useToast } from '../context/ToastContext';

interface Props {
  onAddTask: (day: DayOfWeek) => void;
  onEditTask: (task: Task) => void;
}

export const WeeklyPlanner: React.FC<Props> = ({ onAddTask, onEditTask }) => {
  const { tasks, completeTask, deleteTask, stats } = useGame();
  const { t } = useSettings();
  const { addToast } = useToast();

  // State to track expanded days (default to today or Saturday)
  const [expandedDay, setExpandedDay] = useState<DayOfWeek | null>('Saturday');

  // Calculate Today's Index (0 = Saturday, ... 6 = Friday)
  const todayIndex = (new Date().getDay() + 1) % 7;

  // Optimize: Group tasks by day once using useMemo instead of filtering 7 times inside map
  const tasksByDay = useMemo(() => {
    const grouped: Record<string, Task[]> = {};
    DAYS_OF_WEEK.forEach(d => grouped[d.id] = []);

    tasks.forEach(task => {
        if (task.day && grouped[task.day]) {
            grouped[task.day].push(task);
        }
    });
    return grouped;
  }, [tasks]);

  const handleAddClick = (dayIndex: number, dayId: DayOfWeek) => {
      if (dayIndex < todayIndex) {
          addToast(t('dayLockedMsg') || "هذا اليوم قد مضى. لا يمكن إضافة مهام جديدة.", 'error');
          return;
      }
      onAddTask(dayId);
  };

  return (
    <div className="h-full overflow-y-auto pb-24 animate-fade-in p-4 space-y-4 no-scrollbar">
        <div className="flex items-center gap-2 mb-2">
            <Calendar className="text-game-red" size={24} />
            <h2 className="text-2xl font-black text-white">{t('weeklyPlanner')}</h2>
        </div>

        {DAYS_OF_WEEK.map((day, index) => {
            const isRestDay = day.id === 'Friday';
            const isPast = index < todayIndex;
            const isToday = index === todayIndex;

            const dayTasks = tasksByDay[day.id] || [];
            const completedCount = dayTasks.filter(t => t.completed).length;
            const totalCount = dayTasks.length;
            const progress = totalCount > 0 ? (completedCount / totalCount) * 100 : 0;
            const isExpanded = expandedDay === day.id;

            return (
                <div 
                    key={day.id} 
                    className={`
                        border rounded-2xl overflow-hidden transition-all duration-300 relative
                        ${isPast 
                            ? 'bg-neutral-950/80 border-neutral-900 opacity-70 grayscale-[0.8]' 
                            : isRestDay 
                                ? 'bg-gradient-to-br from-emerald-900/20 to-neutral-900 border-emerald-900/50' 
                                : isToday
                                    ? 'bg-neutral-900 border-game-red/50 shadow-[0_0_15px_rgba(220,38,38,0.1)]'
                                    : 'bg-neutral-900 border-neutral-800'}
                    `}
                >
                    {/* Header Card */}
                    <div 
                        onClick={() => setExpandedDay(isExpanded ? null : day.id)}
                        className="p-4 flex items-center justify-between cursor-pointer active:bg-white/5 relative z-10"
                    >
                        <div className="flex items-center gap-4">
                            {/* Day Icon / Progress */}
                            <div className="relative w-12 h-12 flex items-center justify-center">
                                {isPast ? (
                                    <div className="bg-neutral-800 p-2 rounded-full border border-neutral-700">
                                        <Lock size={18} className="text-neutral-500" />
                                    </div>
                                ) : isRestDay ? (
                                    <Coffee className="text-emerald-500" size={24} />
                                ) : (
                                    <CircularProgress 
                                        size={48} 
                                        strokeWidth={4} 
                                        percentage={progress} 
                                        color={progress === 100 ? 'text-game-red' : 'text-neutral-600'}
                                    >
                                        <span className={`text-xs font-bold ${progress === 100 ? 'text-game-red' : 'text-neutral-500'}`}>
                                            {Math.round(progress)}%
                                        </span>
                                    </CircularProgress>
                                )}
                            </div>

                            <div>
                                <h3 className={`font-black text-lg flex items-center gap-2 ${isPast ? 'text-neutral-500' : isRestDay ? 'text-emerald-500' : 'text-white'}`}>
                                    {day.label}
                                    {isToday && <span className="text-[9px] bg-game-red text-white px-2 py-0.5 rounded-full uppercase tracking-wider">Today</span>}
                                </h3>
                                <p className="text-xs text-neutral-500">
                                    {isPast 
                                        ? t('dayLocked') || "مغلق" 
                                        : isRestDay 
                                            ? t('restDay') 
                                            : `${completedCount} / ${totalCount} ${t('completedTasks')}`}
                                </p>
                            </div>
                        </div>

                        {/* Expand Icon */}
                        <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''} text-neutral-500`}>
                            ▼
                        </div>
                    </div>

                    {/* Expanded Content */}
                    <div className={`transition-all duration-300 overflow-hidden ${isExpanded ? 'max-h-[1000px] opacity-100' : 'max-h-0 opacity-0'}`}>
                        <div className="p-4 pt-0 border-t border-neutral-800/50">

                            {isRestDay && !isPast ? (
                                <div className="py-6 text-center text-emerald-500/80">
                                    <p className="text-sm font-bold">{t('enjoyDay')}</p>
                                </div>
                            ) : (
                                <>
                                    {dayTasks.length === 0 ? (
                                        <div className="py-8 text-center">
                                            <p className="text-neutral-600 text-sm mb-3">
                                                {isPast ? (t('noTasksHistory') || "لا توجد مهام مسجلة") : t('noScheduledTasks')}
                                            </p>
                                            {!isPast && (
                                                <button 
                                                    onClick={(e) => { e.stopPropagation(); handleAddClick(index, day.id); }}
                                                    className="text-game-red text-xs font-bold border border-game-red/30 px-3 py-1.5 rounded-lg hover:bg-game-red/10"
                                                >
                                                    + {t('addTaskFor')} {day.label}
                                                </button>
                                            )}
                                        </div>
                                    ) : (
                                        <div className="space-y-3 mt-4">
                                            {dayTasks.map(task => (
                                                <TaskItem 
                                                    key={task.id}
                                                    task={task}
                                                    onComplete={completeTask}
                                                    onDelete={deleteTask}
                                                    onEdit={isPast ? undefined : onEditTask} // Disable editing for past days
                                                    canAfford={stats.energy >= task.energyCost}
                                                />
                                            ))}
                                            {!isPast && (
                                                <button 
                                                    onClick={() => handleAddClick(index, day.id)}
                                                    className="w-full py-3 border border-dashed border-neutral-800 rounded-xl text-neutral-600 text-sm font-bold hover:text-white hover:border-neutral-600 transition-colors flex items-center justify-center gap-2"
                                                >
                                                    <Plus size={16} /> {t('addMore')}
                                                </button>
                                            )}
                                        </div>
                                    )}
                                </>
                            )}
                        </div>
                    </div>
                </div>
            );
        })}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Dumbbell, Zap, Trophy, Target, Calendar, Scroll, CheckCircle2, LayoutGrid, Clock, BarChart3, Lock } from 'lucide-react';
import { PillarType, Task, DayOfWeek, TaskDifficulty } from '../types';
import { PILLARS, HOME_EXERCISES, DAYS_OF_WEEK, PILLAR_BASE_RATES, DIFFICULTY_CONFIG, ENERGY_PER_QURAN_PAGE } from '../constants';
import { useGame } from '../context/GameContext';
import { useSettings } from '../context/SettingsContext';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (taskData: Partial<Task>) => void;
  initialData?: Task | null;
  defaultPillar?: PillarType;
  defaultDay?: DayOfWeek;
}

export const TaskFormModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, initialData, defaultPillar, defaultDay }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [pillar, setPillar] = useState<PillarType>('Learning');
  const [day, setDay] = useState<DayOfWeek>('Saturday');
  const [difficulty, setDifficulty] = useState<TaskDifficulty>('D'); // Default D-Rank
  const [dueDate, setDueDate] = useState('');
  const [pages, setPages] = useState<number>(1); // For Quran

  const { t } = useSettings();

  // Calculate Today's Index (0 = Saturday, ... 6 = Friday)
  const todayIndex = (new Date().getDay() + 1) % 7;

  // Dynamic Calculation
  const baseRates = PILLAR_BASE_RATES[pillar];
  const multiplier = DIFFICULTY_CONFIG[difficulty].multiplier;

  // Calculate final costs
  const calculatedEnergy = pillar === 'Quran' 
    ? -(pages * ENERGY_PER_QURAN_PAGE) 
    : Math.ceil(baseRates.energy * multiplier);

  const calculatedXp = Math.ceil(baseRates.xp * multiplier);

  // Get current real day for visual comparison
  const days: DayOfWeek[] = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  const todayName = days[new Date().getDay()];

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setTitle(initialData.title);
        setDescription(initialData.description);
        setPillar(initialData.pillar);
        setDay(initialData.day || 'Saturday');
        setDifficulty(initialData.difficulty || 'D');
        setDueDate(initialData.dueDate || '');
        setPages(initialData.pages || 1);
      } else {
        setTitle('');
        setDescription('');
        setPillar(defaultPillar || 'Learning');
        // If defaultDay is provided and it's in the past relative to today, default to Today instead
        const defaultDayIndex = DAYS_OF_WEEK.findIndex(d => d.id === defaultDay);
        const effectiveDay = (defaultDay && defaultDayIndex >= todayIndex) ? defaultDay : todayName;

        setDay(effectiveDay);
        setDifficulty('D');
        setDueDate('');
        setPages(1);
      }
    }
  }, [isOpen, initialData, defaultPillar, defaultDay, todayName, todayIndex]);

  const handleExerciseSelect = (ex: typeof HOME_EXERCISES[0]) => {
    setTitle(ex.name);
    setPillar('Exercise');
    setDescription(`Goal: ${ex.reps || ex.duration}`);
    setDifficulty(ex.difficulty);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // For Quran, title can be auto-generated if empty
    let finalTitle = title;
    if (pillar === 'Quran' && !finalTitle.trim()) {
        finalTitle = `${t('quran')} - ${pages} ${t('pagesToRead')}`;
    }

    if (!finalTitle.trim()) return;

    if (day === 'Friday' && pillar !== 'Quran') {
        alert(t('fridayRestWarning'));
        return;
    }

    onSubmit({
      title: finalTitle,
      description,
      pillar,
      day,
      difficulty,
      dueDate,
      pages: pillar === 'Quran' ? Number(pages) : undefined
    });
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in">
      <div className="bg-neutral-900 border border-neutral-700 w-full max-w-md rounded-3xl p-0 relative shadow-2xl max-h-[90vh] overflow-hidden flex flex-col">

        {/* Header */}
        <div className="p-4 border-b border-neutral-800 bg-neutral-900 flex justify-between items-center sticky top-0 z-10">
             <h3 className="text-lg font-black text-white uppercase tracking-wider flex items-center gap-2">
                {initialData ? <><CheckCircle2 size={20} className="text-blue-500"/> {t('editTask')}</> : <><LayoutGrid size={20} className="text-game-red"/> {t('newTask')}</>}
            </h3>
            <button onClick={onClose} className="p-2 bg-neutral-800 rounded-full text-neutral-400 hover:text-white hover:bg-neutral-700 transition-colors">
                <X size={20} />
            </button>
        </div>

        <div className="overflow-y-auto p-6 space-y-6 no-scrollbar">
            <form onSubmit={handleSubmit} className="space-y-6">

                {/* Pillar Selector (Grid) */}
                <div>
                    <label className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest mb-3 block">{t('selectPillar')}</label>
                    <div className="grid grid-cols-3 gap-2">
                        {PILLARS.map(p => (
                            <button
                                key={p.id}
                                type="button"
                                onClick={() => setPillar(p.id)}
                                className={`
                                    flex flex-col items-center justify-center gap-1 p-2 rounded-xl border-2 transition-all
                                    ${pillar === p.id 
                                        ? `bg-${p.color.split('-')[1]}-900/20 border-${p.color.split('-')[1]}-500 text-white shadow-lg shadow-${p.color.split('-')[1]}-500/10` 
                                        : 'bg-neutral-950 border-neutral-800 text-neutral-500 hover:border-neutral-700 hover:bg-neutral-900'}
                                `}
                            >
                                <p.icon size={20} className={pillar === p.id ? p.color : 'text-neutral-600'} />
                                <span className="text-[10px] font-bold">{t(p.id.toLowerCase() as any)}</span>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Day Selector */}
                <div>
                    <div className="flex items-center justify-between mb-3">
                        <label className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest flex items-center gap-2">
                            <Calendar size={12} /> {t('timing')}
                        </label>
                        <div className="flex items-center gap-1 text-[10px] text-game-red font-bold animate-pulse">
                            <Clock size={10} />
                            <span>{t('today')}: {todayName}</span>
                        </div>
                    </div>
                    <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                        {DAYS_OF_WEEK.map((d, index) => {
                            const isToday = d.id === todayName;
                            const isPast = index < todayIndex;
                            // Only disable if it's past AND we are not editing a task that was already on this day (though usually we want to force reschedule)
                            // Strict Rule: Cannot schedule on past days.
                            const isDisabled = isPast || (d.id === 'Friday' && pillar !== 'Quran');

                            return (
                                <button
                                    key={d.id}
                                    type="button"
                                    onClick={() => !isDisabled && setDay(d.id)}
                                    className={`
                                        relative flex items-center justify-center px-3 py-2 rounded-lg text-[10px] font-bold border transition-all whitespace-nowrap
                                        ${isDisabled ? 'opacity-40 border-dashed border-neutral-800 cursor-not-allowed bg-black/50 text-neutral-600' : ''}
                                        ${day === d.id 
                                            ? 'bg-white text-black border-white shadow-lg scale-105' 
                                            : !isDisabled && isToday ? 'bg-neutral-800 border-game-red text-white' : 'bg-black text-neutral-500 border-neutral-800 hover:border-neutral-600'}
                                    `}
                                    disabled={isDisabled}
                                >
                                    {isPast && <Lock size={8} className="absolute -top-1 -left-1 text-neutral-500" />}
                                    {d.label}
                                    {isToday && day !== d.id && !isDisabled && (
                                        <span className="absolute -top-1 -right-1 w-2 h-2 bg-game-red rounded-full" />
                                    )}
                                </button>
                            );
                        })}
                    </div>
                </div>

                {/* Inputs Area */}
                <div className="bg-neutral-950/50 p-4 rounded-2xl border border-neutral-800/50 space-y-4">
                    {pillar === 'Quran' ? (
                        <div className="bg-emerald-900/10 border border-emerald-900/50 p-4 rounded-xl text-center">
                            <label className="block text-xs text-emerald-400 mb-3 font-bold flex items-center justify-center gap-2">
                                <Scroll size={16} /> {t('pagesToRead')}
                            </label>
                            <div className="flex items-center justify-center gap-4">
                                <button type="button" onClick={() => setPages(p => Math.max(1, p - 1))} className="w-10 h-10 rounded-full bg-neutral-800 hover:bg-neutral-700 text-white font-bold text-xl transition-colors">-</button>
                                <span className="text-3xl font-black text-white w-16 text-center">{pages}</span>
                                <button type="button" onClick={() => setPages(p => p + 1)} className="w-10 h-10 rounded-full bg-neutral-800 hover:bg-neutral-700 text-white font-bold text-xl transition-colors">+</button>
                            </div>
                            <p className="text-[10px] text-neutral-500 mt-3">{t('pageEnergy')}</p>
                        </div>
                    ) : (
                        <>
                            <div>
                                <label className="block text-[10px] text-neutral-500 font-bold mb-1 uppercase">{t('taskTitle')}</label>
                                <input 
                                    type="text" 
                                    value={title}
                                    onChange={(e) => setTitle(e.target.value)}
                                    className="w-full bg-black border border-neutral-800 rounded-xl p-4 text-white placeholder:text-neutral-700 focus:border-game-red focus:ring-1 focus:ring-game-red outline-none transition-all font-bold"
                                    placeholder={pillar === 'Exercise' ? "..." : t('taskPlaceholder')}
                                />
                            </div>

                            {/* Difficulty Selector */}
                            <div>
                                <label className="text-[10px] text-neutral-500 font-bold mb-2 uppercase flex items-center gap-2">
                                    <BarChart3 size={12} /> {t('difficultyLevel')}
                                </label>
                                <div className="grid grid-cols-6 gap-1">
                                    {(Object.keys(DIFFICULTY_CONFIG) as TaskDifficulty[]).map(key => (
                                        <button
                                            key={key}
                                            type="button"
                                            onClick={() => setDifficulty(key)}
                                            className={`
                                                flex flex-col items-center justify-center py-2 rounded-lg border transition-all
                                                ${difficulty === key 
                                                    ? `bg-neutral-800 border-white text-white` 
                                                    : 'bg-black border-neutral-800 text-neutral-600 hover:border-neutral-600'}
                                            `}
                                        >
                                            <span className={`text-xs font-black ${DIFFICULTY_CONFIG[key].color}`}>{key}</span>
                                        </button>
                                    ))}
                                </div>
                                <div className="text-center mt-2 text-[10px] text-neutral-500 font-mono uppercase">
                                    {DIFFICULTY_CONFIG[difficulty].label} • x{DIFFICULTY_CONFIG[difficulty].multiplier} Rewards
                                </div>
                            </div>

                            {/* Exercise Quick Presets */}
                            {pillar === 'Exercise' && (
                                <div>
                                    <label className="block text-[10px] text-green-500 font-bold mb-2 uppercase tracking-wide">{t('suggestedExercises')}</label>
                                    <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                                        {HOME_EXERCISES.slice(0, 5).map(ex => (
                                            <button
                                                key={ex.id}
                                                type="button"
                                                onClick={() => handleExerciseSelect(ex)}
                                                className="bg-neutral-900 border border-neutral-800 hover:border-green-500/50 hover:bg-green-900/10 rounded-lg px-3 py-2 whitespace-nowrap transition-colors"
                                            >
                                                <span className="text-xs text-white font-bold">{ex.name.split('/')[1] || ex.name}</span>
                                                <span className="block text-[9px] text-neutral-500">{ex.reps || ex.duration} • Rank {ex.difficulty}</span>
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}

                            <div>
                                <label className="block text-[10px] text-neutral-500 font-bold mb-1 uppercase">{t('additionalNotes')}</label>
                                <textarea 
                                    value={description}
                                    onChange={(e) => setDescription(e.target.value)}
                                    className="w-full bg-black border border-neutral-800 rounded-xl p-3 text-white placeholder:text-neutral-700 focus:border-game-red outline-none h-20 text-sm resize-none"
                                    placeholder={t('detailsPlaceholder')}
                                />
                            </div>
                        </>
                    )}
                </div>

                {/* Stats Preview */}
                <div className="flex gap-3">
                    <div className="flex-1 bg-black p-3 rounded-xl border border-neutral-800 flex items-center gap-3">
                        <div className="bg-yellow-900/20 p-2 rounded-lg text-yellow-500"><Zap size={18} /></div>
                        <div>
                            <p className="text-[10px] text-neutral-500 font-bold uppercase">{t('energy')}</p>
                            <p className={`text-lg font-black ${calculatedEnergy < 0 ? 'text-green-500' : 'text-white'}`}>
                                {calculatedEnergy > 0 ? `-${calculatedEnergy}` : `+${Math.abs(calculatedEnergy)}`}
                            </p>
                        </div>
                    </div>
                    {pillar !== 'Quran' && (
                        <div className="flex-1 bg-black p-3 rounded-xl border border-neutral-800 flex items-center gap-3">
                            <div className="bg-red-900/20 p-2 rounded-lg text-game-red"><Trophy size={18} /></div>
                            <div>
                                <p className="text-[10px] text-neutral-500 font-bold uppercase">{t('energyReward')}</p>
                                <p className="text-lg font-black text-white">{calculatedXp} XP</p>
                            </div>
                        </div>
                    )}
                </div>

                {/* Submit Button */}
                <button 
                    type="submit" 
                    disabled={day === 'Friday' && pillar !== 'Quran'}
                    className={`
                        w-full font-black py-4 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2
                        ${day === 'Friday' && pillar !== 'Quran' 
                            ? 'bg-neutral-800 text-neutral-500 cursor-not-allowed' 
                            : 'bg-white text-black hover:bg-neutral-200 hover:scale-[1.02] active:scale-[0.98]'}
                    `}
                >
                    {initialData ? t('saveChanges') : t('addToSchedule')}
                </button>

            </form>
        </div>
      </div>
    </div>
  );
};

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo, useRef } from 'react';
import { GameState, Task, UserStats, PlayerProfile, WeeklyHistory, MonthlyHistory, WeeklyReport, MonthlyReport, WeeklyReward, MonthlyReward, DailyQuestProgress, BASE_XP_PER_LEVEL, DayOfWeek } from '../types';
import { ENERGY_RECOVERY_RATE, PILLAR_BASE_RATES, DIFFICULTY_CONFIG, XP_SCALING_FACTOR, SHADOW_TASKS, DAILY_QUEST_TARGETS, ENERGY_PER_QURAN_PAGE, DAYS_OF_WEEK, XP_PENALTY_RATIO, MAX_DAILY_XP_LOSS_PERCENT } from '../constants';
import { StorageService, defaultStats } from '../services/storage';
import { HistoryEngine } from '../services/historyEngine';
import { useToast } from './ToastContext';
import { useSettings } from '../context/SettingsContext';
import { AudioService } from '../services/audioService';

interface GameContextType extends GameState {
  createProfile: (profileData: Omit<PlayerProfile, 'createdAt'>) => void;
  updateProfile: (updates: Partial<PlayerProfile>) => void;
  addTask: (task: Partial<Task>) => void;
  editTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  reorderTasks: (reorderedTasks: Task[]) => void;
  moveTask: (taskId: string, direction: 'up' | 'down') => void;
  resetProgress: () => void;
  setWeeklyChallenge: (title: string) => void;
  completeWeeklyChallenge: () => void;
  updateDailyQuest: (type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => void;
  showLevelUpModal: boolean;
  closeLevelUpModal: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

// Helper for local date string YYYY-MM-DD
const getLocalDateString = () => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
};

// Helper for safe UUID
const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
    }
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

// 2️⃣ Time Modifier Function
const getTimeModifier = () => {
    const hour = new Date().getHours();
    if (hour >= 6 && hour < 10) return { xp: 1.15, energy: 0.85 }; // Morning Bonus
    if (hour >= 22 || hour < 4) return { xp: 0.85, energy: 1.15 }; // Night Penalty
    return { xp: 1, energy: 1 };
};

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [playerProfile, setPlayerProfile] = useState<PlayerProfile | null>(null);

  // History State
  const [weeklyHistory, setWeeklyHistory] = useState<WeeklyHistory[]>([]);
  const [monthlyHistory, setMonthlyHistory] = useState<MonthlyHistory[]>([]);
  const [weeklyReports, setWeeklyReports] = useState<WeeklyReport[]>([]);
  const [monthlyReports, setMonthlyReports] = useState<MonthlyReport[]>([]);
  const [weeklyRewards, setWeeklyRewards] = useState<WeeklyReward[]>([]);
  const [monthlyRewards, setMonthlyRewards] = useState<MonthlyReward[]>([]);

  const [isLoaded, setIsLoaded] = useState(false);
  const [showLevelUpModal, setShowLevelUpModal] = useState(false);
  const { addToast } = useToast();
  const { soundEnabled, hapticsEnabled } = useSettings();

  // Ref to track if we are currently saving to avoid loops
  const isSaving = useRef(false);

  // Helper for Sound/Haptics
  const triggerFeedback = useCallback((type: 'success' | 'hard-success' | 'error' | 'levelup' | 'click' | 'boost' | 'mystery' | 'failure') => {
      if (hapticsEnabled && navigator.vibrate) {
          if (type === 'success') navigator.vibrate(50);
          if (type === 'hard-success') navigator.vibrate([100, 50, 100]);
          if (type === 'error') navigator.vibrate([50, 50, 50]);
          if (type === 'levelup') navigator.vibrate([100, 50, 100, 50, 200]);
          if (type === 'click') navigator.vibrate(10);
          if (type === 'failure') navigator.vibrate([500, 200]);
      }

      if (soundEnabled) {
          if (type === 'success') AudioService.playTaskComplete();
          if (type === 'hard-success') AudioService.playHardTaskComplete();
          if (type === 'error') AudioService.playEnergyWarning();
          if (type === 'click') AudioService.playTaskComplete(); // Simple blip
          if (type === 'boost') AudioService.playXpGain();
          if (type === 'mystery') AudioService.playMysteryReveal();
          if (type === 'failure') AudioService.playFailure();
      }
  }, [soundEnabled, hapticsEnabled]);

  // --- 1. INITIAL LOAD & TIME TRAVEL ENGINE ---
  useEffect(() => {
    const loadedProfile = StorageService.loadProfile();
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();
    const loadedWeekly = StorageService.loadWeeklyHistory();
    const loadedMonthly = StorageService.loadMonthlyHistory();
    const loadedWeeklyReports = StorageService.loadWeeklyReports();
    const loadedMonthlyReports = StorageService.loadMonthlyReports();
    const loadedWeeklyRewards = StorageService.loadWeeklyRewards();
    const loadedMonthlyRewards = StorageService.loadMonthlyRewards();

    if (loadedProfile) setPlayerProfile(loadedProfile);
    if (loadedTasks) setTasks(loadedTasks);

    // Set history states initially
    setWeeklyHistory(loadedWeekly);
    setMonthlyHistory(loadedMonthly);
    setWeeklyReports(loadedWeeklyReports);
    setMonthlyReports(loadedMonthlyReports);
    setWeeklyRewards(loadedWeeklyRewards);
    setMonthlyRewards(loadedMonthlyRewards);

    if (loadedStats) {
        let currentStats = { ...loadedStats };
        const today = getLocalDateString();
        const nowMs = Date.now();
        const isNewDay = currentStats.lastLoginDate !== today;

        // --- NEW: MISSED TASK LOGIC (Penalty System) ---
        // This runs BEFORE we potentially reset the day/week, locking in yesterday's failures.
        let updatedTasks = loadedTasks ? [...loadedTasks] : [];
        let missedCount = 0;
        let totalXpPenalty = 0;
        let energyPenalty = 0;

        // Map DayOfWeek to index 0-6 (Saturday to Friday)
        const dayIndices = { 'Saturday': 0, 'Sunday': 1, 'Monday': 2, 'Tuesday': 3, 'Wednesday': 4, 'Thursday': 5, 'Friday': 6 };
        const currentDayName = DAYS_OF_WEEK[new Date().getDay()].id as DayOfWeek; // Correct day from system
        const currentDayIdx = dayIndices[currentDayName];

        updatedTasks = updatedTasks.map(t => {
            if (!t.completed && !t.isMissed && t.day) {
                const taskDayIdx = dayIndices[t.day];

                // If the task was scheduled for a previous day in the current cycle
                if (taskDayIdx < currentDayIdx) {
                    // Check safe window: Created < 2 hours before midnight of that day?
                    // Simplified: Check if created more than 24h ago
                    const createdAgo = nowMs - t.createdAt;
                    if (createdAgo > 24 * 60 * 60 * 1000) {
                        missedCount++;
                        const penalty = Math.ceil(t.xpReward * XP_PENALTY_RATIO);
                        totalXpPenalty += penalty;

                        // Energy penalty for high difficulty
                        if (['A', 'S'].includes(t.difficulty)) {
                            energyPenalty += 5; // Flat 5 energy penalty
                        }

                        return { ...t, isMissed: true };
                    }
                }
            }
            return t;
        });

        // Apply XP Penalties
        if (missedCount > 0) {
            // Cap XP loss at 25% of current XP
            const maxLoss = Math.floor(currentStats.currentXp * MAX_DAILY_XP_LOSS_PERCENT);
            const actualXpLoss = Math.min(totalXpPenalty, maxLoss);

            currentStats.currentXp = Math.max(0, currentStats.currentXp - actualXpLoss);

            // Track stats
            currentStats.weeklyMissedTasks = (currentStats.weeklyMissedTasks || 0) + missedCount;
            currentStats.weeklyXpLost = (currentStats.weeklyXpLost || 0) + actualXpLoss;

            // Delayed Toast for UI feedback after render
            setTimeout(() => {
                addToast(`⚠️ ${missedCount} مهام فائتة! -${actualXpLoss} XP`, 'error');
                triggerFeedback('failure');
            }, 2000);

            // Update tasks state immediately
            setTasks(updatedTasks);
        }

        // --- ENERGY LOGIC ---
        // Variable to hold the target energy for today (to allow animation)
        let targetEnergy = currentStats.energy;

        if (isNewDay) {
            // Rule 1: Reset to Max on New Day
            // Rule 3: Visual/UX Feedback triggers later

            // Apply Missed Task Energy Penalty to the MAX restoration (Rule 3 previous prompt)
            let dailyResetValue = currentStats.maxEnergy;

            if (energyPenalty > 0) {
                 dailyResetValue = Math.max(0, dailyResetValue - energyPenalty);
                 // We accumulate the notification
                 setTimeout(() => {
                     addToast(`⚠️ خصم طاقة: -${energyPenalty} (مهام فائتة)`, 'error');
                 }, 2500);
            }

            targetEnergy = dailyResetValue;
            currentStats.lastEnergyUpdate = nowMs; // Reset timer base

            // Keep currentStats.energy at OLD value briefly to allow animation in UI
            // We do NOT update currentStats.energy here yet

        } else {
            // Same Day: Passive Regeneration (Offline Calculation)
            if (currentStats.energy < currentStats.maxEnergy) {
                const lastUpdate = currentStats.lastEnergyUpdate || nowMs;
                const diffInHours = (nowMs - lastUpdate) / (1000 * 60 * 60);
                const energyRecovered = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);
                if (energyRecovered > 0) {
                    currentStats.energy = Math.min(currentStats.maxEnergy, currentStats.energy + energyRecovered);
                    currentStats.lastEnergyUpdate = nowMs; // Reset timer base
                }
            } else {
                 currentStats.lastEnergyUpdate = nowMs;
            }

            // Apply immediate penalty if same day
            if (energyPenalty > 0) {
                currentStats.energy = Math.max(0, currentStats.energy - energyPenalty);
            }
            targetEnergy = currentStats.energy; // No animation needed for same day passive
        }

        // C. Daily Quest Reset & Streak Decay
        if (currentStats.dailyQuest?.lastResetDate !== today) {
             // Streak Logic
             const lastTaskDate = new Date(currentStats.lastTaskCompletionDate || '1970-01-01');
             const yesterday = new Date();
             yesterday.setDate(yesterday.getDate() - 1);
             const lastTaskStr = lastTaskDate.toISOString().split('T')[0];
             const yesterdayStr = yesterday.toISOString().split('T')[0];

             if (lastTaskStr !== today && lastTaskStr !== yesterdayStr) {
                 if (currentStats.streak > 0) {
                    addToast("انقطعت السلسلة! 😢", "error");
                    currentStats.streak = 0;
                 }
             }

             // Reset Daily Quest
             currentStats.dailyQuest = {
                pushups: 0, situps: 0, squats: 0, run: 0,
                isCompleted: false,
                lastResetDate: today
            };
        }
        currentStats.lastLoginDate = today;

        // D. Process Time Skip (Weekly/Monthly Reports)
        const processed = HistoryEngine.processTimeSkip(
            currentStats,
            updatedTasks,
            loadedWeekly,
            loadedMonthly,
            loadedWeeklyReports,
            loadedMonthlyReports,
            loadedWeeklyRewards,
            loadedMonthlyRewards
        );

        if (processed.reportsGenerated > 0) {
            addToast(`تم إصدار ${processed.reportsGenerated} تقارير جديدة! 📊`, 'info');
            // Trigger mystery sound for new report
            if(soundEnabled) AudioService.playMysteryReveal();

            setWeeklyHistory(processed.weeklyHistory);
            setMonthlyHistory(processed.monthlyHistory);
            setWeeklyReports(processed.weeklyReports);
            setMonthlyReports(processed.monthlyReports);
            setWeeklyRewards(processed.weeklyRewards);
            setMonthlyRewards(processed.monthlyRewards);

            // Trigger batch save
            StorageService.saveWeeklyHistory(processed.weeklyHistory);
            StorageService.saveMonthlyHistory(processed.monthlyHistory);
            StorageService.saveWeeklyReports(processed.weeklyReports);
            StorageService.saveMonthlyReports(processed.monthlyReports);
            StorageService.saveWeeklyRewards(processed.weeklyRewards);
            StorageService.saveMonthlyRewards(processed.monthlyRewards);
        }

        // Set State
        setStats(processed.stats);

        // Trigger Energy Restore Animation and Toast if New Day
        if (isNewDay) {
            setTimeout(() => {
                setStats(prev => ({ ...prev, energy: targetEnergy }));
                if (soundEnabled) AudioService.playEnergyRestore();
                addToast("🌅 يوم جديد! تم استعادة طاقتك بالكامل.", 'success');
            }, 800);
        }
    }

    setIsLoaded(true);
  }, []);


  // --- 2. GAME LOOP (HEARTBEAT) ---
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    const tick = () => {
        setStats(prev => {
            const now = Date.now();

            // Energy Logic
            let newEnergy = prev.energy;
            let lastUpdate = prev.lastEnergyUpdate;

            if (newEnergy < prev.maxEnergy) {
                const diffInHours = (now - lastUpdate) / (1000 * 60 * 60);
                const thresholdHours = 1 / ENERGY_RECOVERY_RATE; 

                if (diffInHours >= thresholdHours) {
                    const energyGained = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);
                    newEnergy = Math.min(prev.maxEnergy, prev.energy + energyGained);
                    lastUpdate = lastUpdate + (energyGained / ENERGY_RECOVERY_RATE) * (1000 * 60 * 60); 

                    // Sound Effect for passive restore
                    if (soundEnabled) AudioService.playEnergyRestore();
                }
            } else {
                lastUpdate = now;
            }

            if (newEnergy === prev.energy && lastUpdate === prev.lastEnergyUpdate) {
                return prev;
            }

            return {
                ...prev,
                energy: newEnergy,
                lastEnergyUpdate: lastUpdate
            };
        });
    };

    const interval = setInterval(tick, 30000); // Check every 30 seconds
    return () => clearInterval(interval);
  }, [isLoaded, playerProfile, soundEnabled]);


  // --- 3. SHADOW TASK INJECTOR ---
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    if (stats.energy < 20) {
        setTasks(currentTasks => {
            const hasShadowTask = currentTasks.some(t => t.isShadow && !t.completed);
            if (!hasShadowTask) {
                const randomShadow = SHADOW_TASKS[Math.floor(Math.random() * SHADOW_TASKS.length)];
                const shadowTask: Task = {
                    id: generateId(),
                    title: `👻 ${randomShadow.title}`,
                    description: randomShadow.description,
                    pillar: 'Entertainment',
                    completed: false,
                    energyCost: -randomShadow.energyRestore,
                    xpReward: 0,
                    difficulty: 'E',
                    createdAt: Date.now(),
                    order: -1,
                    isShadow: true
                };
                addToast("ظهرت مهمة ظل! استعد طاقتك الآن.", 'shadow');
                if (soundEnabled) AudioService.playMysteryReveal();
                return [shadowTask, ...currentTasks];
            }
            return currentTasks;
        });
    }
  }, [stats.energy, isLoaded, playerProfile, soundEnabled]); 


  // --- 4. AUTO-SAVE SYSTEM ---
  useEffect(() => {
    if (isLoaded && playerProfile && !isSaving.current) {
        isSaving.current = true;
        StorageService.saveStats(stats);
        StorageService.saveTasks(tasks);
        setTimeout(() => { isSaving.current = false; }, 100);
    }
  }, [stats, tasks, isLoaded, playerProfile]);


  // --- ACTIONS ---

  const createProfile = useCallback((data: Omit<PlayerProfile, 'createdAt'>) => {
    const newProfile: PlayerProfile = {
        ...data,
        createdAt: new Date().toISOString()
    };
    StorageService.initializeNewAccount(newProfile);
    setPlayerProfile(newProfile);
    setStats({
        ...defaultStats,
        lastLoginDate: getLocalDateString()
    });
    setTasks([]);
    triggerFeedback('success');
    addToast('أهلاً بك في رحلة التطوير! 🚀', 'success');
  }, [addToast, triggerFeedback]);

  const updateProfile = useCallback((updates: Partial<PlayerProfile>) => {
    setPlayerProfile(prev => {
        if (!prev) return null;
        const updated = { ...prev, ...updates };
        StorageService.saveProfile(updated);
        return updated;
    });
    addToast('تم تحديث البيانات', 'success');
  }, [addToast]);

  const addTask = useCallback((taskData: Partial<Task>) => {
    setTasks(prev => {
        const maxOrder = prev.length > 0 ? Math.max(...prev.map(t => t.order)) : 0;
        const pillar = taskData.pillar || 'Work';
        const difficulty = taskData.difficulty || 'D';

        const baseRates = PILLAR_BASE_RATES[pillar];
        const multiplier = DIFFICULTY_CONFIG[difficulty].multiplier;

        const newTask: Task = {
          id: generateId(),
          title: taskData.title || (pillar === 'Quran' ? 'ورد القرآن' : 'مهمة جديدة'),
          description: taskData.description || '',
          pillar: pillar,
          completed: false,
          difficulty: difficulty,
          energyCost: Math.ceil(baseRates.energy * multiplier),
          xpReward: Math.ceil(baseRates.xp * multiplier),
          dueDate: taskData.dueDate,
          day: taskData.day,
          createdAt: Date.now(),
          order: maxOrder + 1,
          pages: taskData.pages
        };
        return [...prev, newTask];
    });
    triggerFeedback('click');
    addToast('تمت إضافة المهمة بنجاح', 'success');
  }, [addToast, triggerFeedback]);

  const editTask = useCallback((id: string, updates: Partial<Task>) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;
      const pillar = updates.pillar || t.pillar;
      const difficulty = updates.difficulty || t.difficulty;
      const baseRates = PILLAR_BASE_RATES[pillar];
      const multiplier = DIFFICULTY_CONFIG[difficulty].multiplier;

      return { 
          ...t, 
          ...updates,
          energyCost: Math.ceil(baseRates.energy * multiplier),
          xpReward: Math.ceil(baseRates.xp * multiplier)
      };
    }));
    addToast('تم حفظ التعديلات', 'success');
  }, [addToast]);

  const deleteTask = useCallback((id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    addToast('تم حذف المهمة', 'info');
  }, [addToast]);

  const reorderTasks = useCallback((reorderedTasks: Task[]) => {
      setTasks(reorderedTasks);
  }, []);

  const moveTask = useCallback((taskId: string, direction: 'up' | 'down') => {
      setTasks(prevTasks => {
        const sortedTasks = [...prevTasks].sort((a, b) => a.order - b.order);
        const sortedIndex = sortedTasks.findIndex(t => t.id === taskId);
        if (sortedIndex === -1) return prevTasks;
        if (direction === 'up' && sortedIndex > 0) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex - 1].order;
            sortedTasks[sortedIndex - 1].order = tempOrder;
        } else if (direction === 'down' && sortedIndex < sortedTasks.length - 1) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex + 1].order;
            sortedTasks[sortedIndex + 1].order = tempOrder;
        }
        return [...sortedTasks];
      });
      triggerFeedback('click');
  }, [triggerFeedback]);

  const setWeeklyChallenge = useCallback((title: string) => {
    setStats(prev => ({
        ...prev,
        weeklyChallenge: {
            id: generateId(),
            title: title,
            weekStart: getLocalDateString(),
            completed: false
        }
    }));
    triggerFeedback('click');
    addToast('تم تحديد التحدي الأسبوعي! 🎯', 'info');
  }, [addToast, triggerFeedback]);

  const completeWeeklyChallenge = useCallback(() => {
    setStats(prev => {
        if (!prev.weeklyChallenge || prev.weeklyChallenge.completed) return prev;

        const bonusXP = Math.floor(prev.maxXp * 0.25);

        let currentXp = prev.currentXp + bonusXP;
        let weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + bonusXP;

        let level = prev.level;
        let maxXp = prev.maxXp;
        let didLevelUp = false;

        while (currentXp >= maxXp) {
            currentXp -= maxXp;
            level += 1;
            maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
            didLevelUp = true;
        }

        let newAttributes = { ...prev.hunterAttributes };
        if (didLevelUp) {
             newAttributes.strength += 1;
             newAttributes.intelligence += 1;
             newAttributes.vitality += 1;
             newAttributes.sense += 1;
             newAttributes.agility += 1;
        }

        if (didLevelUp) {
            setShowLevelUpModal(true);
        } else {
            addToast(`مكافأة التحدي: +${bonusXP} XP 🔥`, 'success');
            triggerFeedback('hard-success');
        }

        return {
            ...prev,
            weeklyChallenge: { ...prev.weeklyChallenge!, completed: true },
            currentXp, level, maxXp, weeklyXpAccumulated,
            hunterAttributes: newAttributes
        };
    });
  }, [addToast, triggerFeedback]);

  const closeLevelUpModal = useCallback(() => {
    setShowLevelUpModal(false);
  }, []);

  const updateDailyQuest = useCallback((type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => {
      setStats(prev => {
          if (!prev.dailyQuest || prev.dailyQuest.isCompleted) return prev;

          const newStats = { ...prev };
          newStats.dailyQuest = { ...prev.dailyQuest, [type]: Math.min(DAILY_QUEST_TARGETS[type], amount) };

          const { pushups, situps, squats, run } = newStats.dailyQuest;
          const target = DAILY_QUEST_TARGETS;

          if (pushups >= target.pushups && situps >= target.situps && squats >= target.squats && run >= target.run) {
              if (!prev.dailyQuest.isCompleted) {
                  newStats.dailyQuest.isCompleted = true;
                  newStats.energy = newStats.maxEnergy;
                  const dailyXpReward = Math.floor(prev.maxXp * 0.15);
                  newStats.currentXp += dailyXpReward;

                  newStats.hunterAttributes.strength += 2;
                  newStats.hunterAttributes.vitality += 1;

                  addToast(`مهمة يومية مكتملة! طاقة كاملة + ${dailyXpReward}XP`, 'success');
                  triggerFeedback('hard-success');
              }
          }
          triggerFeedback('click');
          return newStats;
      });
  }, [addToast, triggerFeedback]);

  const completeTask = useCallback((id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed || task.isMissed) return; // Ignore missed tasks

    if (task.isShadow) {
        setStats(prev => ({
            ...prev,
            energy: Math.min(prev.maxEnergy, prev.energy + Math.abs(task.energyCost))
        }));
        setTasks(prev => prev.filter(t => t.id !== id));
        addToast("تم استعادة بعض الطاقة! 👻", 'success');
        triggerFeedback('mystery');
        return;
    }

    const timeMod = getTimeModifier();
    const baseRates = PILLAR_BASE_RATES[task.pillar];
    const multiplier = DIFFICULTY_CONFIG[task.difficulty || 'D'].multiplier;
    const rawEnergyCost = Math.ceil(baseRates.energy * multiplier * timeMod.energy);
    const finalEnergyCost = baseRates.energy < 0 ? baseRates.energy * multiplier : rawEnergyCost; 

    if (task.pillar !== 'Quran' && finalEnergyCost > 0 && stats.energy < finalEnergyCost) {
        addToast("طاقة غير كافية! خذ استراحة.", 'error');
        triggerFeedback('error');
        return;
    }

    setTasks(currentTasks => currentTasks.map(t => t.id === id ? { ...t, completed: true } : t));

    setStats(prev => {
        const today = getLocalDateString();
        let newStreak = prev.streak;
        let lastTaskDate = prev.lastTaskCompletionDate;

        if (lastTaskDate !== today) {
            const d = new Date();
            d.setDate(d.getDate() - 1);
            const yesterdayStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
            if (lastTaskDate === yesterdayStr) newStreak += 1;
            else newStreak = 1;
            lastTaskDate = today;
        }

        let weeklyTasks = (prev.weeklyTasksCompleted || 0) + 1;
        let weeklyStreak = Math.max((prev.weeklyMaxStreak || 0), newStreak);
        let weeklyExercise = (prev.weeklyExerciseCount || 0) + (task.pillar === 'Exercise' ? 1 : 0);

        let newStats = { 
            ...prev,
            streak: newStreak,
            lastTaskCompletionDate: lastTaskDate,
            lastEnergyUpdate: Date.now(),
            weeklyTasksCompleted: weeklyTasks,
            weeklyMaxStreak: weeklyStreak,
            weeklyExerciseCount: weeklyExercise,
            hunterAttributes: { ...prev.hunterAttributes }
        };

        const attrGain = 0.5 * multiplier;
        if (task.pillar === 'Exercise') newStats.hunterAttributes.strength += attrGain;
        if (task.pillar === 'Studying' || task.pillar === 'Learning') newStats.hunterAttributes.intelligence += attrGain;
        if (task.pillar === 'Entertainment') newStats.hunterAttributes.vitality += attrGain;
        if (task.pillar === 'Quran') newStats.hunterAttributes.sense += attrGain;
        if (task.pillar === 'Work') newStats.hunterAttributes.agility += attrGain;

        let didLevelUp = false;

        if (task.pillar === 'Quran') {
            const pagesToAdd = task.pages || 1;
            newStats.quranPagesRead = (prev.quranPagesRead || 0) + pagesToAdd;
            const energyGain = pagesToAdd * ENERGY_PER_QURAN_PAGE;
            newStats.energy = Math.min(newStats.maxEnergy, prev.energy + energyGain);
            addToast(`✅ ${pagesToAdd} صفحة | +${energyGain}⚡ طاقة`, 'success');
            if(soundEnabled) AudioService.playEnergyRestore();
        } 
        else {
            newStats.energy = Math.min(newStats.maxEnergy, prev.energy - finalEnergyCost);

            let finalXpReward = Math.ceil(baseRates.xp * multiplier * timeMod.xp);
            let currentXp = prev.currentXp + finalXpReward;
            newStats.weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + finalXpReward;

            let level = prev.level;
            let maxXp = prev.maxXp;
            while (currentXp >= maxXp) {
                currentXp -= maxXp;
                level += 1;
                maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
                didLevelUp = true;
            }

            if (!didLevelUp) {
                const energyMsg = finalEnergyCost > 0 ? `-${finalEnergyCost}⚡` : `+${Math.abs(finalEnergyCost)}⚡`;
                addToast(`+${finalXpReward} XP | ${energyMsg}`, 'success');
                // Play different sound for hard tasks (B rank or higher)
                const isHard = ['B', 'A', 'S'].includes(task.difficulty);
                if (isHard) triggerFeedback('hard-success');
                else triggerFeedback('success');
            } else {
                 // Level up audio is handled in the modal for cinematic sync
                 // But we trigger the XP gain sound first
                 if(soundEnabled) AudioService.playXpGain();
            }

            newStats.currentXp = currentXp;
            newStats.level = level;
            newStats.maxXp = maxXp;
        }

        if (didLevelUp) {
            newStats.hunterAttributes.strength += 1;
            newStats.hunterAttributes.intelligence += 1;
            newStats.hunterAttributes.vitality += 1;
            newStats.hunterAttributes.sense += 1;
            newStats.hunterAttributes.agility += 1;

            setShowLevelUpModal(true);
        }

        return newStats;
    });
  }, [tasks, stats.energy, addToast, triggerFeedback, soundEnabled]);

  const resetProgress = useCallback(() => {
    if (confirm("هل أنت متأكد من حذف الحساب وإعادة البدء؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
      setWeeklyHistory([]);
      setMonthlyHistory([]);
      setWeeklyReports([]);
      setMonthlyReports([]);
      setWeeklyRewards([]);
      setMonthlyRewards([]);
      setPlayerProfile(null);
      addToast('تم إعادة تعيين الحساب', 'info');
      triggerFeedback('error');
    }
  }, [addToast, triggerFeedback]);

  const value = useMemo(() => ({
    stats,
    tasks,
    playerProfile,
    weeklyHistory,
    monthlyHistory,
    weeklyReports,
    monthlyReports,
    weeklyRewards,
    monthlyRewards,
    createProfile,
    updateProfile,
    addTask,
    editTask,
    deleteTask,
    completeTask, 
    reorderTasks,
    moveTask,
    resetProgress,
    setWeeklyChallenge,
    completeWeeklyChallenge,
    showLevelUpModal,
    closeLevelUpModal,
    updateDailyQuest
  }), [stats, tasks, playerProfile, weeklyHistory, monthlyHistory, weeklyReports, monthlyReports, weeklyRewards, monthlyRewards, createProfile, updateProfile, addTask, editTask, deleteTask, completeTask, reorderTasks, moveTask, resetProgress, setWeeklyChallenge, completeWeeklyChallenge, showLevelUpModal, closeLevelUpModal, updateDailyQuest]);

  return (
    <GameContext.Provider value={value}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

/**
 * Solo Task Audio Engine - Dark RPG Edition
 * Pure Web Audio API Implementation (Offline / Zero Asset)
 */

class AudioEngine {
    private ctx: AudioContext | null = null;
    private masterGain: GainNode | null = null;
    private ambientSource: AudioBufferSourceNode | null = null;
    private ambientGain: GainNode | null = null;
    private volume: number = 0.5;
    private isMuted: boolean = false;
    private noiseBuffer: AudioBuffer | null = null;

    constructor() {
        // Lazy init in methods to adhere to browser autoplay policies
    }

    private getContext(): AudioContext {
        if (!this.ctx) {
            this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
            this.masterGain = this.ctx.createGain();
            this.masterGain.connect(this.ctx.destination);
            this.masterGain.gain.setValueAtTime(this.volume, this.ctx.currentTime);
            this.createNoiseBuffer();
        }
        if (this.ctx.state === 'suspended') {
            this.ctx.resume();
        }
        return this.ctx;
    }

    private createNoiseBuffer() {
        if (!this.ctx) return;
        const bufferSize = this.ctx.sampleRate * 2; // 2 seconds of noise
        const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
        const data = buffer.getChannelData(0);
        for (let i = 0; i < bufferSize; i++) {
            data[i] = Math.random() * 2 - 1; // White noise
        }
        this.noiseBuffer = buffer;
    }

    public setVolume(vol: number) {
        this.volume = Math.max(0, Math.min(1, vol));
        if (this.masterGain && this.ctx) {
            this.masterGain.gain.setTargetAtTime(this.isMuted ? 0 : this.volume, this.ctx.currentTime, 0.1);
        }
    }

    public setMute(muted: boolean) {
        this.isMuted = muted;
        if (this.masterGain && this.ctx) {
            this.masterGain.gain.setTargetAtTime(muted ? 0 : this.volume, this.ctx.currentTime, 0.1);
        }
    }

    // --- FX Helpers ---

    private createReverb(duration: number = 1.0, decay: number = 2.0): GainNode {
        const ctx = this.getContext();
        // Simulating reverb using delay feedback for "metallic" room sound
        const input = ctx.createGain();
        const delay = ctx.createDelay();
        const feedback = ctx.createGain();
        const output = ctx.createGain();

        delay.delayTime.value = 0.03; // 30ms slapback for metallic feel
        feedback.gain.value = 0.4;

        input.connect(output);
        input.connect(delay);
        delay.connect(feedback);
        feedback.connect(delay);
        feedback.connect(output);

        // Connect to master
        if (this.masterGain) output.connect(this.masterGain);
        return input;
    }

    // --- Sound Synthesis Methods ---

    /**
     * UI Click: Short, crisp blip
     */
    public playClick() {
        const ctx = this.getContext();
        const now = ctx.currentTime;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'sine';
        osc.frequency.setValueAtTime(800, now);
        osc.frequency.exponentialRampToValueAtTime(1200, now + 0.05);

        gain.gain.setValueAtTime(0.08, now); // Quiet
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.05);

        osc.connect(gain);
        if (this.masterGain) gain.connect(this.masterGain);

        osc.start(now);
        osc.stop(now + 0.05);
    }

    /**
     * Tab Switch: Airy swoosh
     */
    public playTabSwitch() {
        const ctx = this.getContext();
        const now = ctx.currentTime;

        // Swoosh sound (filtered noise)
        const bufferSize = ctx.sampleRate * 0.2;
        const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
        const data = buffer.getChannelData(0);
        for (let i = 0; i < bufferSize; i++) {
            data[i] = Math.random() * 2 - 1;
        }

        const noise = ctx.createBufferSource();
        noise.buffer = buffer;

        const filter = ctx.createBiquadFilter();
        filter.type = 'bandpass';
        filter.frequency.setValueAtTime(400, now);
        filter.frequency.linearRampToValueAtTime(1200, now + 0.15);
        filter.Q.value = 1;

        const gain = ctx.createGain();
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.linearRampToValueAtTime(0, now + 0.15);

        noise.connect(filter).connect(gain);
        if (this.masterGain) gain.connect(this.masterGain);

        noise.start(now);
    }

    /**
     * Toggle Switch: Up/Down pitch
     */
    public playToggle(state: boolean) {
        const ctx = this.getContext();
        const now = ctx.currentTime;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        // Up for on, Down for off
        const f1 = state ? 400 : 600;
        const f2 = state ? 600 : 400;

        osc.type = 'sine';
        osc.frequency.setValueAtTime(f1, now);
        osc.frequency.linearRampToValueAtTime(f2, now + 0.1);

        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);

        osc.connect(gain);
        if (this.masterGain) gain.connect(this.masterGain);

        osc.start(now);
        osc.stop(now + 0.1);
    }

    /**
     * Pop: Modal Open
     */
    public playPop() {
        const ctx = this.getContext();
        const now = ctx.currentTime;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.frequency.setValueAtTime(400, now);
        osc.frequency.linearRampToValueAtTime(600, now + 0.05);

        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.05);

        osc.connect(gain);
        if (this.masterGain) gain.connect(this.masterGain);

        osc.start(now);
        osc.stop(now + 0.05);
    }

    /**
     * Standard Task Completion: Soft metallic ping
     */
    public playTaskComplete() {
        const ctx = this.getContext();
        const now = ctx.currentTime;
        const gain = ctx.createGain();

        const osc = ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.setValueAtTime(800, now);
        osc.frequency.exponentialRampToValueAtTime(1200, now + 0.1);

        gain.gain.setValueAtTime(0.2, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.3);

        osc.connect(gain);
        // Add subtle echo
        const reverb = this.createReverb();
        gain.connect(reverb);

        osc.start(now);
        osc.stop(now + 0.3);
    }

    /**
     * Hard/Expert Task: Heavy impact tone
     */
    public playHardTaskComplete() {
        const ctx = this.getContext();
        const now = ctx.currentTime;
        const gain = ctx.createGain();

        // Low impact
        const osc1 = ctx.createOscillator();
        osc1.type = 'triangle';
        osc1.frequency.setValueAtTime(100, now);
        osc1.frequency.exponentialRampToValueAtTime(40, now + 0.4);

        // High metallic ring
        const osc2 = ctx.createOscillator();
        osc2.type = 'sine';
        osc2.frequency.setValueAtTime(400, now);
        osc2.frequency.linearRampToValueAtTime(800, now + 0.1);

        gain.gain.setValueAtTime(0.4, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.6);

        osc1.connect(gain);
        osc2.connect(gain);

        if (this.masterGain) gain.connect(this.masterGain);

        osc1.start(now);
        osc1.stop(now + 0.6);
        osc2.start(now);
        osc2.stop(now + 0.6);
    }

    /**
     * XP Gain: Sci-fi digital pulse
     */
    public playXpGain() {
        const ctx = this.getContext();
        const now = ctx.currentTime;
        const gain = ctx.createGain();
        const osc = ctx.createOscillator();

        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(200, now);
        osc.frequency.linearRampToValueAtTime(600, now + 0.15);

        // Lowpass to make it less harsh
        const filter = ctx.createBiquadFilter();
        filter.type = 'lowpass';
        filter.frequency.value = 1000;

        gain.gain.setValueAtTime(0.1, now);
        gain.gain.linearRampToValueAtTime(0, now + 0.15);

        osc.connect(filter);
        filter.connect(gain);
        if (this.masterGain) gain.connect(this.masterGain);

        osc.start(now);
        osc.stop(now + 0.15);
    }

    /**
     * LEVEL UP: Complex multi-layered cinematic sound
     */
    public playLevelUp() {
        const ctx = this.getContext();
        const now = ctx.currentTime;

        // Layer 1: Sub-bass Swell (The Power)
        const subOsc = ctx.createOscillator();
        const subGain = ctx.createGain();
        subOsc.type = 'sine';
        subOsc.frequency.setValueAtTime(40, now);
        subOsc.frequency.linearRampToValueAtTime(60, now + 1.5);
        subGain.gain.setValueAtTime(0, now);
        subGain.gain.linearRampToValueAtTime(0.6, now + 0.5);
        subGain.gain.exponentialRampToValueAtTime(0.01, now + 2.5);

        // Layer 2: Mid-range Sweep (The Rise)
        const midOsc = ctx.createOscillator();
        const midGain = ctx.createGain();
        const midFilter = ctx.createBiquadFilter();
        midOsc.type = 'sawtooth';
        midOsc.frequency.setValueAtTime(100, now);
        midOsc.frequency.exponentialRampToValueAtTime(800, now + 1.0);
        midFilter.type = 'lowpass';
        midFilter.frequency.setValueAtTime(200, now);
        midFilter.frequency.linearRampToValueAtTime(2000, now + 1.0);
        midGain.gain.setValueAtTime(0, now);
        midGain.gain.linearRampToValueAtTime(0.2, now + 0.8);
        midGain.gain.linearRampToValueAtTime(0, now + 1.2);

        // Layer 3: Impact/Explosion (The Release)
        const impactTime = now + 1.0;
        const noiseSrc = ctx.createBufferSource();
        if (this.noiseBuffer) noiseSrc.buffer = this.noiseBuffer;
        const noiseFilter = ctx.createBiquadFilter();
        const noiseGain = ctx.createGain();
        noiseFilter.type = 'lowpass';
        noiseFilter.frequency.setValueAtTime(500, impactTime);
        noiseFilter.frequency.exponentialRampToValueAtTime(100, impactTime + 1.0);
        noiseGain.gain.setValueAtTime(0, impactTime);
        noiseGain.gain.setValueAtTime(0.4, impactTime); // Burst
        noiseGain.gain.exponentialRampToValueAtTime(0.01, impactTime + 1.5);

        // Routing
        if (this.masterGain) {
            subOsc.connect(subGain).connect(this.masterGain);
            midOsc.connect(midFilter).connect(midGain).connect(this.masterGain);

            // Reverb on impact
            const reverb = this.createReverb();
            noiseSrc.connect(noiseFilter).connect(noiseGain);
            noiseGain.connect(reverb); 
        }

        // Execution
        subOsc.start(now);
        subOsc.stop(now + 2.5);
        midOsc.start(now);
        midOsc.stop(now + 1.2);
        noiseSrc.start(impactTime);
        noiseSrc.stop(impactTime + 1.5);
    }

    /**
     * Energy Restore: Calm Chime
     */
    public playEnergyRestore() {
        const ctx = this.getContext();
        const now = ctx.currentTime;
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'sine';
        osc.frequency.setValueAtTime(440, now); // A4
        osc.frequency.setValueAtTime(554, now + 0.1); // C#5
        osc.frequency.setValueAtTime(659, now + 0.2); // E5

        gain.gain.setValueAtTime(0, now);
        gain.gain.linearRampToValueAtTime(0.1, now + 0.1);
        gain.gain.linearRampToValueAtTime(0, now + 1.0);

        osc.connect(gain);
        if (this.masterGain) gain.connect(this.masterGain);

        osc.start(now);
        osc.stop(now + 1.0);
    }

    /**
     * Energy Depleted: Low Pulse
     */
    public playEnergyWarning() {
        const ctx = this.getContext();
        const now = ctx.currentTime;
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'sine';
        osc.frequency.setValueAtTime(60, now);
        osc.frequency.linearRampToValueAtTime(40, now + 0.3);

        gain.gain.setValueAtTime(0.3, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.4);

        osc.connect(gain);
        if (this.masterGain) gain.connect(this.masterGain);

        osc.start(now);
        osc.stop(now + 0.4);
    }

    /**
     * Failure/Missed Task: Low metallic thud
     */
    public playFailure() {
        const ctx = this.getContext();
        const now = ctx.currentTime;
        const gain = ctx.createGain();

        // Low thud
        const osc = ctx.createOscillator();
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(80, now);
        osc.frequency.exponentialRampToValueAtTime(10, now + 0.5);

        // Filter
        const filter = ctx.createBiquadFilter();
        filter.type = 'lowpass';
        filter.frequency.setValueAtTime(200, now);
        filter.frequency.linearRampToValueAtTime(50, now + 0.5);

        gain.gain.setValueAtTime(0.4, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.5);

        osc.connect(filter);
        filter.connect(gain);
        if (this.masterGain) gain.connect(this.masterGain);

        osc.start(now);
        osc.stop(now + 0.5);
    }

    /**
     * Weekly Report/Hidden Unlock: Mystery Reveal
     */
    public playMysteryReveal() {
        const ctx = this.getContext();
        const now = ctx.currentTime;
        const osc1 = ctx.createOscillator();
        const osc2 = ctx.createOscillator();
        const gain = ctx.createGain();

        osc1.frequency.setValueAtTime(200, now);
        osc2.frequency.setValueAtTime(204, now); // Slight detune for phasing

        gain.gain.setValueAtTime(0, now);
        gain.gain.linearRampToValueAtTime(0.15, now + 0.5);
        gain.gain.linearRampToValueAtTime(0, now + 2.0);

        osc1.connect(gain);
        osc2.connect(gain);

        const reverb = this.createReverb();
        gain.connect(reverb);

        osc1.start(now);
        osc1.stop(now + 2.0);
        osc2.start(now);
        osc2.stop(now + 2.0);
    }

    /**
     * Motivation Boost: Rising energy sound
     */
    public playBoost() {
        if (!this.ctx) this.getContext(); 
        const ctx = this.getContext();
        const now = ctx.currentTime;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'triangle';
        osc.frequency.setValueAtTime(200, now);
        osc.frequency.exponentialRampToValueAtTime(600, now + 0.4);

        gain.gain.setValueAtTime(0, now);
        gain.gain.linearRampToValueAtTime(0.2, now + 0.1);
        gain.gain.linearRampToValueAtTime(0, now + 0.4);

        osc.connect(gain);
        if (this.masterGain) gain.connect(this.masterGain);

        osc.start(now);
        osc.stop(now + 0.4);
    }

    // --- Ambient Drone (Dungeon Vibe) ---

    public startAmbient() {
        if (this.ambientSource) return; // Already playing

        const ctx = this.getContext();
        const src = ctx.createBufferSource();
        if (this.noiseBuffer) src.buffer = this.noiseBuffer;
        src.loop = true;

        const filter = ctx.createBiquadFilter();
        filter.type = 'bandpass';
        filter.frequency.value = 100; // Low rumble
        filter.Q.value = 1;

        const gain = ctx.createGain();
        gain.gain.value = 0.05; // Very subtle

        // LFO to modulate filter (breathing effect)
        const lfo = ctx.createOscillator();
        lfo.frequency.value = 0.2; // Slow cycle
        const lfoGain = ctx.createGain();
        lfoGain.gain.value = 50;
        lfo.connect(lfoGain).connect(filter.frequency);

        src.connect(filter).connect(gain);
        if (this.masterGain) gain.connect(this.masterGain);

        src.start();
        lfo.start();

        this.ambientSource = src;
        this.ambientGain = gain;
    }

    public stopAmbient() {
        if (this.ambientSource) {
            // Fade out
            if (this.ambientGain && this.ctx) {
                this.ambientGain.gain.setTargetAtTime(0, this.ctx.currentTime, 0.5);
            }
            setTimeout(() => {
                this.ambientSource?.stop();
                this.ambientSource = null;
                this.ambientGain = null;
            }, 600);
        }
    }
}

export const AudioService = new AudioEngine();

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo, useRef } from 'react';
import { GameState, Task, UserStats, PlayerProfile, WeeklyHistory, MonthlyHistory, WeeklyReport, MonthlyReport, WeeklyReward, MonthlyReward, DailyQuestProgress, BASE_XP_PER_LEVEL, DayOfWeek } from '../types';
import { ENERGY_RECOVERY_RATE, PILLAR_BASE_RATES, DIFFICULTY_CONFIG, XP_SCALING_FACTOR, SHADOW_TASKS, DAILY_QUEST_TARGETS, ENERGY_PER_QURAN_PAGE, DAYS_OF_WEEK, XP_PENALTY_RATIO, MAX_DAILY_XP_LOSS_PERCENT } from '../constants';
import { StorageService, defaultStats } from '../services/storage';
import { HistoryEngine } from '../services/historyEngine';
import { useToast } from './ToastContext';
import { useSettings } from '../context/SettingsContext';
import { AudioService } from '../services/audioService';

interface GameContextType extends GameState {
  createProfile: (profileData: Omit<PlayerProfile, 'createdAt'>) => void;
  updateProfile: (updates: Partial<PlayerProfile>) => void;
  addTask: (task: Partial<Task>) => void;
  editTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  reorderTasks: (reorderedTasks: Task[]) => void;
  moveTask: (taskId: string, direction: 'up' | 'down') => void;
  resetProgress: () => void;
  setWeeklyChallenge: (title: string) => void;
  completeWeeklyChallenge: () => void;
  updateDailyQuest: (type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => void;
  showLevelUpModal: boolean;
  closeLevelUpModal: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

// Helper for local date string YYYY-MM-DD
const getLocalDateString = () => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
};

// Helper for safe UUID
const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
    }
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

// 2️⃣ Time Modifier Function
const getTimeModifier = () => {
    const hour = new Date().getHours();
    if (hour >= 6 && hour < 10) return { xp: 1.15, energy: 0.85 }; // Morning Bonus
    if (hour >= 22 || hour < 4) return { xp: 0.85, energy: 1.15 }; // Night Penalty
    return { xp: 1, energy: 1 };
};

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [playerProfile, setPlayerProfile] = useState<PlayerProfile | null>(null);

  // History State
  const [weeklyHistory, setWeeklyHistory] = useState<WeeklyHistory[]>([]);
  const [monthlyHistory, setMonthlyHistory] = useState<MonthlyHistory[]>([]);
  const [weeklyReports, setWeeklyReports] = useState<WeeklyReport[]>([]);
  const [monthlyReports, setMonthlyReports] = useState<MonthlyReport[]>([]);
  const [weeklyRewards, setWeeklyRewards] = useState<WeeklyReward[]>([]);
  const [monthlyRewards, setMonthlyRewards] = useState<MonthlyReward[]>([]);

  const [isLoaded, setIsLoaded] = useState(false);
  const [showLevelUpModal, setShowLevelUpModal] = useState(false);
  const { addToast } = useToast();
  const { soundEnabled, hapticsEnabled } = useSettings();

  // Ref to track if we are currently saving to avoid loops
  const isSaving = useRef(false);

  // Helper for Sound/Haptics
  const triggerFeedback = useCallback((type: 'success' | 'hard-success' | 'error' | 'levelup' | 'click' | 'boost' | 'mystery' | 'failure') => {
      if (hapticsEnabled && navigator.vibrate) {
          if (type === 'success') navigator.vibrate(50);
          if (type === 'hard-success') navigator.vibrate([100, 50, 100]);
          if (type === 'error') navigator.vibrate([50, 50, 50]);
          if (type === 'levelup') navigator.vibrate([100, 50, 100, 50, 200]);
          if (type === 'click') navigator.vibrate(10);
          if (type === 'failure') navigator.vibrate([500, 200]);
      }

      if (soundEnabled) {
          if (type === 'success') AudioService.playTaskComplete();
          if (type === 'hard-success') AudioService.playHardTaskComplete();
          if (type === 'error') AudioService.playEnergyWarning();
          if (type === 'click') AudioService.playClick(); // Updated to cleaner click
          if (type === 'boost') AudioService.playXpGain();
          if (type === 'mystery') AudioService.playMysteryReveal();
          if (type === 'failure') AudioService.playFailure();
      }
  }, [soundEnabled, hapticsEnabled]);

  // --- 1. INITIAL LOAD & TIME TRAVEL ENGINE ---
  useEffect(() => {
    const loadedProfile = StorageService.loadProfile();
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();
    const loadedWeekly = StorageService.loadWeeklyHistory();
    const loadedMonthly = StorageService.loadMonthlyHistory();
    const loadedWeeklyReports = StorageService.loadWeeklyReports();
    const loadedMonthlyReports = StorageService.loadMonthlyReports();
    const loadedWeeklyRewards = StorageService.loadWeeklyRewards();
    const loadedMonthlyRewards = StorageService.loadMonthlyRewards();

    if (loadedProfile) setPlayerProfile(loadedProfile);
    if (loadedTasks) setTasks(loadedTasks);

    // Set history states initially
    setWeeklyHistory(loadedWeekly);
    setMonthlyHistory(loadedMonthly);
    setWeeklyReports(loadedWeeklyReports);
    setMonthlyReports(loadedMonthlyReports);
    setWeeklyRewards(loadedWeeklyRewards);
    setMonthlyRewards(loadedMonthlyRewards);

    if (loadedStats) {
        let currentStats = { ...loadedStats };
        const today = getLocalDateString();
        const nowMs = Date.now();
        const isNewDay = currentStats.lastLoginDate !== today;

        // --- NEW: MISSED TASK LOGIC (Penalty System) ---
        // This runs BEFORE we potentially reset the day/week, locking in yesterday's failures.
        let updatedTasks = loadedTasks ? [...loadedTasks] : [];
        let missedCount = 0;
        let totalXpPenalty = 0;
        let energyPenalty = 0;

        // Map DayOfWeek to index 0-6 (Saturday to Friday)
        const dayIndices = { 'Saturday': 0, 'Sunday': 1, 'Monday': 2, 'Tuesday': 3, 'Wednesday': 4, 'Thursday': 5, 'Friday': 6 };
        const currentDayName = DAYS_OF_WEEK[new Date().getDay()].id as DayOfWeek; // Correct day from system
        const currentDayIdx = dayIndices[currentDayName];

        updatedTasks = updatedTasks.map(t => {
            if (!t.completed && !t.isMissed && t.day) {
                const taskDayIdx = dayIndices[t.day];

                // If the task was scheduled for a previous day in the current cycle
                if (taskDayIdx < currentDayIdx) {
                    // Check safe window: Created < 2 hours before midnight of that day?
                    // Simplified: Check if created more than 24h ago
                    const createdAgo = nowMs - t.createdAt;
                    if (createdAgo > 24 * 60 * 60 * 1000) {
                        missedCount++;
                        const penalty = Math.ceil(t.xpReward * XP_PENALTY_RATIO);
                        totalXpPenalty += penalty;

                        // Energy penalty for high difficulty
                        if (['A', 'S'].includes(t.difficulty)) {
                            energyPenalty += 5; // Flat 5 energy penalty
                        }

                        return { ...t, isMissed: true };
                    }
                }
            }
            return t;
        });

        // Apply XP Penalties
        if (missedCount > 0) {
            // Cap XP loss at 25% of current XP
            const maxLoss = Math.floor(currentStats.currentXp * MAX_DAILY_XP_LOSS_PERCENT);
            const actualXpLoss = Math.min(totalXpPenalty, maxLoss);

            currentStats.currentXp = Math.max(0, currentStats.currentXp - actualXpLoss);

            // Track stats
            currentStats.weeklyMissedTasks = (currentStats.weeklyMissedTasks || 0) + missedCount;
            currentStats.weeklyXpLost = (currentStats.weeklyXpLost || 0) + actualXpLoss;

            // Delayed Toast for UI feedback after render
            setTimeout(() => {
                addToast(`⚠️ ${missedCount} مهام فائتة! -${actualXpLoss} XP`, 'error');
                triggerFeedback('failure');
            }, 2000);

            // Update tasks state immediately
            setTasks(updatedTasks);
        }

        // --- ENERGY LOGIC ---
        // Variable to hold the target energy for today (to allow animation)
        let targetEnergy = currentStats.energy;

        if (isNewDay) {
            // Rule 1: Reset to Max on New Day
            // Rule 3: Visual/UX Feedback triggers later

            // Apply Missed Task Energy Penalty to the MAX restoration (Rule 3 previous prompt)
            let dailyResetValue = currentStats.maxEnergy;

            if (energyPenalty > 0) {
                 dailyResetValue = Math.max(0, dailyResetValue - energyPenalty);
                 // We accumulate the notification
                 setTimeout(() => {
                     addToast(`⚠️ خصم طاقة: -${energyPenalty} (مهام فائتة)`, 'error');
                 }, 2500);
            }

            targetEnergy = dailyResetValue;
            currentStats.lastEnergyUpdate = nowMs; // Reset timer base

            // Keep currentStats.energy at OLD value briefly to allow animation in UI
            // We do NOT update currentStats.energy here yet

        } else {
            // Same Day: Passive Regeneration (Offline Calculation)
            if (currentStats.energy < currentStats.maxEnergy) {
                const lastUpdate = currentStats.lastEnergyUpdate || nowMs;
                const diffInHours = (nowMs - lastUpdate) / (1000 * 60 * 60);
                const energyRecovered = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);
                if (energyRecovered > 0) {
                    currentStats.energy = Math.min(currentStats.maxEnergy, currentStats.energy + energyRecovered);
                    currentStats.lastEnergyUpdate = nowMs; // Reset timer base
                }
            } else {
                 currentStats.lastEnergyUpdate = nowMs;
            }

            // Apply immediate penalty if same day
            if (energyPenalty > 0) {
                currentStats.energy = Math.max(0, currentStats.energy - energyPenalty);
            }
            targetEnergy = currentStats.energy; // No animation needed for same day passive
        }

        // C. Daily Quest Reset & Streak Decay
        if (currentStats.dailyQuest?.lastResetDate !== today) {
             // Streak Logic
             const lastTaskDate = new Date(currentStats.lastTaskCompletionDate || '1970-01-01');
             const yesterday = new Date();
             yesterday.setDate(yesterday.getDate() - 1);
             const lastTaskStr = lastTaskDate.toISOString().split('T')[0];
             const yesterdayStr = yesterday.toISOString().split('T')[0];

             if (lastTaskStr !== today && lastTaskStr !== yesterdayStr) {
                 if (currentStats.streak > 0) {
                    addToast("انقطعت السلسلة! 😢", "error");
                    currentStats.streak = 0;
                 }
             }

             // Reset Daily Quest
             currentStats.dailyQuest = {
                pushups: 0, situps: 0, squats: 0, run: 0,
                isCompleted: false,
                lastResetDate: today
            };
        }
        currentStats.lastLoginDate = today;

        // D. Process Time Skip (Weekly/Monthly Reports)
        const processed = HistoryEngine.processTimeSkip(
            currentStats,
            updatedTasks,
            loadedWeekly,
            loadedMonthly,
            loadedWeeklyReports,
            loadedMonthlyReports,
            loadedWeeklyRewards,
            loadedMonthlyRewards
        );

        if (processed.reportsGenerated > 0) {
            addToast(`تم إصدار ${processed.reportsGenerated} تقارير جديدة! 📊`, 'info');
            // Trigger mystery sound for new report
            if(soundEnabled) AudioService.playMysteryReveal();

            setWeeklyHistory(processed.weeklyHistory);
            setMonthlyHistory(processed.monthlyHistory);
            setWeeklyReports(processed.weeklyReports);
            setMonthlyReports(processed.monthlyReports);
            setWeeklyRewards(processed.weeklyRewards);
            setMonthlyRewards(processed.monthlyRewards);

            // Trigger batch save
            StorageService.saveWeeklyHistory(processed.weeklyHistory);
            StorageService.saveMonthlyHistory(processed.monthlyHistory);
            StorageService.saveWeeklyReports(processed.weeklyReports);
            StorageService.saveMonthlyReports(processed.monthlyReports);
            StorageService.saveWeeklyRewards(processed.weeklyRewards);
            StorageService.saveMonthlyRewards(processed.monthlyRewards);
        }

        // Set State
        setStats(processed.stats);

        // Trigger Energy Restore Animation and Toast if New Day
        if (isNewDay) {
            setTimeout(() => {
                setStats(prev => ({ ...prev, energy: targetEnergy }));
                if (soundEnabled) AudioService.playEnergyRestore();
                addToast("🌅 يوم جديد! تم استعادة طاقتك بالكامل.", 'success');
            }, 800);
        }
    }

    setIsLoaded(true);
  }, []);


  // --- 2. GAME LOOP (HEARTBEAT) ---
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    const tick = () => {
        setStats(prev => {
            const now = Date.now();

            // Energy Logic
            let newEnergy = prev.energy;
            let lastUpdate = prev.lastEnergyUpdate;

            if (newEnergy < prev.maxEnergy) {
                const diffInHours = (now - lastUpdate) / (1000 * 60 * 60);
                const thresholdHours = 1 / ENERGY_RECOVERY_RATE; 

                if (diffInHours >= thresholdHours) {
                    const energyGained = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);
                    newEnergy = Math.min(prev.maxEnergy, prev.energy + energyGained);
                    lastUpdate = lastUpdate + (energyGained / ENERGY_RECOVERY_RATE) * (1000 * 60 * 60); 

                    // Sound Effect for passive restore
                    if (soundEnabled) AudioService.playEnergyRestore();
                }
            } else {
                lastUpdate = now;
            }

            if (newEnergy === prev.energy && lastUpdate === prev.lastEnergyUpdate) {
                return prev;
            }

            return {
                ...prev,
                energy: newEnergy,
                lastEnergyUpdate: lastUpdate
            };
        });
    };

    const interval = setInterval(tick, 30000); // Check every 30 seconds
    return () => clearInterval(interval);
  }, [isLoaded, playerProfile, soundEnabled]);


  // --- 3. SHADOW TASK INJECTOR ---
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    if (stats.energy < 20) {
        setTasks(currentTasks => {
            const hasShadowTask = currentTasks.some(t => t.isShadow && !t.completed);
            if (!hasShadowTask) {
                const randomShadow = SHADOW_TASKS[Math.floor(Math.random() * SHADOW_TASKS.length)];
                const shadowTask: Task = {
                    id: generateId(),
                    title: `👻 ${randomShadow.title}`,
                    description: randomShadow.description,
                    pillar: 'Entertainment',
                    completed: false,
                    energyCost: -randomShadow.energyRestore,
                    xpReward: 0,
                    difficulty: 'E',
                    createdAt: Date.now(),
                    order: -1,
                    isShadow: true
                };
                addToast("ظهرت مهمة ظل! استعد طاقتك الآن.", 'shadow');
                if (soundEnabled) AudioService.playMysteryReveal();
                return [shadowTask, ...currentTasks];
            }
            return currentTasks;
        });
    }
  }, [stats.energy, isLoaded, playerProfile, soundEnabled]); 


  // --- 4. AUTO-SAVE SYSTEM ---
  useEffect(() => {
    if (isLoaded && playerProfile && !isSaving.current) {
        isSaving.current = true;
        StorageService.saveStats(stats);
        StorageService.saveTasks(tasks);
        setTimeout(() => { isSaving.current = false; }, 100);
    }
  }, [stats, tasks, isLoaded, playerProfile]);


  // --- ACTIONS ---

  const createProfile = useCallback((data: Omit<PlayerProfile, 'createdAt'>) => {
    const newProfile: PlayerProfile = {
        ...data,
        createdAt: new Date().toISOString()
    };
    StorageService.initializeNewAccount(newProfile);
    setPlayerProfile(newProfile);
    setStats({
        ...defaultStats,
        lastLoginDate: getLocalDateString()
    });
    setTasks([]);
    triggerFeedback('success');
    addToast('أهلاً بك في رحلة التطوير! 🚀', 'success');
  }, [addToast, triggerFeedback]);

  const updateProfile = useCallback((updates: Partial<PlayerProfile>) => {
    setPlayerProfile(prev => {
        if (!prev) return null;
        const updated = { ...prev, ...updates };
        StorageService.saveProfile(updated);
        return updated;
    });
    addToast('تم تحديث البيانات', 'success');
  }, [addToast]);

  const addTask = useCallback((taskData: Partial<Task>) => {
    setTasks(prev => {
        const maxOrder = prev.length > 0 ? Math.max(...prev.map(t => t.order)) : 0;
        const pillar = taskData.pillar || 'Work';
        const difficulty = taskData.difficulty || 'D';

        const baseRates = PILLAR_BASE_RATES[pillar];
        const multiplier = DIFFICULTY_CONFIG[difficulty].multiplier;

        const newTask: Task = {
          id: generateId(),
          title: taskData.title || (pillar === 'Quran' ? 'ورد القرآن' : 'مهمة جديدة'),
          description: taskData.description || '',
          pillar: pillar,
          completed: false,
          difficulty: difficulty,
          energyCost: Math.ceil(baseRates.energy * multiplier),
          xpReward: Math.ceil(baseRates.xp * multiplier),
          dueDate: taskData.dueDate,
          day: taskData.day,
          createdAt: Date.now(),
          order: maxOrder + 1,
          pages: taskData.pages
        };
        return [...prev, newTask];
    });
    triggerFeedback('click');
    addToast('تمت إضافة المهمة بنجاح', 'success');
  }, [addToast, triggerFeedback]);

  const editTask = useCallback((id: string, updates: Partial<Task>) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;
      const pillar = updates.pillar || t.pillar;
      const difficulty = updates.difficulty || t.difficulty;
      const baseRates = PILLAR_BASE_RATES[pillar];
      const multiplier = DIFFICULTY_CONFIG[difficulty].multiplier;

      return { 
          ...t, 
          ...updates,
          energyCost: Math.ceil(baseRates.energy * multiplier),
          xpReward: Math.ceil(baseRates.xp * multiplier)
      };
    }));
    addToast('تم حفظ التعديلات', 'success');
  }, [addToast]);

  const deleteTask = useCallback((id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    addToast('تم حذف المهمة', 'info');
  }, [addToast]);

  const reorderTasks = useCallback((reorderedTasks: Task[]) => {
      setTasks(reorderedTasks);
  }, []);

  const moveTask = useCallback((taskId: string, direction: 'up' | 'down') => {
      setTasks(prevTasks => {
        const sortedTasks = [...prevTasks].sort((a, b) => a.order - b.order);
        const sortedIndex = sortedTasks.findIndex(t => t.id === taskId);
        if (sortedIndex === -1) return prevTasks;
        if (direction === 'up' && sortedIndex > 0) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex - 1].order;
            sortedTasks[sortedIndex - 1].order = tempOrder;
        } else if (direction === 'down' && sortedIndex < sortedTasks.length - 1) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex + 1].order;
            sortedTasks[sortedIndex + 1].order = tempOrder;
        }
        return [...sortedTasks];
      });
      triggerFeedback('click');
  }, [triggerFeedback]);

  const setWeeklyChallenge = useCallback((title: string) => {
    setStats(prev => ({
        ...prev,
        weeklyChallenge: {
            id: generateId(),
            title: title,
            weekStart: getLocalDateString(),
            completed: false
        }
    }));
    triggerFeedback('click');
    addToast('تم تحديد التحدي الأسبوعي! 🎯', 'info');
  }, [addToast, triggerFeedback]);

  const completeWeeklyChallenge = useCallback(() => {
    setStats(prev => {
        if (!prev.weeklyChallenge || prev.weeklyChallenge.completed) return prev;

        const bonusXP = Math.floor(prev.maxXp * 0.25);

        let currentXp = prev.currentXp + bonusXP;
        let weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + bonusXP;

        let level = prev.level;
        let maxXp = prev.maxXp;
        let didLevelUp = false;

        while (currentXp >= maxXp) {
            currentXp -= maxXp;
            level += 1;
            maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
            didLevelUp = true;
        }

        let newAttributes = { ...prev.hunterAttributes };
        if (didLevelUp) {
             newAttributes.strength += 1;
             newAttributes.intelligence += 1;
             newAttributes.vitality += 1;
             newAttributes.sense += 1;
             newAttributes.agility += 1;
        }

        if (didLevelUp) {
            setShowLevelUpModal(true);
        } else {
            addToast(`مكافأة التحدي: +${bonusXP} XP 🔥`, 'success');
            triggerFeedback('hard-success');
        }

        return {
            ...prev,
            weeklyChallenge: { ...prev.weeklyChallenge!, completed: true },
            currentXp, level, maxXp, weeklyXpAccumulated,
            hunterAttributes: newAttributes
        };
    });
  }, [addToast, triggerFeedback]);

  const closeLevelUpModal = useCallback(() => {
    setShowLevelUpModal(false);
  }, []);

  const updateDailyQuest = useCallback((type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => {
      setStats(prev => {
          if (!prev.dailyQuest || prev.dailyQuest.isCompleted) return prev;

          const newStats = { ...prev };
          newStats.dailyQuest = { ...prev.dailyQuest, [type]: Math.min(DAILY_QUEST_TARGETS[type], amount) };

          const { pushups, situps, squats, run } = newStats.dailyQuest;
          const target = DAILY_QUEST_TARGETS;

          if (pushups >= target.pushups && situps >= target.situps && squats >= target.squats && run >= target.run) {
              if (!prev.dailyQuest.isCompleted) {
                  newStats.dailyQuest.isCompleted = true;
                  newStats.energy = newStats.maxEnergy;
                  const dailyXpReward = Math.floor(prev.maxXp * 0.15);
                  newStats.currentXp += dailyXpReward;

                  newStats.hunterAttributes.strength += 2;
                  newStats.hunterAttributes.vitality += 1;

                  addToast(`مهمة يومية مكتملة! طاقة كاملة + ${dailyXpReward}XP`, 'success');
                  triggerFeedback('hard-success');
              }
          }
          triggerFeedback('click');
          return newStats;
      });
  }, [addToast, triggerFeedback]);

  const completeTask = useCallback((id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed || task.isMissed) return; // Ignore missed tasks

    if (task.isShadow) {
        setStats(prev => ({
            ...prev,
            energy: Math.min(prev.maxEnergy, prev.energy + Math.abs(task.energyCost))
        }));
        setTasks(prev => prev.filter(t => t.id !== id));
        addToast("تم استعادة بعض الطاقة! 👻", 'success');
        triggerFeedback('mystery');
        return;
    }

    const timeMod = getTimeModifier();
    const baseRates = PILLAR_BASE_RATES[task.pillar];
    const multiplier = DIFFICULTY_CONFIG[task.difficulty || 'D'].multiplier;
    const rawEnergyCost = Math.ceil(baseRates.energy * multiplier * timeMod.energy);
    const finalEnergyCost = baseRates.energy < 0 ? baseRates.energy * multiplier : rawEnergyCost; 

    if (task.pillar !== 'Quran' && finalEnergyCost > 0 && stats.energy < finalEnergyCost) {
        addToast("طاقة غير كافية! خذ استراحة.", 'error');
        triggerFeedback('error');
        return;
    }

    setTasks(currentTasks => currentTasks.map(t => t.id === id ? { ...t, completed: true } : t));

    setStats(prev => {
        const today = getLocalDateString();
        let newStreak = prev.streak;
        let lastTaskDate = prev.lastTaskCompletionDate;

        if (lastTaskDate !== today) {
            const d = new Date();
            d.setDate(d.getDate() - 1);
            const yesterdayStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
            if (lastTaskDate === yesterdayStr) newStreak += 1;
            else newStreak = 1;
            lastTaskDate = today;
        }

        let weeklyTasks = (prev.weeklyTasksCompleted || 0) + 1;
        let weeklyStreak = Math.max((prev.weeklyMaxStreak || 0), newStreak);
        let weeklyExercise = (prev.weeklyExerciseCount || 0) + (task.pillar === 'Exercise' ? 1 : 0);

        let newStats = { 
            ...prev,
            streak: newStreak,
            lastTaskCompletionDate: lastTaskDate,
            lastEnergyUpdate: Date.now(),
            weeklyTasksCompleted: weeklyTasks,
            weeklyMaxStreak: weeklyStreak,
            weeklyExerciseCount: weeklyExercise,
            hunterAttributes: { ...prev.hunterAttributes }
        };

        const attrGain = 0.5 * multiplier;
        if (task.pillar === 'Exercise') newStats.hunterAttributes.strength += attrGain;
        if (task.pillar === 'Studying' || task.pillar === 'Learning') newStats.hunterAttributes.intelligence += attrGain;
        if (task.pillar === 'Entertainment') newStats.hunterAttributes.vitality += attrGain;
        if (task.pillar === 'Quran') newStats.hunterAttributes.sense += attrGain;
        if (task.pillar === 'Work') newStats.hunterAttributes.agility += attrGain;

        let didLevelUp = false;

        if (task.pillar === 'Quran') {
            const pagesToAdd = task.pages || 1;
            newStats.quranPagesRead = (prev.quranPagesRead || 0) + pagesToAdd;
            const energyGain = pagesToAdd * ENERGY_PER_QURAN_PAGE;
            newStats.energy = Math.min(newStats.maxEnergy, prev.energy + energyGain);
            addToast(`✅ ${pagesToAdd} صفحة | +${energyGain}⚡ طاقة`, 'success');
            if(soundEnabled) AudioService.playEnergyRestore();
        } 
        else {
            newStats.energy = Math.min(newStats.maxEnergy, prev.energy - finalEnergyCost);

            let finalXpReward = Math.ceil(baseRates.xp * multiplier * timeMod.xp);
            let currentXp = prev.currentXp + finalXpReward;
            newStats.weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + finalXpReward;

            let level = prev.level;
            let maxXp = prev.maxXp;
            while (currentXp >= maxXp) {
                currentXp -= maxXp;
                level += 1;
                maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
                didLevelUp = true;
            }

            if (!didLevelUp) {
                const energyMsg = finalEnergyCost > 0 ? `-${finalEnergyCost}⚡` : `+${Math.abs(finalEnergyCost)}⚡`;
                addToast(`+${finalXpReward} XP | ${energyMsg}`, 'success');
                // Play different sound for hard tasks (B rank or higher)
                const isHard = ['B', 'A', 'S'].includes(task.difficulty);
                if (isHard) triggerFeedback('hard-success');
                else triggerFeedback('success');
            } else {
                 // Level up audio is handled in the modal for cinematic sync
                 // But we trigger the XP gain sound first
                 if(soundEnabled) AudioService.playXpGain();
            }

            newStats.currentXp = currentXp;
            newStats.level = level;
            newStats.maxXp = maxXp;
        }

        if (didLevelUp) {
            newStats.hunterAttributes.strength += 1;
            newStats.hunterAttributes.intelligence += 1;
            newStats.hunterAttributes.vitality += 1;
            newStats.hunterAttributes.sense += 1;
            newStats.hunterAttributes.agility += 1;

            setShowLevelUpModal(true);
        }

        return newStats;
    });
  }, [tasks, stats.energy, addToast, triggerFeedback, soundEnabled]);

  const resetProgress = useCallback(() => {
    if (confirm("هل أنت متأكد من حذف الحساب وإعادة البدء؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
      setWeeklyHistory([]);
      setMonthlyHistory([]);
      setWeeklyReports([]);
      setMonthlyReports([]);
      setWeeklyRewards([]);
      setMonthlyRewards([]);
      setPlayerProfile(null);
      addToast('تم إعادة تعيين الحساب', 'info');
      triggerFeedback('error');
    }
  }, [addToast, triggerFeedback]);

  const value = useMemo(() => ({
    stats,
    tasks,
    playerProfile,
    weeklyHistory,
    monthlyHistory,
    weeklyReports,
    monthlyReports,
    weeklyRewards,
    monthlyRewards,
    createProfile,
    updateProfile,
    addTask,
    editTask,
    deleteTask,
    completeTask, 
    reorderTasks,
    moveTask,
    resetProgress,
    setWeeklyChallenge,
    completeWeeklyChallenge,
    showLevelUpModal,
    closeLevelUpModal,
    updateDailyQuest
  }), [stats, tasks, playerProfile, weeklyHistory, monthlyHistory, weeklyReports, monthlyReports, weeklyRewards, monthlyRewards, createProfile, updateProfile, addTask, editTask, deleteTask, completeTask, reorderTasks, moveTask, resetProgress, setWeeklyChallenge, completeWeeklyChallenge, showLevelUpModal, closeLevelUpModal, updateDailyQuest]);

  return (
    <GameContext.Provider value={value}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { useState, useEffect } from 'react';
import { GameProvider, useGame } from './context/GameContext';
import { SettingsProvider, useSettings } from './context/SettingsContext';
import { ToastProvider, useToast } from './context/ToastContext';
import { Dashboard } from './components/Dashboard';
import { PillarsView } from './components/PillarsView';
import { WeeklyPlanner } from './components/WeeklyPlanner';
import { AICoach } from './components/AICoach';
import { SettingsScreen } from './components/SettingsScreen';
import { SignUpScreen } from './components/SignUpScreen';
import { StatisticsScreen } from './components/StatisticsScreen';
import { ToastSystem } from './components/ToastSystem';
import { AppTab, PillarType, StackScreen, Task, DayOfWeek } from './types';
import { Settings as SettingsIcon, ArrowRight } from 'lucide-react';
import { LearningScreen, StudyingScreen, ExerciseScreen, WorkScreen, EntertainmentScreen, QuranScreen } from './components/PillarScreens';
import { TaskFormModal } from './components/TaskFormModal';
import { LevelUpModal } from './components/LevelUpModal';
import { SmartNotificationManager } from './components/SmartNotificationManager';
import { App as CapacitorApp } from '@capacitor/app';
import { MotivationService } from './services/motivationService';
import { AudioService } from './services/audioService';

// Helper to get current day name in English to match DayOfWeek type
const getCurrentDayOfWeek = (): DayOfWeek => {
  const days: DayOfWeek[] = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  return days[new Date().getDay()];
};

const AppContent: React.FC = () => {
  const { playerProfile, addTask, editTask } = useGame();
  const { t, soundEnabled } = useSettings();
  const { addToast } = useToast();

  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [currentStackScreen, setCurrentStackScreen] = useState<StackScreen>('ROOT');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [modalDefaultPillar, setModalDefaultPillar] = useState<PillarType>('Learning');

  // Initialize with current actual day
  const [modalDefaultDay, setModalDefaultDay] = useState<DayOfWeek>(getCurrentDayOfWeek());

  // Navigation Wrappers with Sound
  const handleTabChange = (tab: AppTab) => {
    if (tab !== activeTab) {
        if(soundEnabled) AudioService.playTabSwitch();
        setActiveTab(tab);
    }
  };

  const navigateToPillar = (pillar: PillarType) => {
    if(soundEnabled) AudioService.playTabSwitch();
    setActiveTab(AppTab.PILLARS); 
    setCurrentStackScreen(pillar);
  };

  const handleBack = () => {
    if(soundEnabled) AudioService.playTabSwitch();
    setCurrentStackScreen('ROOT');
    setActiveTab(AppTab.DASHBOARD);
  };

  const goHome = () => {
    if(soundEnabled) AudioService.playTabSwitch();
    setActiveTab(AppTab.DASHBOARD);
    setCurrentStackScreen('ROOT');
  };

  // Hardware Back Button Handler
  useEffect(() => {
    let listener: any;

    const setupListener = async () => {
        listener = await CapacitorApp.addListener('backButton', ({ canGoBack }) => {
            if (isModalOpen) {
                setIsModalOpen(false);
            } else if (currentStackScreen !== 'ROOT') {
                handleBack();
            } else if (activeTab !== AppTab.DASHBOARD) {
                goHome();
            } else {
                CapacitorApp.exitApp();
            }
        });
    };

    setupListener();

    return () => {
        if (listener) {
            listener.remove();
        }
    };
  }, [currentStackScreen, activeTab, isModalOpen]);

  // Daily Motivation Check
  useEffect(() => {
    if (playerProfile) {
        const dailyQuote = MotivationService.checkDailyQuote();
        if (dailyQuote) {
            setTimeout(() => {
                addToast(`💡 ${dailyQuote.text}`, 'info');
            }, 1500);
        }
    }
  }, [playerProfile, addToast]);

  // Handlers for Modal
  const openAddTask = (pillar?: PillarType, day?: DayOfWeek) => {
    setEditingTask(null);
    setModalDefaultPillar(pillar || (currentStackScreen !== 'ROOT' ? (currentStackScreen as PillarType) : 'Learning'));
    // Automatically set the day to TODAY if no specific day is passed
    setModalDefaultDay(day || getCurrentDayOfWeek());
    setIsModalOpen(true);
  };

  const openEditTask = (task: Task) => {
    setEditingTask(task);
    setIsModalOpen(true);
  };

  const handleSaveTask = (taskData: Partial<Task>) => {
    if (editingTask) {
        editTask(editingTask.id, taskData);
    } else {
        addTask(taskData);
    }
    setIsModalOpen(false);
  };

  // If no profile exists, show Sign Up
  if (!playerProfile) {
    return (
        <>
            <SignUpScreen />
            <ToastSystem />
        </>
    );
  }

  const renderContent = () => {
    // If we are in a specific pillar screen (Stack Navigation)
    if (currentStackScreen !== 'ROOT') {
        const props = { 
            onBack: handleBack, 
            onAddTask: () => openAddTask(currentStackScreen as PillarType),
            onEditTask: openEditTask
        };
        switch (currentStackScreen) {
            case 'Learning': return <LearningScreen {...props} />;
            case 'Studying': return <StudyingScreen {...props} />;
            case 'Exercise': return <ExerciseScreen {...props} />;
            case 'Work': return <WorkScreen {...props} />;
            case 'Entertainment': return <EntertainmentScreen {...props} />;
            case 'Quran': return <QuranScreen {...props} />;
        }
    }

    // Default Tab Navigation
    switch (activeTab) {
      case AppTab.DASHBOARD: 
        return <Dashboard 
                  onNavigateToPillar={navigateToPillar} 
                  onOpenSettings={() => handleTabChange(AppTab.SETTINGS)} 
                  onNavigateToTab={handleTabChange}
                  onQuickAdd={() => openAddTask()}
               />;
      case AppTab.PLANNER:
        return <WeeklyPlanner onAddTask={(day) => openAddTask(undefined, day)} onEditTask={openEditTask} />;
      case AppTab.PILLARS: 
        return <PillarsView onNavigate={navigateToPillar} />;
      case AppTab.COACH: 
        return <AICoach />;
      case AppTab.STATS:
        return <StatisticsScreen />;
      case AppTab.SETTINGS:
        return <SettingsScreen />;
      default: 
        return <Dashboard 
                  onNavigateToPillar={navigateToPillar} 
                  onOpenSettings={() => handleTabChange(AppTab.SETTINGS)} 
                  onNavigateToTab={handleTabChange}
                  onQuickAdd={() => openAddTask()}
               />;
    }
  };

  return (
    <div className="min-h-[100dvh] bg-game-black text-white flex justify-center font-sans overflow-hidden">
      <div className="w-full max-w-md h-[100dvh] flex flex-col relative bg-game-black shadow-2xl overflow-hidden">

        {/* Header (Only show if not in stack screen) */}
        {currentStackScreen === 'ROOT' && (
            <header className="p-4 flex justify-between items-center border-b border-neutral-800 bg-game-black/80 backdrop-blur-md sticky top-0 z-20">
                <div className="flex items-center gap-3">
                    {activeTab !== AppTab.DASHBOARD && (
                        <button onClick={goHome} className="text-neutral-400 hover:text-white">
                            <ArrowRight size={24} />
                        </button>
                    )}
                    {/* Stylized Logo for 'Solo Task' */}
                    <div className="flex flex-col">
                        <h1 className="text-2xl font-black tracking-tighter leading-none italic select-none">
                            <span className="text-white drop-shadow-md">SOLO</span>
                            <span className="text-game-red drop-shadow-md ml-1">TASK</span>
                        </h1>
                        <span className="text-[7px] font-mono text-neutral-500 tracking-[0.4em] uppercase opacity-80">
                            SYSTEM ACTIVE
                        </span>
                    </div>
                </div>
                <button 
                    onClick={() => handleTabChange(AppTab.SETTINGS)} 
                    className={`text-neutral-500 hover:text-game-red transition-colors ${activeTab === AppTab.SETTINGS ? 'text-game-red' : ''}`}
                >
                    <SettingsIcon size={20} />
                </button>
            </header>
        )}

        {/* Main Content - No scroll here, children handle it */}
        <main className="flex-1 overflow-hidden relative">
            {renderContent()}
        </main>

        {/* Global Task Modal */}
        <TaskFormModal 
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            onSubmit={handleSaveTask}
            initialData={editingTask}
            defaultPillar={modalDefaultPillar}
            defaultDay={modalDefaultDay}
        />

        {/* Managers & Overlays */}
        <SmartNotificationManager />
        <ToastSystem />
        <LevelUpModal />

      </div>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <SettingsProvider>
        <ToastProvider>
            <GameProvider>
                <AppContent />
            </GameProvider>
        </ToastProvider>
    </SettingsProvider>
  );
};

export default App;

