  const { playerProfile, updateProfile, resetProgress } = useGame();
  const { addToast } = useToast();

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [tempProfile, setTempProfile] = useState({
      name: playerProfile?.name || '',
      age: playerProfile?.age || 0,
      height: playerProfile?.height || 0,
      weight: playerProfile?.weight || 0
  });

  const themes: { id: ThemeColor; color: string; label: string }[] = [
    { id: 'red-black', color: '#ef4444', label: 'Red & Black' },
    { id: 'blue-dark', color: '#3b82f6', label: 'Blue & Dark' },
    { id: 'green-matrix', color: '#00f763', label: 'Matrix Green' },
    { id: 'purple-royal', color: '#d946ef', label: 'Royal Purple' },
    { id: 'pink-white', color: '#ff4d8d', label: 'Pink & White' },
  ];

  const handleNotificationClick = async () => {
    const targetState = !notificationsEnabled;
    if(soundEnabled) AudioService.playToggle(targetState);
    const success = await toggleNotifications();

    if (success) {
        if (targetState) {
            new Notification("Solo Level", { body: "System Online" });
            addToast("تم تفعيل الإشعارات", 'success');
        } else {
            addToast("تم إيقاف الإشعارات", 'info');
        }
    } else {
        addToast("تم رفض الإذن من المتصفح", 'error');
    }
  };

  const handleDurationChange = (duration: NotificationDuration) => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ notificationDuration: duration });
      setTimeout(() => addToast(`Updated duration to ${duration}`, 'info'), 100);
  };

  const handleHapticsToggle = () => {
      if(soundEnabled) AudioService.playToggle(!hapticsEnabled);
      updateSettings({ hapticsEnabled: !hapticsEnabled });
  };

  const saveProfileChanges = () => {
      if(soundEnabled) AudioService.playClick();
      updateProfile(tempProfile);
      setIsEditingProfile(false);
  };

  const toggleEditProfile = (edit: boolean) => {
      if(soundEnabled) AudioService.playClick();
      setIsEditingProfile(edit);
  };

  const changeTheme = (id: ThemeColor) => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ themeColor: id });
  };

  const changeLanguage = (lang: 'ar' | 'en') => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ language: lang });
  };

  return (
    <div className="h-full overflow-y-auto no-scrollbar pb-24 animate-fade-in bg-game-black">

      {/* Header */}
      <div className="sticky top-0 z-20 bg-game-black/90 backdrop-blur-md p-4 border-b border-neutral-800 flex items-center gap-3">
          <Monitor className="text-game-red" size={24} />
          <h2 className="text-2xl font-black text-white uppercase tracking-tighter">{t('settingsScreen')}</h2>
      </div>

      <div className="p-4 space-y-6">

        {/* 1. Profile Section */}
        <div className="bg-neutral-900 border border-neutral-800 rounded-2xl overflow-hidden relative">
            <div className="absolute top-0 right-0 p-4 opacity-10">
                <Shield size={100} />
            </div>

            <div className="p-4 border-b border-neutral-800 flex justify-between items-center relative z-10">
                <div className="flex items-center gap-2 text-game-red">
                    <User size={18} />
                    <h3 className="font-bold text-sm uppercase tracking-widest">{t('profileSettings')}</h3>
                </div>
                {!isEditingProfile ? (
                    <button onClick={() => toggleEditProfile(true)} className="p-2 bg-neutral-800 rounded-lg hover:text-white text-neutral-400 transition-colors">
                        <Edit2 size={16} />
                    </button>
                ) : (
                     <div className="flex gap-2">
                        <button onClick={() => toggleEditProfile(false)} className="p-2 bg-neutral-800 rounded-lg text-red-400 hover:bg-red-900/20">
                            <X size={16} />
                        </button>
                        <button onClick={saveProfileChanges} className="p-2 bg-green-900/50 rounded-lg text-green-400 hover:bg-green-900/80 border border-green-800">
                            <Save size={16} />
                        </button>
                    </div>
                )}
            </div>

            <div className="p-4 relative z-10">
                <div className="flex items-center gap-4 mb-6">
                    <div className="w-16 h-16 bg-gradient-to-br from-neutral-800 to-neutral-950 rounded-full border-2 border-game-red flex items-center justify-center shadow-[0_0_15px_rgba(220,38,38,0.3)]">
                        <User size={32} className="text-game-red" />
                    </div>
                    <div className="flex-1">
                        {isEditingProfile ? (
                            <input 
                                type="text" 
                                value={tempProfile.name}
                                onChange={(e) => setTempProfile({...tempProfile, name: e.target.value})}
                                className="bg-black border border-neutral-700 rounded px-2 py-1 text-white font-bold w-full focus:border-game-red outline-none"
                            />
                        ) : (
                            <h2 className="text-xl font-black text-white">{playerProfile?.name}</h2>
                        )}
                        <p className="text-xs text-game-red font-mono uppercase tracking-widest">{t('jobTitle')}</p>
                    </div>
                </div>

                <div className="grid grid-cols-3 gap-2">
                    <div className="bg-black/40 p-2 rounded border border-neutral-800 text-center">
                        <span className="text-[10px] text-neutral-500 uppercase block mb-1">{t('age')}</span>
                        {isEditingProfile ? (
                            <input 
                                type="number" 
                                value={tempProfile.age}
                                onChange={(e) => setTempProfile({...tempProfile, age: Number(e.target.value)})}
                                className="bg-neutral-900 w-full text-center text-sm font-bold text-white outline-none rounded"
                            />
                        ) : (
                            <span className="text-lg font-bold text-white">{playerProfile?.age}</span>
                        )}
                    </div>
                    <div className="bg-black/40 p-2 rounded border border-neutral-800 text-center">
                        <span className="text-[10px] text-neutral-500 uppercase block mb-1">{t('height')}</span>
                        {isEditingProfile ? (
                             <input 
                                type="number" 
                                value={tempProfile.height}
                                onChange={(e) => setTempProfile({...tempProfile, height: Number(e.target.value)})}
                                className="bg-neutral-900 w-full text-center text-sm font-bold text-white outline-none rounded"
                            />
                        ) : (
                             <span className="text-lg font-bold text-white">{playerProfile?.height} <span className="text-[10px]">cm</span></span>
                        )}
                    </div>
                    <div className="bg-black/40 p-2 rounded border border-neutral-800 text-center">
                        <span className="text-[10px] text-neutral-500 uppercase block mb-1">{t('weight')}</span>
                        {isEditingProfile ? (
                             <input 
                                type="number" 
                                value={tempProfile.weight}
                                onChange={(e) => setTempProfile({...tempProfile, weight: Number(e.target.value)})}
                                className="bg-neutral-900 w-full text-center text-sm font-bold text-white outline-none rounded"
                            />
                        ) : (
                            <span className="text-lg font-bold text-white">{playerProfile?.weight} <span className="text-[10px]">kg</span></span>
                        )}
                    </div>
                </div>
            </div>
        </div>

        {/* 2. System Settings */}
        <div className="bg-neutral-900 border border-neutral-800 rounded-2xl overflow-hidden">
             <div className="p-4 border-b border-neutral-800 flex items-center gap-2 text-blue-500">
                <Activity size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">{t('systemSettings')}</h3>
            </div>

            <div className="divide-y divide-neutral-800">
                {/* Notifications */}
                <button 
                    onClick={handleNotificationClick}
                    className="w-full p-4 flex items-center justify-between hover:bg-neutral-800/50 transition-colors"
                >
                    <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-lg ${notificationsEnabled ? 'bg-green-900/20 text-green-500' : 'bg-neutral-800 text-neutral-500'}`}>
                            <Bell size={18} />
                        </div>
                        <div className="text-left">
                            <p className="font-bold text-sm text-white">{t('notifications')}</p>
                            <p className="text-[10px] text-neutral-500">{t('notificationsDesc')}</p>
                        </div>
                    </div>
                    <div className={`w-10 h-5 rounded-full p-0.5 transition-colors ${notificationsEnabled ? 'bg-green-600' : 'bg-neutral-700'}`}>
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${notificationsEnabled ? (language === 'ar' ? '-translate-x-5' : 'translate-x-5') : ''}`} />
                    </div>
                </button>

                {/* Notification Duration */}
                <div className="p-4 flex flex-col gap-3 bg-black/20">
                     <div className="flex items-center gap-3 mb-1">
                        <div className="p-2 rounded-lg bg-neutral-800 text-neutral-400">
                            <Clock size={18} />
                        </div>
                        <p className="font-bold text-sm text-white">Alert Duration</p>
                    </div>
                    <div className="grid grid-cols-4 gap-2">
                        {(['short', 'medium', 'long', 'persistent'] as NotificationDuration[]).map(d => (
                            <button
                                key={d}
                                onClick={() => handleDurationChange(d)}
                                className={`
                                    py-2 rounded-lg text-[10px] font-bold uppercase transition-all border
                                    ${notificationDuration === d 
                                        ? 'bg-neutral-800 text-white border-white' 
                                        : 'bg-black text-neutral-500 border-neutral-800 hover:border-neutral-600'}
                                `}
                            >
                                {d}
                            </button>
                        ))}
                    </div>
                </div>

                 {/* Volume Control Slider */}
                 <div className="w-full p-4 flex flex-col gap-3">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-neutral-800 text-neutral-400">
                                {soundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                            </div>
                            <p className="font-bold text-sm text-white">{t('soundEffects')}</p>
                        </div>
                        <span className="text-xs font-mono text-neutral-500">{(soundVolume * 100).toFixed(0)}%</span>
                    </div>

                    <div className="flex items-center gap-4">
                        <button 
                            onClick={() => {
                                if(soundEnabled) AudioService.playToggle(!soundEnabled);
                                updateSettings({ soundEnabled: !soundEnabled });
                            }}
                            className={`w-10 h-5 rounded-full p-0.5 transition-colors ${soundEnabled ? 'bg-blue-600' : 'bg-neutral-700'}`}
                        >
                            <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${soundEnabled ? (language === 'ar' ? '-translate-x-5' : 'translate-x-5') : ''}`} />
                        </button>
                        <input 
                            type="range" 
                            min="0" 
                            max="1" 
                            step="0.05"
                            value={soundVolume}
                            onChange={(e) => updateSettings({ soundVolume: parseFloat(e.target.value), soundEnabled: true })}
                            className="flex-1 h-2 bg-neutral-700 rounded-lg appearance-none cursor-pointer accent-game-red"
                        />
                    </div>
                </div>

                {/* Haptics */}
                 <button 
                    onClick={handleHapticsToggle}
                    className="w-full p-4 flex items-center justify-between hover:bg-neutral-800/50 transition-colors"
                >
                    <div className="flex items-center gap-3">
                        <div className="p-2 rounded-lg bg-neutral-800 text-neutral-400">
                            <Smartphone size={18} />
                        </div>
                        <p className="font-bold text-sm text-white">{t('hapticFeedback')}</p>
                    </div>
                    <div className={`w-10 h-5 rounded-full p-0.5 transition-colors ${hapticsEnabled ? 'bg-blue-600' : 'bg-neutral-700'}`}>
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${hapticsEnabled ? (language === 'ar' ? '-translate-x-5' : 'translate-x-5') : ''}`} />
                    </div>
                </button>

                {/* Language */}
                <div className="p-4 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="p-2 rounded-lg bg-neutral-800 text-neutral-400">
                            <Globe size={18} />
                        </div>
                        <p className="font-bold text-sm text-white">{t('language')}</p>
                    </div>
                    <div className="flex bg-black rounded-lg p-1 border border-neutral-800">
                        <button 
                            onClick={() => changeLanguage('ar')}
                            className={`px-3 py-1 rounded text-xs font-bold transition-colors ${language === 'ar' ? 'bg-blue-600 text-white' : 'text-neutral-500 hover:text-white'}`}
                        >
                            AR
                        </button>
                        <button 
                             onClick={() => changeLanguage('en')}
                             className={`px-3 py-1 rounded text-xs font-bold transition-colors ${language === 'en' ? 'bg-blue-600 text-white' : 'text-neutral-500 hover:text-white'}`}
                        >
                            EN
                        </button>
                    </div>
                </div>
            </div>
        </div>

        {/* 3. Visuals */}
        <div className="bg-neutral-900 border border-neutral-800 rounded-2xl overflow-hidden p-4">
             <div className="flex items-center gap-2 mb-4 text-purple-500">
                <Palette size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">{t('theme')}</h3>
            </div>

            <div className="grid grid-cols-2 gap-3">
                {themes.map(theme => (
                    <button
                        key={theme.id}
                        onClick={() => changeTheme(theme.id)}
                        className={`
                            relative h-16 rounded-xl overflow-hidden transition-all border-2
                            ${themeColor === theme.id ? 'border-white scale-105 shadow-lg' : 'border-transparent opacity-60 hover:opacity-100'}
                        `}
                        style={{ backgroundColor: theme.color }}
                    >
                        <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent flex items-end p-2">
                             <span className="text-white font-bold text-xs">{theme.label}</span>
                             {themeColor === theme.id && <Check size={14} className="ml-auto text-white" />}
                        </div>
                    </button>
                ))}
            </div>
        </div>

        {/* 4. Danger Zone */}
         <div className="bg-red-950/20 border border-red-900/50 rounded-2xl overflow-hidden p-4">
             <div className="flex items-center gap-2 mb-4 text-red-500">
                <AlertTriangle size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">{t('dangerZone')}</h3>
            </div>
             <button 
                onClick={resetProgress}
                className="w-full flex items-center justify-center gap-2 bg-red-900/20 text-red-500 p-3 rounded-xl border border-red-900/50 hover:bg-red-900/40 transition-colors"
            >
                <RotateCcw size={16} />
                <span className="font-bold text-sm">{t('resetProgress')}</span>
            </button>
         </div>

         <div className="text-center">
            <p className="text-[10px] text-neutral-600 font-mono">SYSTEM VERSION 1.1.0 (UPDATED)</p>
         </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Dumbbell, Zap, Trophy, Target, Calendar, Scroll, CheckCircle2, LayoutGrid, Clock, BarChart3, Lock } from 'lucide-react';
import { PillarType, Task, DayOfWeek, TaskDifficulty } from '../types';
import { PILLARS, HOME_EXERCISES, DAYS_OF_WEEK, PILLAR_BASE_RATES, DIFFICULTY_CONFIG, ENERGY_PER_QURAN_PAGE } from '../constants';
import { useGame } from '../context/GameContext';
import { useSettings } from '../context/SettingsContext';
import { AudioService } from '../services/audioService';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (taskData: Partial<Task>) => void;
  initialData?: Task | null;
  defaultPillar?: PillarType;
  defaultDay?: DayOfWeek;
}

export const TaskFormModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, initialData, defaultPillar, defaultDay }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [pillar, setPillar] = useState<PillarType>('Learning');
  const [day, setDay] = useState<DayOfWeek>('Saturday');
  const [difficulty, setDifficulty] = useState<TaskDifficulty>('D'); // Default D-Rank
  const [dueDate, setDueDate] = useState('');
  const [pages, setPages] = useState<number>(1); // For Quran

  const { t, soundEnabled } = useSettings();

  // Calculate Today's Index (0 = Saturday, ... 6 = Friday)
  const todayIndex = (new Date().getDay() + 1) % 7;

  // Dynamic Calculation
  const baseRates = PILLAR_BASE_RATES[pillar];
  const multiplier = DIFFICULTY_CONFIG[difficulty].multiplier;

  // Calculate final costs
  const calculatedEnergy = pillar === 'Quran' 
    ? -(pages * ENERGY_PER_QURAN_PAGE) 
    : Math.ceil(baseRates.energy * multiplier);

  const calculatedXp = Math.ceil(baseRates.xp * multiplier);

  // Get current real day for visual comparison
  const days: DayOfWeek[] = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  const todayName = days[new Date().getDay()];

  useEffect(() => {
    if (isOpen) {
      if(soundEnabled) AudioService.playPop();

      if (initialData) {
        setTitle(initialData.title);
        setDescription(initialData.description);
        setPillar(initialData.pillar);
        setDay(initialData.day || 'Saturday');
        setDifficulty(initialData.difficulty || 'D');
        setDueDate(initialData.dueDate || '');
        setPages(initialData.pages || 1);
      } else {
        setTitle('');
        setDescription('');
        setPillar(defaultPillar || 'Learning');
        // If defaultDay is provided and it's in the past relative to today, default to Today instead
        const defaultDayIndex = DAYS_OF_WEEK.findIndex(d => d.id === defaultDay);
        const effectiveDay = (defaultDay && defaultDayIndex >= todayIndex) ? defaultDay : todayName;

        setDay(effectiveDay);
        setDifficulty('D');
        setDueDate('');
        setPages(1);
      }
    }
  }, [isOpen, initialData, defaultPillar, defaultDay, todayName, todayIndex, soundEnabled]);

  const handleExerciseSelect = (ex: typeof HOME_EXERCISES[0]) => {
    if(soundEnabled) AudioService.playClick();
    setTitle(ex.name);
    setPillar('Exercise');
    setDescription(`Goal: ${ex.reps || ex.duration}`);
    setDifficulty(ex.difficulty);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if(soundEnabled) AudioService.playClick();

    // For Quran, title can be auto-generated if empty
    let finalTitle = title;
    if (pillar === 'Quran' && !finalTitle.trim()) {
        finalTitle = `${t('quran')} - ${pages} ${t('pagesToRead')}`;
    }

    if (!finalTitle.trim()) return;

    if (day === 'Friday' && pillar !== 'Quran') {
        alert(t('fridayRestWarning'));
        return;
    }

    onSubmit({
      title: finalTitle,
      description,
      pillar,
      day,
      difficulty,
      dueDate,
      pages: pillar === 'Quran' ? Number(pages) : undefined
    });
    onClose();
  };

  const handlePillarChange = (p: PillarType) => {
      if(soundEnabled) AudioService.playClick();
      setPillar(p);
  }

  const handleDayChange = (d: DayOfWeek) => {
      if(soundEnabled) AudioService.playClick();
      setDay(d);
  }

  const handleDifficultyChange = (d: TaskDifficulty) => {
      if(soundEnabled) AudioService.playClick();
      setDifficulty(d);
  }

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in">
      <div className="bg-neutral-900 border border-neutral-700 w-full max-w-md rounded-3xl p-0 relative shadow-2xl max-h-[90vh] overflow-hidden flex flex-col">

        {/* Header */}
        <div className="p-4 border-b border-neutral-800 bg-neutral-900 flex justify-between items-center sticky top-0 z-10">
             <h3 className="text-lg font-black text-white uppercase tracking-wider flex items-center gap-2">
                {initialData ? <><CheckCircle2 size={20} className="text-blue-500"/> {t('editTask')}</> : <><LayoutGrid size={20} className="text-game-red"/> {t('newTask')}</>}
            </h3>
            <button onClick={onClose} className="p-2 bg-neutral-800 rounded-full text-neutral-400 hover:text-white hover:bg-neutral-700 transition-colors">
                <X size={20} />
            </button>
        </div>

        <div className="overflow-y-auto p-6 space-y-6 no-scrollbar">
            <form onSubmit={handleSubmit} className="space-y-6">

                {/* Pillar Selector (Grid) */}
                <div>
                    <label className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest mb-3 block">{t('selectPillar')}</label>
                    <div className="grid grid-cols-3 gap-2">
                        {PILLARS.map(p => (
                            <button
                                key={p.id}
                                type="button"
                                onClick={() => handlePillarChange(p.id)}
                                className={`
                                    flex flex-col items-center justify-center gap-1 p-2 rounded-xl border-2 transition-all
                                    ${pillar === p.id 
                                        ? `bg-${p.color.split('-')[1]}-900/20 border-${p.color.split('-')[1]}-500 text-white shadow-lg shadow-${p.color.split('-')[1]}-500/10` 
                                        : 'bg-neutral-950 border-neutral-800 text-neutral-500 hover:border-neutral-700 hover:bg-neutral-900'}
                                `}
                            >
                                <p.icon size={20} className={pillar === p.id ? p.color : 'text-neutral-600'} />
                                <span className="text-[10px] font-bold">{t(p.id.toLowerCase() as any)}</span>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Day Selector */}
                <div>
                    <div className="flex items-center justify-between mb-3">
                        <label className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest flex items-center gap-2">
                            <Calendar size={12} /> {t('timing')}
                        </label>
                        <div className="flex items-center gap-1 text-[10px] text-game-red font-bold animate-pulse">
                            <Clock size={10} />
                            <span>{t('today')}: {todayName}</span>
                        </div>
                    </div>
                    <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                        {DAYS_OF_WEEK.map((d, index) => {
                            const isToday = d.id === todayName;
                            const isPast = index < todayIndex;
                            // Only disable if it's past AND we are not editing a task that was already on this day (though usually we want to force reschedule)
                            // Strict Rule: Cannot schedule on past days.
                            const isDisabled = isPast || (d.id === 'Friday' && pillar !== 'Quran');

                            return (
                                <button
                                    key={d.id}
                                    type="button"
                                    onClick={() => !isDisabled && handleDayChange(d.id)}
                                    className={`
                                        relative flex items-center justify-center px-3 py-2 rounded-lg text-[10px] font-bold border transition-all whitespace-nowrap
                                        ${isDisabled ? 'opacity-40 border-dashed border-neutral-800 cursor-not-allowed bg-black/50 text-neutral-600' : ''}
                                        ${day === d.id 
                                            ? 'bg-white text-black border-white shadow-lg scale-105' 
                                            : !isDisabled && isToday ? 'bg-neutral-800 border-game-red text-white' : 'bg-black text-neutral-500 border-neutral-800 hover:border-neutral-600'}
                                    `}
                                    disabled={isDisabled}
                                >
                                    {isPast && <Lock size={8} className="absolute -top-1 -left-1 text-neutral-500" />}
                                    {d.label}
                                    {isToday && day !== d.id && !isDisabled && (
                                        <span className="absolute -top-1 -right-1 w-2 h-2 bg-game-red rounded-full" />
                                    )}
                                </button>
                            );
                        })}
                    </div>
                </div>

                {/* Inputs Area */}
                <div className="bg-neutral-950/50 p-4 rounded-2xl border border-neutral-800/50 space-y-4">
                    {pillar === 'Quran' ? (
                        <div className="bg-emerald-900/10 border border-emerald-900/50 p-4 rounded-xl text-center">
                            <label className="block text-xs text-emerald-400 mb-3 font-bold flex items-center justify-center gap-2">
                                <Scroll size={16} /> {t('pagesToRead')}
                            </label>
                            <div className="flex items-center justify-center gap-4">
                                <button type="button" onClick={() => setPages(p => Math.max(1, p - 1))} className="w-10 h-10 rounded-full bg-neutral-800 hover:bg-neutral-700 text-white font-bold text-xl transition-colors">-</button>
                                <span className="text-3xl font-black text-white w-16 text-center">{pages}</span>
                                <button type="button" onClick={() => setPages(p => p + 1)} className="w-10 h-10 rounded-full bg-neutral-800 hover:bg-neutral-700 text-white font-bold text-xl transition-colors">+</button>
                            </div>
                            <p className="text-[10px] text-neutral-500 mt-3">{t('pageEnergy')}</p>
                        </div>
                    ) : (
                        <>
                            <div>
                                <label className="block text-[10px] text-neutral-500 font-bold mb-1 uppercase">{t('taskTitle')}</label>
                                <input 
                                    type="text" 
                                    value={title}
                                    onChange={(e) => setTitle(e.target.value)}
                                    className="w-full bg-black border border-neutral-800 rounded-xl p-4 text-white placeholder:text-neutral-700 focus:border-game-red focus:ring-1 focus:ring-game-red outline-none transition-all font-bold"
                                    placeholder={pillar === 'Exercise' ? "..." : t('taskPlaceholder')}
                                />
                            </div>

                            {/* Difficulty Selector */}
                            <div>
                                <label className="text-[10px] text-neutral-500 font-bold mb-2 uppercase flex items-center gap-2">
                                    <BarChart3 size={12} /> {t('difficultyLevel')}
                                </label>
                                <div className="grid grid-cols-6 gap-1">
                                    {(Object.keys(DIFFICULTY_CONFIG) as TaskDifficulty[]).map(key => (
                                        <button
                                            key={key}
                                            type="button"
                                            onClick={() => handleDifficultyChange(key)}
                                            className={`
                                                flex flex-col items-center justify-center py-2 rounded-lg border transition-all
                                                ${difficulty === key 
                                                    ? `bg-neutral-800 border-white text-white` 
                                                    : 'bg-black border-neutral-800 text-neutral-600 hover:border-neutral-600'}
                                            `}
                                        >
                                            <span className={`text-xs font-black ${DIFFICULTY_CONFIG[key].color}`}>{key}</span>
                                        </button>
                                    ))}
                                </div>
                                <div className="text-center mt-2 text-[10px] text-neutral-500 font-mono uppercase">
                                    {DIFFICULTY_CONFIG[difficulty].label} • x{DIFFICULTY_CONFIG[difficulty].multiplier} Rewards
                                </div>
                            </div>

                            {/* Exercise Quick Presets */}
                            {pillar === 'Exercise' && (
                                <div>
                                    <label className="block text-[10px] text-green-500 font-bold mb-2 uppercase tracking-wide">{t('suggestedExercises')}</label>
                                    <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                                        {HOME_EXERCISES.slice(0, 5).map(ex => (
                                            <button
                                                key={ex.id}
                                                type="button"
                                                onClick={() => handleExerciseSelect(ex)}
                                                className="bg-neutral-900 border border-neutral-800 hover:border-green-500/50 hover:bg-green-900/10 rounded-lg px-3 py-2 whitespace-nowrap transition-colors"
                                            >
                                                <span className="text-xs text-white font-bold">{ex.name.split('/')[1] || ex.name}</span>
                                                <span className="block text-[9px] text-neutral-500">{ex.reps || ex.duration} • Rank {ex.difficulty}</span>
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}

                            <div>
                                <label className="block text-[10px] text-neutral-500 font-bold mb-1 uppercase">{t('additionalNotes')}</label>
                                <textarea 
                                    value={description}
                                    onChange={(e) => setDescription(e.target.value)}
                                    className="w-full bg-black border border-neutral-800 rounded-xl p-3 text-white placeholder:text-neutral-700 focus:border-game-red outline-none h-20 text-sm resize-none"
                                    placeholder={t('detailsPlaceholder')}
                                />
                            </div>
                        </>
                    )}
                </div>

                {/* Stats Preview */}
                <div className="flex gap-3">
                    <div className="flex-1 bg-black p-3 rounded-xl border border-neutral-800 flex items-center gap-3">
                        <div className="bg-yellow-900/20 p-2 rounded-lg text-yellow-500"><Zap size={18} /></div>
                        <div>
                            <p className="text-[10px] text-neutral-500 font-bold uppercase">{t('energy')}</p>
                            <p className={`text-lg font-black ${calculatedEnergy < 0 ? 'text-green-500' : 'text-white'}`}>
                                {calculatedEnergy > 0 ? `-${calculatedEnergy}` : `+${Math.abs(calculatedEnergy)}`}
                            </p>
                        </div>
                    </div>
                    {pillar !== 'Quran' && (
                        <div className="flex-1 bg-black p-3 rounded-xl border border-neutral-800 flex items-center gap-3">
                            <div className="bg-red-900/20 p-2 rounded-lg text-game-red"><Trophy size={18} /></div>
                            <div>
                                <p className="text-[10px] text-neutral-500 font-bold uppercase">{t('energyReward')}</p>
                                <p className="text-lg font-black text-white">{calculatedXp} XP</p>
                            </div>
                        </div>
                    )}
                </div>

                {/* Submit Button */}
                <button 
                    type="submit" 
                    disabled={day === 'Friday' && pillar !== 'Quran'}
                    className={`
                        w-full font-black py-4 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2
                        ${day === 'Friday' && pillar !== 'Quran' 
                            ? 'bg-neutral-800 text-neutral-500 cursor-not-allowed' 
                            : 'bg-white text-black hover:bg-neutral-200 hover:scale-[1.02] active:scale-[0.98]'}
                    `}
                >
                    {initialData ? t('saveChanges') : t('addToSchedule')}
                </button>

            </form>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { useSettings } from '../context/SettingsContext';
import { PILLARS } from '../constants';
import { Activity, Flame, Trophy, Zap, Settings, CalendarDays, Bot, Target, CheckCircle2, ArrowRight, PieChart, Plus } from 'lucide-react';
import { DashboardWidget } from './DashboardWidget';
import { PillWidget } from './PillWidget';
import { PillarType, AppTab } from '../types';
import { AudioService } from '../services/audioService';

interface Props {
  onNavigateToPillar: (pillar: PillarType) => void;
  onOpenSettings: () => void;
  onNavigateToTab: (tab: AppTab) => void;
  onQuickAdd: () => void;
}

export const Dashboard: React.FC<Props> = ({ onNavigateToPillar, onOpenSettings, onNavigateToTab, onQuickAdd }) => {
  const { stats, tasks, playerProfile, setWeeklyChallenge, completeWeeklyChallenge } = useGame();
  const { t, soundEnabled } = useSettings();

  const [challengeInput, setChallengeInput] = useState('');
  const completedTasksCount = tasks.filter(t => t.completed).length;
  const showChallengeSelector = !stats.weeklyChallenge;

  const handleSetChallenge = (e: React.FormEvent) => {
    e.preventDefault();
    if(challengeInput.trim()) {
        if(soundEnabled) AudioService.playClick();
        setWeeklyChallenge(challengeInput);
        setChallengeInput('');
    }
  };

  const handleQuickAdd = () => {
      if(soundEnabled) AudioService.playClick();
      onQuickAdd();
  }

  const handleNavigatePillar = (id: PillarType) => {
      if(soundEnabled) AudioService.playTabSwitch(); // Pillars navigation is a major switch
      onNavigateToPillar(id);
  }

  return (
    <div className="h-full overflow-y-auto no-scrollbar space-y-5 pb-24 animate-fade-in bg-game-black">

      {/* Welcome & Header */}
      <div className="px-5 pt-4 flex justify-between items-start">
        <div>
            <p className="text-neutral-500 text-xs font-mono uppercase tracking-widest mb-1">{t('welcomeHunter')}</p>
            <h2 className="text-3xl font-black text-white tracking-tighter">{playerProfile?.name || 'Player'}</h2>
        </div>
        <button onClick={onOpenSettings} className="p-2 bg-neutral-900 rounded-full text-neutral-500 hover:text-white border border-neutral-800">
            <Settings size={20} />
        </button>
      </div>

      {/* 1️⃣ Weekly Challenge Section */}
      <div className="px-4">
        {showChallengeSelector && (
            <div className="bg-gradient-to-r from-neutral-900 to-black border border-neutral-800 p-4 rounded-2xl shadow-lg relative overflow-hidden">
                <div className="absolute top-0 right-0 w-20 h-20 bg-yellow-600/10 rounded-full blur-2xl"></div>
                <div className="flex items-center gap-2 mb-3 text-yellow-500 relative z-10">
                    <Target size={20} />
                    <h3 className="font-bold text-sm uppercase tracking-wider">{t('weeklyChallenge')}</h3>
                </div>
                <p className="text-xs text-neutral-400 mb-4 relative z-10">{t('challengeDesc')} <span className="text-yellow-500 font-bold">+500 XP</span>.</p>

                <form onSubmit={handleSetChallenge} className="flex gap-2 relative z-10">
                    <input 
                        type="text"
                        value={challengeInput}
                        onChange={(e) => setChallengeInput(e.target.value)}
                        placeholder={t('challengePlaceholder')}
                        className="flex-1 bg-black/50 border border-neutral-700 rounded-xl px-4 py-3 text-sm text-white focus:border-game-red outline-none placeholder:text-neutral-600"
                        maxLength={40}
                    />
                    <button 
                        type="submit"
                        disabled={!challengeInput.trim()}
                        className="bg-game-red text-white px-4 rounded-xl font-bold disabled:opacity-50 hover:bg-red-700 transition-colors"
                    >
                        <ArrowRight size={18} />
                    </button>
                </form>
            </div>
        )}

        {/* Active/Completed Challenge */}
        {stats.weeklyChallenge && (
             <div className={`
                p-4 rounded-2xl flex items-center justify-between shadow-lg border relative overflow-hidden
                ${stats.weeklyChallenge.completed 
                    ? 'bg-green-950/30 border-green-900/50' 
                    : 'bg-neutral-900 border-yellow-900/30'}
             `}>
                <div className="relative z-10 flex-1">
                    <div className="flex items-center gap-2 mb-1">
                        <span className={`text-[10px] font-black uppercase tracking-widest ${stats.weeklyChallenge.completed ? 'text-green-500' : 'text-yellow-500'}`}>
                            {stats.weeklyChallenge.completed ? t('missionComplete') : t('activeMission')}
                        </span>
                    </div>
                    <p className={`font-bold text-sm ${stats.weeklyChallenge.completed ? 'text-neutral-400 line-through' : 'text-white'}`}>
                        {stats.weeklyChallenge.title}
                    </p>
                </div>

                {!stats.weeklyChallenge.completed ? (
                    <button 
                        onClick={() => {
                            if(soundEnabled) AudioService.playClick();
                            completeWeeklyChallenge();
                        }}
                        className="relative z-10 bg-neutral-800 hover:bg-yellow-600 hover:text-black text-neutral-400 p-3 rounded-xl transition-all border border-neutral-700 hover:border-yellow-500 hover:shadow-[0_0_15px_rgba(234,179,8,0.4)]"
                    >
                        <CheckCircle2 size={24} />
                    </button>
                ) : (
                    <div className="bg-green-500/20 p-2 rounded-full text-green-500">
                        <CheckCircle2 size={24} />
                    </div>
                )}
             </div>
        )}
      </div>

      {/* Stats Grid */}
      <div className="px-4 grid grid-cols-2 gap-3">
        {/* Level Widget (Tall) */}
        <div className="col-span-1 row-span-2">
             <DashboardWidget 
                label={t('level')}
                value={stats.level}
                subValue={t('currentRank')}
                icon={Trophy}
                iconColor="text-yellow-500"
                progress={{
                    current: stats.currentXp,
                    max: stats.maxXp,
                    colorClass: "bg-game-red"
                }}
                variant="circular"
                borderColor="border-game-red/30"
            />
        </div>

        {/* Energy Widget */}
        <DashboardWidget 
            label={t('energy')}
            value={stats.energy}
            subValue={`/ ${stats.maxEnergy}`}
            icon={Zap}
            iconColor="text-blue-400"
            progress={{
                current: stats.energy,
                max: stats.maxEnergy,
                colorClass: "bg-blue-500"
            }}
        />

        {/* Mini Widgets */}
        <div className="grid grid-cols-2 gap-3">
            <DashboardWidget 
                label={t('streak')}
                value={stats.streak}
                icon={Flame}
                iconColor="text-orange-500"
            />
             <DashboardWidget 
                label={t('done')}
                value={completedTasksCount}
                icon={Activity}
                iconColor="text-emerald-500"
            />
        </div>
      </div>

      {/* Quick Nav */}
      <div className="px-4">
          <div className="bg-neutral-900 border border-neutral-800 rounded-2xl p-1 flex">
             <button onClick={() => onNavigateToTab(AppTab.PLANNER)} className="flex-1 py-3 flex flex-col items-center gap-1 hover:bg-neutral-800 rounded-xl transition-colors">
                <CalendarDays size={20} className="text-neutral-400" />
                <span className="text-[10px] font-bold text-neutral-500">{t('planner')}</span>
             </button>
             <div className="w-px bg-neutral-800 my-2"></div>
             <button onClick={() => onNavigateToTab(AppTab.COACH)} className="flex-1 py-3 flex flex-col items-center gap-1 hover:bg-neutral-800 rounded-xl transition-colors">
                <Bot size={20} className="text-blue-400" />
                <span className="text-[10px] font-bold text-neutral-500">{t('coach')}</span>
             </button>
             <div className="w-px bg-neutral-800 my-2"></div>
             <button onClick={() => onNavigateToTab(AppTab.STATS)} className="flex-1 py-3 flex flex-col items-center gap-1 hover:bg-neutral-800 rounded-xl transition-colors">
                <PieChart size={20} className="text-purple-400" />
                <span className="text-[10px] font-bold text-neutral-500">{t('statistics')}</span>
             </button>
          </div>
      </div>

      {/* Pillars Preview List (Compact) */}
      <div className="px-4 pb-4 space-y-3">
         <div className="flex justify-between items-end border-b border-neutral-800 pb-2 mb-2">
            <h3 className="text-sm font-black text-neutral-300 uppercase tracking-widest">{t('lifePillars')}</h3>
            <button onClick={() => onNavigateToTab(AppTab.PILLARS)} className="text-xs text-game-red font-bold hover:underline">{t('viewAll')}</button>
         </div>

         <div className="grid grid-cols-1 gap-3">
            {/* Show only top 3 active or prioritized pillars to save space? Or all compacted. */}
            {PILLARS.slice(0, 3).map((pillar) => {
                const count = tasks.filter(t => t.pillar === pillar.id && !t.completed).length;
                return (
                    <PillWidget 
                        key={pillar.id}
                        pillarId={pillar.id} 
                        taskCount={count}
                        onClick={() => handleNavigatePillar(pillar.id)}
                        variant="card"
                    />
                );
            })}
         </div>
      </div>

      {/* Quick Add FAB */}
      <button 
        onClick={handleQuickAdd}
        className="fixed bottom-24 left-6 w-14 h-14 bg-white text-black rounded-full shadow-[0_0_30px_rgba(255,255,255,0.3)] flex items-center justify-center hover:scale-110 active:scale-90 transition-all z-40 border-4 border-neutral-200"
      >
        <Plus size={28} strokeWidth={3} />
      </button>

    </div>
  );
};

