  weeklyXpAccumulated: 0,
  weeklyTasksCompleted: 0,
  weeklyMaxStreak: 0,
  weeklyExerciseCount: 0,
  weeklyMissedTasks: 0,
  weeklyXpLost: 0,
  dailyQuest: {
    pushups: 0,
    situps: 0,
    squats: 0,
    run: 0,
    isCompleted: false,
    lastResetDate: new Date().toISOString().split('T')[0]
  },
  hunterAttributes: {
    strength: 10,
    intelligence: 10,
    vitality: 10,
    sense: 10,
