  }
};

export const defaultSettings: AppSettings = {
  language: 'ar',
  themeColor: 'red-black',
  darkMode: true,
  notificationsEnabled: false,
  notificationDuration: 'medium',
  allowDeleteCompleted: false,
  soundEnabled: true,
