import { PillarType, AppTab } from '../types';
import { AudioService } from '../services/audioService';

interface Props {
  onNavigateToPillar: (pillar: PillarType) => void;
  onOpenSettings: () => void;
  onNavigateToTab: (tab: AppTab) => void;
  onQuickAdd: () => void;
}

export const Dashboard: React.FC<Props> = ({ onNavigateToPillar, onOpenSettings, onNavigateToTab, onQuickAdd }) => {
  const { stats, tasks, playerProfile, setWeeklyChallenge, completeWeeklyChallenge } = useGame();
  const { t, soundEnabled } = useSettings();

  const [challengeInput, setChallengeInput] = useState('');
  const completedTasksCount = tasks.filter(t => t.completed).length;
  const showChallengeSelector = !stats.weeklyChallenge;

  const handleSetChallenge = (e: React.FormEvent) => {
    e.preventDefault();
    if(challengeInput.trim()) {
        if(soundEnabled) AudioService.playClick();
        setWeeklyChallenge(challengeInput);
        setChallengeInput('');
    }
  };

  const handleQuickAdd = () => {
      if(soundEnabled) AudioService.playClick();
      onQuickAdd();
  }

  const handleNavigatePillar = (id: PillarType) => {
      if(soundEnabled) AudioService.playTabSwitch(); // Pillars navigation is a major switch
      onNavigateToPillar(id);
  }

  return (
    <div className="h-full overflow-y-auto no-scrollbar space-y-6 pb-24 animate-fade-in bg-game-black relative">

      {/* Background Particles (Static CSS for now, could be canvas) */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
          <div className="absolute top-20 left-10 w-1 h-1 bg-blue-500 rounded-full opacity-50 animate-pulse"></div>
          <div className="absolute top-40 right-20 w-1 h-1 bg-purple-500 rounded-full opacity-30 animate-pulse delay-700"></div>
          <div className="absolute bottom-40 left-1/3 w-1 h-1 bg-blue-400 rounded-full opacity-40 animate-pulse delay-1000"></div>
      </div>

      {/* Welcome & Header */}
      <div className="px-5 pt-6 flex justify-between items-start relative z-10">
        <div>
            <div className="flex items-center gap-2 mb-1">
                <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse shadow-[0_0_10px_#22c55e]"></div>
                <p className="text-blue-400 text-[10px] font-mono uppercase tracking-[0.2em]">{t('systemActive')}</p>
            </div>
            <h2 className="text-3xl font-black text-white tracking-tighter uppercase drop-shadow-md">
                {t('welcomeHunter')} <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-purple-500">{playerProfile?.name || 'Player'}</span>
            </h2>
        </div>
        <button onClick={onOpenSettings} className="p-2 bg-neutral-900/80 backdrop-blur-md rounded-lg text-neutral-400 hover:text-white border border-neutral-700 hover:border-blue-500 transition-colors">
            <Settings size={20} />
        </button>
      </div>

      {/* 1️⃣ Weekly Challenge Section */}
      <div className="px-4 relative z-10">
        {showChallengeSelector && (
            <div className="bg-gradient-to-r from-blue-950/40 to-black border border-blue-900/50 p-5 rounded-lg shadow-[0_0_20px_rgba(30,58,138,0.2)] relative overflow-hidden group">
                <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/10 rounded-full blur-[50px] group-hover:bg-blue-600/20 transition-colors"></div>

                <div className="flex items-center gap-2 mb-3 text-blue-400 relative z-10">
