             </button>
             <div className="w-px bg-white/5 my-2"></div>
             <button onClick={() => onNavigateToTab(AppTab.STATS)} className="flex-1 py-3 flex flex-col items-center gap-1 hover:bg-white/5 rounded-lg transition-colors group">
                <PieChart size={20} className="text-neutral-400 group-hover:text-green-400 transition-colors" />
                <span className="text-[9px] font-bold text-neutral-500 group-hover:text-white uppercase tracking-wider">{t('statistics')}</span>
             </button>
          </div>
      </div>

      {/* Pillars Preview List (Compact) */}
      <div className="px-4 pb-4 space-y-3 relative z-10">
         <div className="flex justify-between items-end border-b border-neutral-800 pb-2 mb-2">
            <h3 className="text-xs font-black text-neutral-400 uppercase tracking-[0.2em]">{t('lifePillars')}</h3>
            <button onClick={() => onNavigateToTab(AppTab.PILLARS)} className="text-[10px] text-blue-500 font-bold hover:text-blue-400 uppercase tracking-widest">{t('viewAll')}</button>
         </div>

         <div className="grid grid-cols-1 gap-3">
            {/* Show only top 3 active or prioritized pillars to save space? Or all compacted. */}
            {PILLARS.slice(0, 3).map((pillar) => {
                const count = tasks.filter(t => t.pillar === pillar.id && !t.completed).length;
                return (
                    <PillWidget 
                        key={pillar.id}
                        pillarId={pillar.id} 
                        taskCount={count}
                        onClick={() => handleNavigatePillar(pillar.id)}
                        variant="card"
                    />
                );
            })}
         </div>
      </div>

      {/* Quick Add FAB (Floating Action Button) */}
      <button 
        onClick={handleQuickAdd}
        className="fixed bottom-24 left-6 w-14 h-14 bg-white text-black rounded-full shadow-[0_0_30px_rgba(255,255,255,0.4)] flex items-center justify-center hover:scale-110 active:scale-90 transition-all z-40 border-4 border-neutral-200 group"
      >
        <Plus size={28} strokeWidth={3} className="group-hover:rotate-90 transition-transform duration-300" />
      </button>

    </div>
  );
};

