      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { useSettings } from '../context/SettingsContext';
import { useGame } from '../context/GameContext';
import { useToast } from '../context/ToastContext';
import { Globe, Palette, AlertTriangle, Check, RotateCcw, Bell, Lock, User, Volume2, Smartphone, Monitor, ChevronRight, Edit2, Shield, Activity, Save, X, Clock, VolumeX, Download, Upload } from 'lucide-react';
import { ThemeColor, NotificationDuration } from '../types';
import { AudioService } from '../services/audioService';
import { NotificationService } from '../services/notifications';

export const SettingsScreen: React.FC = () => {
  const { language, themeColor, darkMode, notificationsEnabled, notificationDuration, soundEnabled, soundVolume, hapticsEnabled, updateSettings, toggleNotifications, t } = useSettings();
  const { playerProfile, updateProfile, resetProgress, exportSaveData, importSaveData } = useGame();
  const { addToast } = useToast();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [tempProfile, setTempProfile] = useState({
      name: playerProfile?.name || '',
      age: playerProfile?.age || 0,
      height: playerProfile?.height || 0,
      weight: playerProfile?.weight || 0
  });

  const themes: { id: ThemeColor; color: string; label: string }[] = [
    { id: 'red-black', color: '#ef4444', label: 'Red & Black' },
    { id: 'blue-dark', color: '#3b82f6', label: 'Blue & Dark' },
    { id: 'green-matrix', color: '#00f763', label: 'Matrix Green' },
    { id: 'purple-royal', color: '#d946ef', label: 'Royal Purple' },
    { id: 'pink-white', color: '#ff4d8d', label: 'Pink & White' },
  ];

  const handleNotificationClick = async () => {
    const targetState = !notificationsEnabled;
    if(soundEnabled) AudioService.playToggle(targetState);

    // If turning ON, request permission
    if (targetState) {
        const granted = await NotificationService.requestPermission();
        if (granted) {
            updateSettings({ notificationsEnabled: true });
            // Send test notification
            NotificationService.sendExternal("Solo Level", "System Online: Notifications Active");
            addToast("تم تفعيل الإشعارات", 'success');
        } else {
            addToast("تم رفض الإذن", 'error');
            updateSettings({ notificationsEnabled: false });
        }
    } else {
        updateSettings({ notificationsEnabled: false });
        addToast("تم إيقاف الإشعارات", 'info');
    }
  };

  const handleDurationChange = (duration: NotificationDuration) => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ notificationDuration: duration });
      setTimeout(() => addToast(`Updated duration to ${duration}`, 'info'), 100);
  };

  const handleHapticsToggle = () => {
      if(soundEnabled) AudioService.playToggle(!hapticsEnabled);
      updateSettings({ hapticsEnabled: !hapticsEnabled });
  };

  const saveProfileChanges = () => {
      if(soundEnabled) AudioService.playClick();
      updateProfile(tempProfile);
      setIsEditingProfile(false);
  };

  const toggleEditProfile = (edit: boolean) => {
      if(soundEnabled) AudioService.playClick();
      setIsEditingProfile(edit);
  };

  const changeTheme = (id: ThemeColor) => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ themeColor: id });
  };

  const changeLanguage = (lang: 'ar' | 'en') => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ language: lang });
  };

  // --- Backup Logic ---
  const handleExport = () => {
      const data = exportSaveData();
      const blob = new Blob([data], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `solotask_backup_${new Date().toISOString().slice(0,10)}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      if(soundEnabled) AudioService.playClick();
      addToast("تم تصدير ملف النسخ الاحتياطي", "success");
  };

  const handleImportClick = () => {
      if(fileInputRef.current) fileInputRef.current.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          const content = event.target?.result as string;
          if (content) {
              if (confirm("تحذير: استعادة النسخة الاحتياطية ستقوم بحذف بياناتك الحالية واستبدالها. هل أنت متأكد؟")) {
                  importSaveData(content);
              }
          }
      };
      reader.readAsText(file);
      // Reset input
      e.target.value = '';
  };

  return (
    <div className="h-full overflow-y-auto no-scrollbar pb-24 animate-fade-in bg-game-black">

      {/* Header */}
      <div className="sticky top-0 z-20 bg-game-black/90 backdrop-blur-md p-4 border-b border-neutral-800 flex items-center gap-3">
          <Monitor className="text-game-red" size={24} />
          <h2 className="text-2xl font-black text-white uppercase tracking-tighter">{t('settingsScreen')}</h2>
      </div>

      <div className="p-4 space-y-6">

        {/* 1. Profile Section */}
        <div className="bg-neutral-900 border border-neutral-800 rounded-2xl overflow-hidden relative">
            <div className="absolute top-0 right-0 p-4 opacity-10">
                <Shield size={100} />
            </div>

            <div className="p-4 border-b border-neutral-800 flex justify-between items-center relative z-10">
                <div className="flex items-center gap-2 text-game-red">
                    <User size={18} />
                    <h3 className="font-bold text-sm uppercase tracking-widest">{t('profileSettings')}</h3>
                </div>
                {!isEditingProfile ? (
                    <button onClick={() => toggleEditProfile(true)} className="p-2 bg-neutral-800 rounded-lg hover:text-white text-neutral-400 transition-colors">
                        <Edit2 size={16} />
                    </button>
                ) : (
                     <div className="flex gap-2">
                        <button onClick={() => toggleEditProfile(false)} className="p-2 bg-neutral-800 rounded-lg text-red-400 hover:bg-red-900/20">
                            <X size={16} />
                        </button>
                        <button onClick={saveProfileChanges} className="p-2 bg-green-900/50 rounded-lg text-green-400 hover:bg-green-900/80 border border-green-800">
                            <Save size={16} />
                        </button>
                    </div>
                )}
            </div>

            <div className="p-4 relative z-10">
                <div className="flex items-center gap-4 mb-6">
                    <div className="w-16 h-16 bg-gradient-to-br from-neutral-800 to-neutral-950 rounded-full border-2 border-game-red flex items-center justify-center shadow-[0_0_15px_rgba(220,38,38,0.3)]">
                        <User size={32} className="text-game-red" />
                    </div>
                    <div className="flex-1">
                        {isEditingProfile ? (
                            <input 
                                type="text" 
                                value={tempProfile.name}
                                onChange={(e) => setTempProfile({...tempProfile, name: e.target.value})}
                                className="bg-black border border-neutral-700 rounded px-2 py-1 text-white font-bold w-full focus:border-game-red outline-none"
                            />
                        ) : (
                            <h2 className="text-xl font-black text-white">{playerProfile?.name}</h2>
                        )}
                        <p className="text-xs text-game-red font-mono uppercase tracking-widest">{t('jobTitle')}</p>
                    </div>
