                <span className="text-lg font-black text-white">{(weeklyHistory.reduce((acc, w) => acc + w.tasksCompleted, 0)) + stats.weeklyTasksCompleted}</span>
            </div>
            <div className="text-center flex-1 border-l border-neutral-800">
                <span className="text-[10px] text-neutral-500 uppercase tracking-wider block mb-1">{t('maxStreak')}</span>
                <span className="text-lg font-black text-game-red">{Math.max(stats.streak, ...weeklyHistory.map(w => w.streakMax))}</span>
            </div>
        </div>

        {/* 2. Interactive Charts Section */}
        <div className="bg-neutral-900 border border-neutral-800 rounded-xl p-4 overflow-hidden">
             <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2 text-game-red">
                    <TrendingUp size={18} />
                    <h3 className="font-bold text-sm uppercase tracking-widest">{t('trend')}</h3>
                </div>
                {/* View Toggle */}
                <div className="flex bg-black rounded-lg p-0.5 border border-neutral-800">
                    <button 
                        onClick={() => {
                            if(soundEnabled) AudioService.playClick();
                            setHistoryView('WEEKS');
                            setSelectedHistoryIndex(null);
                        }}
                        className={`px-3 py-1 text-[10px] font-bold rounded transition-colors ${historyView === 'WEEKS' ? 'bg-neutral-700 text-white' : 'text-neutral-500'}`}
                    >
                        Weeks
                    </button>
                    <button 
                        onClick={() => {
                            if(soundEnabled) AudioService.playClick();
                            setHistoryView('MONTHS');
                            setSelectedHistoryIndex(null);
                        }}
                        className={`px-3 py-1 text-[10px] font-bold rounded transition-colors ${historyView === 'MONTHS' ? 'bg-neutral-700 text-white' : 'text-neutral-500'}`}
                    >
                        Months
                    </button>
                </div>
            </div>

            <div className="h-48 w-full -ml-4 relative z-10">
                <ResponsiveContainer width="100%" height="100%">
                    {historyView === 'WEEKS' ? (
                        weeklyChartData.length > 0 ? (
                            <AreaChart data={weeklyChartData} onClick={handleChartClick}>
                                <defs>
                                    <linearGradient id="colorXp" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="#dc2626" stopOpacity={0.3}/>
                                        <stop offset="95%" stopColor="#dc2626" stopOpacity={0}/>
                                    </linearGradient>
                                </defs>
                                <XAxis dataKey="name" stroke="#444" fontSize={10} tickLine={false} axisLine={false} />
                                <YAxis stroke="#444" fontSize={10} tickLine={false} axisLine={false} />
                                <CartesianGrid strokeDasharray="3 3" stroke="#222" vertical={false} />
                                <Tooltip 
                                    cursor={{ stroke: '#dc2626', strokeWidth: 1 }}
                                    contentStyle={{ backgroundColor: '#111', border: '1px solid #333', borderRadius: '8px' }}
                                    itemStyle={{ color: '#fff', fontSize: '12px' }}
                                />
                                <Area 
                                    type="monotone" 
                                    dataKey="xp" 
                                    stroke="#dc2626" 
                                    fillOpacity={1} 
                                    fill="url(#colorXp)" 
                                    strokeWidth={2} 
                                    activeDot={{ r: 6, strokeWidth: 0, fill: '#fff' }}
                                />
                            </AreaChart>
                        ) : (
                             <div className="flex items-center justify-center h-full text-neutral-600 text-xs">{t('noData')}</div>
                        )
                    ) : (
                        monthlyChartData.length > 0 ? (
                            <BarChart data={monthlyChartData}>
                                <XAxis dataKey="name" stroke="#444" fontSize={10} tickLine={false} axisLine={false} />
                                <YAxis stroke="#444" fontSize={10} tickLine={false} axisLine={false} />
                                <CartesianGrid strokeDasharray="3 3" stroke="#222" vertical={false} />
                                <Tooltip cursor={{fill: 'transparent'}} contentStyle={{ backgroundColor: '#111', border: '1px solid #333' }} />
                                <Bar dataKey="xp" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                            </BarChart>
                        ) : (
                            <div className="flex items-center justify-center h-full text-neutral-600 text-xs">{t('noData')}</div>
                        )
                    )}
                </ResponsiveContainer>
            </div>

            {/* Drill Down Detail View */}
            {historyView === 'WEEKS' && renderSelectedWeekDetails()}
        </div>

        {/* 3. Archives List */}
        <div>
            <h3 className="text-xs font-black text-neutral-500 uppercase tracking-widest mb-3 px-1">
                {historyView === 'WEEKS' ? t('weeklyReport') : t('monthlyReport')} Archives
            </h3>

            <div className="space-y-3">
                {historyView === 'WEEKS' ? (
                    weeklyReports.length === 0 ? (
                         <div className="text-center py-8 opacity-50 border-2 border-dashed border-neutral-800 rounded-xl">
                            <History size={32} className="mx-auto mb-2 text-neutral-600" />
                            <p className="text-sm text-neutral-500">{t('archiveEmpty')}</p>
                        </div>
                    ) : (
                        weeklyReports.slice().reverse().map(report => {
                            const style = getRatingColor(report.rating);
                            const isExpanded = expandedReportId === report.weekId;

                            return (
                                <div key={report.weekId} className={`rounded-xl overflow-hidden border transition-all duration-300 ${style}`}>
                                    <div 
                                        onClick={() => {
                                            if(soundEnabled) AudioService.playClick();
                                            setExpandedReportId(isExpanded ? null : report.weekId);
                                        }}
                                        className="p-4 flex items-center justify-between cursor-pointer active:bg-black/20"
                                    >
                                        <div className="flex items-center gap-4">
                                            <div className="flex flex-col items-center justify-center w-12">
                                                 <span className="text-[10px] font-bold text-neutral-400 uppercase">Week</span>
                                                 {/* Extract week number from ID or index if available, else standard icon */}
                                                 <span className="text-xl font-black">{new Date(report.createdAt).getDate()}</span>
                                            </div>

                                            <div className="h-8 w-px bg-neutral-700/50"></div>

                                            <div>
                                                <div className="flex items-center gap-2">
                                                    <h4 className="font-bold text-sm uppercase tracking-wider">{t(report.rating.toLowerCase() as any)}</h4>
                                                    {report.rating === 'Excellent' && <Trophy size={12} className="text-yellow-500"/>}
                                                </div>
                                                <p className="text-[10px] opacity-70 flex items-center gap-1">
                                                    <Calendar size={10} />
                                                    {new Date(report.createdAt).toLocaleDateString()}
                                                </p>
                                            </div>
                                        </div>

                                        <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}>
                                            <ChevronDown size={18} />
                                        </div>
                                    </div>

                                    {isExpanded && (
                                        <div className="p-4 pt-0 border-t border-black/10 bg-black/20">
                                            <div className="py-3">
                                                <p className="text-xs leading-relaxed opacity-90 font-medium">
                                                    "{report.summaryText}"
                                                </p>
                                            </div>

                                            <div className="grid grid-cols-2 gap-2 mt-2">
                                                <div className="bg-black/30 p-2 rounded flex items-center gap-2">
                                                    <Target size={14} className="text-blue-400" />
                                                    <div>
                                                        <span className="text-[9px] block opacity-50 uppercase">Focus</span>
                                                        <span className="text-xs font-bold">{t(report.bestPillar.toLowerCase() as any)}</span>
                                                    </div>
                                                </div>
                                                <div className="bg-black/30 p-2 rounded flex items-center gap-2">
                                                    <Zap size={14} className="text-yellow-400" />
                                                    <div>
                                                        <span className="text-[9px] block opacity-50 uppercase">Total XP</span>
                                                        <span className="text-xs font-bold">
                                                            {/* Check against null specifically, as 0 is falsey */}
                                                            {report.comparison.xpChangePercent !== null 
                                                                ? `${report.comparison.xpChangePercent > 0 ? '+' : ''}${report.comparison.xpChangePercent}%` 
                                                                : 'N/A'
                                                            }
                                                        </span>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            );
                        })
                    )
                ) : (
                    // Monthly View Logic (Simplified for brevity, follows same pattern)
                    monthlyReports.length === 0 ? (
                         <div className="text-center py-8 opacity-50 border-2 border-dashed border-neutral-800 rounded-xl">
                            <Award size={32} className="mx-auto mb-2 text-neutral-600" />
                            <p className="text-sm text-neutral-500">{t('archiveEmpty')}</p>
                        </div>
                    ) : (
                        monthlyReports.slice().reverse().map(report => (
                            <div key={report.monthId} className={`p-4 rounded-xl border mb-2 ${getRatingColor(report.monthRating)}`}>
                                <div className="flex justify-between items-center">
                                    <div>
                                        <span className="text-xs font-bold block opacity-60">{report.monthId}</span>
                                        <span className="font-black text-lg uppercase">{t(report.monthRating.toLowerCase() as any)}</span>
                                    </div>
                                    <Award size={24} />
                                </div>
                                <p className="text-xs mt-2 opacity-80">{report.summaryText}</p>
                            </div>
                        ))
                    )
                )}
            </div>
        </div>
    </div>
  );

  const renderRecordTab = () => (
      <div className="space-y-4 animate-slide-up pb-6">
           <div className="bg-neutral-900 border border-neutral-800 rounded-xl p-4 mb-4">
                <div className="flex items-center gap-2 text-purple-400 mb-2">
                    <List size={20} />
                    <h3 className="font-black text-white uppercase tracking-wider">{t('detailedHistory')}</h3>
                </div>
                <p className="text-xs text-neutral-400">
                    {t('historyDesc')}
                </p>
           </div>

           <HistoryLogViewer />
      </div>
  );

  return (
    <div className="h-full overflow-y-auto no-scrollbar pb-24 animate-fade-in bg-game-black">
      {/* Header */}
      <div className="sticky top-0 z-20 bg-game-black/90 backdrop-blur-md p-4 border-b border-neutral-800">
          <div className="flex items-center gap-3 mb-4">
            <TrendingUp className="text-game-red" size={24} />
            <h2 className="text-2xl font-black text-white uppercase tracking-tighter">{t('statistics')}</h2>
          </div>

          {/* Tabs */}
          <div className="flex bg-neutral-900 p-1 rounded-xl shadow-inner">
             <button 
                onClick={() => {
                    if(soundEnabled) AudioService.playClick();
                    setActiveTab('STATUS');
                }}
                className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'STATUS' ? 'bg-neutral-800 text-white shadow ring-1 ring-white/10' : 'text-neutral-500 hover:text-white'}`}
             >
                {t('tabStatus')}
             </button>
             <button 
                onClick={() => {
                    if(soundEnabled) AudioService.playClick();
                    setActiveTab('HISTORY');
                }}
                className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'HISTORY' ? 'bg-neutral-800 text-white shadow ring-1 ring-white/10' : 'text-neutral-500 hover:text-white'}`}
             >
                {t('tabHistory')}
             </button>
             <button 
                onClick={() => {
                    if(soundEnabled) AudioService.playClick();
                    setActiveTab('RECORD');
                }}
                className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${activeTab === 'RECORD' ? 'bg-neutral-800 text-white shadow ring-1 ring-white/10' : 'text-neutral-500 hover:text-white'}`}
             >
                {t('tabRecord')}
             </button>
          </div>
      </div>

      <div className="p-4">
        {activeTab === 'STATUS' ? renderStatusTab() : activeTab === 'HISTORY' ? renderHistoryTab() : renderRecordTab()}
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { useSettings } from '../context/SettingsContext';
import { useGame } from '../context/GameContext';
import { useToast } from '../context/ToastContext';
import { Globe, Palette, AlertTriangle, Check, RotateCcw, Bell, Lock, User, Volume2, Smartphone, Monitor, ChevronRight, Edit2, Shield, Activity, Save, X, Clock, VolumeX, Download, Upload, FileText, Database } from 'lucide-react';
import { ThemeColor, NotificationDuration } from '../types';
import { AudioService } from '../services/audioService';
import { NotificationService } from '../services/notifications';

export const SettingsScreen: React.FC = () => {
  const { language, themeColor, darkMode, notificationsEnabled, notificationDuration, soundEnabled, soundVolume, hapticsEnabled, updateSettings, toggleNotifications, t } = useSettings();
  const { playerProfile, updateProfile, resetProgress, exportSaveData, importSaveData } = useGame();
  const { addToast } = useToast();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [tempProfile, setTempProfile] = useState({
      name: playerProfile?.name || '',
      age: playerProfile?.age || 0,
      height: playerProfile?.height || 0,
      weight: playerProfile?.weight || 0
  });

  const themes: { id: ThemeColor; color: string; label: string }[] = [
    { id: 'red-black', color: '#ef4444', label: 'Red & Black' },
    { id: 'blue-dark', color: '#3b82f6', label: 'Blue & Dark' },
    { id: 'green-matrix', color: '#00f763', label: 'Matrix Green' },
    { id: 'purple-royal', color: '#d946ef', label: 'Royal Purple' },
    { id: 'pink-white', color: '#ff4d8d', label: 'Pink & White' },
  ];

  const handleNotificationClick = async () => {
    const targetState = !notificationsEnabled;
    if(soundEnabled) AudioService.playToggle(targetState);

    // If turning ON, request permission
    if (targetState) {
        const granted = await NotificationService.requestPermission();
        if (granted) {
            updateSettings({ notificationsEnabled: true });
            // Send test notification
            NotificationService.sendExternal("Solo Level", "System Online: Notifications Active");
            addToast("تم تفعيل الإشعارات", 'success');
        } else {
            addToast("تم رفض الإذن", 'error');
            updateSettings({ notificationsEnabled: false });
        }
    } else {
        updateSettings({ notificationsEnabled: false });
        addToast("تم إيقاف الإشعارات", 'info');
    }
  };

  const handleDurationChange = (duration: NotificationDuration) => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ notificationDuration: duration });
      setTimeout(() => addToast(`Updated duration to ${duration}`, 'info'), 100);
  };

  const handleHapticsToggle = () => {
      if(soundEnabled) AudioService.playToggle(!hapticsEnabled);
      updateSettings({ hapticsEnabled: !hapticsEnabled });
  };

  const saveProfileChanges = () => {
      if(soundEnabled) AudioService.playClick();
      updateProfile(tempProfile);
      setIsEditingProfile(false);
  };

  const toggleEditProfile = (edit: boolean) => {
      if(soundEnabled) AudioService.playClick();
      setIsEditingProfile(edit);
  };

  const changeTheme = (id: ThemeColor) => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ themeColor: id });
  };

  const changeLanguage = (lang: 'ar' | 'en') => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ language: lang });
  };

  // --- Backup Logic ---
  const handleExport = () => {
      const data = exportSaveData();
      const blob = new Blob([data], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `solotask_backup_${new Date().toISOString().slice(0,10)}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      if(soundEnabled) AudioService.playClick();
      addToast("تم تصدير ملف النسخ الاحتياطي", "success");
  };

  const handleImportClick = () => {
      if(fileInputRef.current) fileInputRef.current.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          const content = event.target?.result as string;
          if (content) {
              if (confirm("تحذير: استعادة النسخة الاحتياطية ستقوم بحذف بياناتك الحالية واستبدالها. هل أنت متأكد؟")) {
                  importSaveData(content);
              }
          }
      };
      reader.readAsText(file);
      // Reset input
      e.target.value = '';
  };

  return (
    <div className="h-full overflow-y-auto no-scrollbar pb-24 animate-fade-in bg-game-black">

      {/* Header */}
      <div className="sticky top-0 z-20 bg-game-black/90 backdrop-blur-md p-4 border-b border-neutral-800 flex items-center gap-3">
          <Monitor className="text-game-red" size={24} />
          <h2 className="text-2xl font-black text-white uppercase tracking-tighter">{t('settingsScreen')}</h2>
      </div>

      <div className="p-4 space-y-6">

        {/* 1. Profile Section */}
        <div className="bg-neutral-900 border border-neutral-800 rounded-2xl overflow-hidden relative">
            <div className="absolute top-0 right-0 p-4 opacity-10">
                <Shield size={100} />
            </div>

            <div className="p-4 border-b border-neutral-800 flex justify-between items-center relative z-10">
                <div className="flex items-center gap-2 text-game-red">
                    <User size={18} />
                    <h3 className="font-bold text-sm uppercase tracking-widest">{t('profileSettings')}</h3>
                </div>
                {!isEditingProfile ? (
                    <button onClick={() => toggleEditProfile(true)} className="p-2 bg-neutral-800 rounded-lg hover:text-white text-neutral-400 transition-colors">
                        <Edit2 size={16} />
                    </button>
                ) : (
                     <div className="flex gap-2">
                        <button onClick={() => toggleEditProfile(false)} className="p-2 bg-neutral-800 rounded-lg text-red-400 hover:bg-red-900/20">
                            <X size={16} />
                        </button>
                        <button onClick={saveProfileChanges} className="p-2 bg-green-900/50 rounded-lg text-green-400 hover:bg-green-900/80 border border-green-800">
                            <Save size={16} />
                        </button>
                    </div>
                )}
            </div>

            <div className="p-4 relative z-10">
                <div className="flex items-center gap-4 mb-6">
                    <div className="w-16 h-16 bg-gradient-to-br from-neutral-800 to-neutral-950 rounded-full border-2 border-game-red flex items-center justify-center shadow-[0_0_15px_rgba(220,38,38,0.3)]">
                        <User size={32} className="text-game-red" />
                    </div>
                    <div className="flex-1">
                        {isEditingProfile ? (
                            <input 
                                type="text" 
                                value={tempProfile.name}
                                onChange={(e) => setTempProfile({...tempProfile, name: e.target.value})}
                                className="bg-black border border-neutral-700 rounded px-2 py-1 text-white font-bold w-full focus:border-game-red outline-none"
                            />
                        ) : (
                            <h2 className="text-xl font-black text-white">{playerProfile?.name}</h2>
                        )}
                        <p className="text-xs text-game-red font-mono uppercase tracking-widest">{t('jobTitle')}</p>
                    </div>
                </div>

                <div className="grid grid-cols-3 gap-2">
                    <div className="bg-black/40 p-2 rounded border border-neutral-800 text-center">
                        <span className="text-[10px] text-neutral-500 uppercase block mb-1">{t('age')}</span>
                        {isEditingProfile ? (
                            <input 
                                type="number" 
                                value={tempProfile.age}
                                onChange={(e) => setTempProfile({...tempProfile, age: Number(e.target.value)})}
                                className="bg-neutral-900 w-full text-center text-sm font-bold text-white outline-none rounded"
                            />
                        ) : (
                            <span className="text-lg font-bold text-white">{playerProfile?.age}</span>
                        )}
                    </div>
                    <div className="bg-black/40 p-2 rounded border border-neutral-800 text-center">
                        <span className="text-[10px] text-neutral-500 uppercase block mb-1">{t('height')}</span>
                        {isEditingProfile ? (
                             <input 
                                type="number" 
                                value={tempProfile.height}
                                onChange={(e) => setTempProfile({...tempProfile, height: Number(e.target.value)})}
                                className="bg-neutral-900 w-full text-center text-sm font-bold text-white outline-none rounded"
                            />
                        ) : (
                             <span className="text-lg font-bold text-white">{playerProfile?.height} <span className="text-[10px]">cm</span></span>
                        )}
                    </div>
                    <div className="bg-black/40 p-2 rounded border border-neutral-800 text-center">
                        <span className="text-[10px] text-neutral-500 uppercase block mb-1">{t('weight')}</span>
                        {isEditingProfile ? (
                             <input 
                                type="number" 
                                value={tempProfile.weight}
                                onChange={(e) => setTempProfile({...tempProfile, weight: Number(e.target.value)})}
                                className="bg-neutral-900 w-full text-center text-sm font-bold text-white outline-none rounded"
                            />
                        ) : (
                            <span className="text-lg font-bold text-white">{playerProfile?.weight} <span className="text-[10px]">kg</span></span>
                        )}
                    </div>
                </div>
            </div>
        </div>

        {/* 2. System Settings */}
        <div className="bg-neutral-900 border border-neutral-800 rounded-2xl overflow-hidden">
             <div className="p-4 border-b border-neutral-800 flex items-center gap-2 text-blue-500">
                <Activity size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">{t('systemSettings')}</h3>
            </div>

            <div className="divide-y divide-neutral-800">
                {/* Notifications */}
                <button 
                    onClick={handleNotificationClick}
                    className="w-full p-4 flex items-center justify-between hover:bg-neutral-800/50 transition-colors"
                >
                    <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-lg ${notificationsEnabled ? 'bg-green-900/20 text-green-500' : 'bg-neutral-800 text-neutral-500'}`}>
                            <Bell size={18} />
                        </div>
                        <div className="text-left">
                            <p className="font-bold text-sm text-white">{t('notifications')}</p>
                            <p className="text-[10px] text-neutral-500">{t('notificationsDesc')}</p>
                        </div>
                    </div>
                    <div className={`w-10 h-5 rounded-full p-0.5 transition-colors ${notificationsEnabled ? 'bg-green-600' : 'bg-neutral-700'}`}>
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${notificationsEnabled ? (language === 'ar' ? '-translate-x-5' : 'translate-x-5') : ''}`} />
                    </div>
                </button>

                {/* Notification Duration */}
                <div className="p-4 flex flex-col gap-3 bg-black/20">
                     <div className="flex items-center gap-3 mb-1">
                        <div className="p-2 rounded-lg bg-neutral-800 text-neutral-400">
                            <Clock size={18} />
                        </div>
                        <p className="font-bold text-sm text-white">{t('alertDuration')}</p>
                    </div>
                    <div className="grid grid-cols-4 gap-2">
                        {(['short', 'medium', 'long', 'persistent'] as NotificationDuration[]).map(d => (
                            <button
                                key={d}
                                onClick={() => handleDurationChange(d)}
                                className={`
                                    py-2 rounded-lg text-[10px] font-bold uppercase transition-all border
                                    ${notificationDuration === d 
                                        ? 'bg-neutral-800 text-white border-white' 
                                        : 'bg-black text-neutral-500 border-neutral-800 hover:border-neutral-600'}
                                `}
                            >
                                {d}
                            </button>
                        ))}
                    </div>
                </div>

                 {/* Volume Control Slider */}
                 <div className="w-full p-4 flex flex-col gap-3">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-neutral-800 text-neutral-400">
                                {soundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                            </div>
                            <p className="font-bold text-sm text-white">{t('soundEffects')}</p>
                        </div>
                        <span className="text-xs font-mono text-neutral-500">{(soundVolume * 100).toFixed(0)}%</span>
                    </div>

                    <div className="flex items-center gap-4">
                        <button 
                            onClick={() => {
                                if(soundEnabled) AudioService.playToggle(!soundEnabled);
                                updateSettings({ soundEnabled: !soundEnabled });
                            }}
                            className={`w-10 h-5 rounded-full p-0.5 transition-colors ${soundEnabled ? 'bg-blue-600' : 'bg-neutral-700'}`}
                        >
                            <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${soundEnabled ? (language === 'ar' ? '-translate-x-5' : 'translate-x-5') : ''}`} />
                        </button>
                        <input 
                            type="range" 
                            min="0" 
                            max="1" 
                            step="0.05"
                            value={soundVolume}
                            onChange={(e) => updateSettings({ soundVolume: parseFloat(e.target.value), soundEnabled: true })}
                            className="flex-1 h-2 bg-neutral-700 rounded-lg appearance-none cursor-pointer accent-game-red"
                        />
                    </div>
                </div>

                {/* Haptics */}
                 <button 
                    onClick={handleHapticsToggle}
                    className="w-full p-4 flex items-center justify-between hover:bg-neutral-800/50 transition-colors"
                >
                    <div className="flex items-center gap-3">
                        <div className="p-2 rounded-lg bg-neutral-800 text-neutral-400">
                            <Smartphone size={18} />
                        </div>
                        <p className="font-bold text-sm text-white">{t('hapticFeedback')}</p>
                    </div>
                    <div className={`w-10 h-5 rounded-full p-0.5 transition-colors ${hapticsEnabled ? 'bg-blue-600' : 'bg-neutral-700'}`}>
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${hapticsEnabled ? (language === 'ar' ? '-translate-x-5' : 'translate-x-5') : ''}`} />
                    </div>
                </button>

                {/* Language */}
                <div className="p-4 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="p-2 rounded-lg bg-neutral-800 text-neutral-400">
                            <Globe size={18} />
                        </div>
                        <p className="font-bold text-sm text-white">{t('language')}</p>
                    </div>
                    <div className="flex bg-black rounded-lg p-1 border border-neutral-800">
                        <button 
                            onClick={() => changeLanguage('ar')}
                            className={`px-3 py-1 rounded text-xs font-bold transition-colors ${language === 'ar' ? 'bg-blue-600 text-white' : 'text-neutral-500 hover:text-white'}`}
                        >
                            AR
                        </button>
                        <button 
                             onClick={() => changeLanguage('en')}
                             className={`px-3 py-1 rounded text-xs font-bold transition-colors ${language === 'en' ? 'bg-blue-600 text-white' : 'text-neutral-500 hover:text-white'}`}
                        >
                            EN
                        </button>
                    </div>
                </div>
            </div>
        </div>

        {/* 3. NEW: Security & Permissions */}
        <div className="bg-neutral-900 border border-neutral-800 rounded-2xl overflow-hidden p-4">
             <div className="flex items-center gap-2 mb-4 text-emerald-500">
                <Lock size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">{t('securitySection')}</h3>
            </div>

            <div className="space-y-4">
                {/* Notification Status */}
                <div className="flex items-start justify-between bg-black/40 p-3 rounded-xl border border-neutral-800">
                    <div className="flex gap-3">
                        <Bell size={18} className="text-neutral-500 mt-1" />
                        <div>
                            <h4 className="text-xs font-bold text-white">{t('permNotificationsTitle')}</h4>
                            <p className="text-[10px] text-neutral-500 leading-tight mt-1 max-w-[200px]">
                                {t('permNotificationsDesc')}
                            </p>
                        </div>
                    </div>
                    <span className={`text-[9px] font-bold px-2 py-1 rounded border uppercase ${notificationsEnabled ? 'text-green-400 border-green-900 bg-green-900/20' : 'text-red-400 border-red-900 bg-red-900/20'}`}>
                        {notificationsEnabled ? t('permGranted') : t('permDenied')}
                    </span>
                </div>

                {/* Storage Status */}
                <div className="flex items-start justify-between bg-black/40 p-3 rounded-xl border border-neutral-800">
                    <div className="flex gap-3">
                        <FileText size={18} className="text-neutral-500 mt-1" />
                        <div>
                            <h4 className="text-xs font-bold text-white">{t('permStorageTitle')}</h4>
                            <p className="text-[10px] text-neutral-500 leading-tight mt-1 max-w-[200px]">
                                {t('permStorageDesc')}
                            </p>
                        </div>
                    </div>
                    <span className="text-[9px] font-bold px-2 py-1 rounded border uppercase text-blue-400 border-blue-900 bg-blue-900/20">
                        {t('permSystem')}
                    </span>
                </div>

                {/* Privacy Badge */}
                <div className="flex items-center gap-3 bg-emerald-900/10 p-3 rounded-xl border border-emerald-900/30">
                    <Database size={18} className="text-emerald-500" />
                    <div>
                        <h4 className="text-xs font-bold text-emerald-400">{t('permPrivacyTitle')}</h4>
                        <p className="text-[10px] text-emerald-500/70 leading-tight mt-0.5">
                            {t('permPrivacyDesc')}
                        </p>
                    </div>
                    <div className="flex-1 text-left" dir="ltr">
                        <Check size={14} className="text-emerald-500 inline-block ml-auto" />
                    </div>
                </div>
            </div>
        </div>

        {/* 4. Visuals */}
        <div className="bg-neutral-900 border border-neutral-800 rounded-2xl overflow-hidden p-4">
             <div className="flex items-center gap-2 mb-4 text-purple-500">
                <Palette size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">{t('theme')}</h3>
            </div>

            <div className="grid grid-cols-2 gap-3">
                {themes.map(theme => (
                    <button
                        key={theme.id}
                        onClick={() => changeTheme(theme.id)}
                        className={`
                            relative h-16 rounded-xl overflow-hidden transition-all border-2
                            ${themeColor === theme.id ? 'border-white scale-105 shadow-lg' : 'border-transparent opacity-60 hover:opacity-100'}
                        `}
                        style={{ backgroundColor: theme.color }}
                    >
                        <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent flex items-end p-2">
                             <span className="text-white font-bold text-xs">{theme.label}</span>
                             {themeColor === theme.id && <Check size={14} className="ml-auto text-white" />}
                        </div>
                    </button>
                ))}
            </div>
        </div>

        {/* 5. Backup & Data */}
        <div className="bg-neutral-900 border border-neutral-800 rounded-2xl overflow-hidden p-4">
             <div className="flex items-center gap-2 mb-4 text-blue-400">
                <Save size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">إدارة البيانات</h3>
            </div>

            <div className="grid grid-cols-2 gap-3">
                <button
                    onClick={handleExport}
                    className="flex flex-col items-center justify-center gap-2 bg-neutral-800 p-4 rounded-xl hover:bg-neutral-700 border border-neutral-700 transition-colors"
                >
                    <Download size={20} className="text-blue-400" />
                    <span className="text-xs font-bold text-white">تصدير نسخة</span>
                </button>

                <button
                    onClick={handleImportClick}
                    className="flex flex-col items-center justify-center gap-2 bg-neutral-800 p-4 rounded-xl hover:bg-neutral-700 border border-neutral-700 transition-colors"
                >
                    <Upload size={20} className="text-yellow-400" />
                    <span className="text-xs font-bold text-white">استعادة نسخة</span>
                </button>
                {/* Hidden File Input */}
                <input 
                    type="file" 
                    ref={fileInputRef} 
                    onChange={handleFileChange} 
                    className="hidden" 
                    accept=".json"
                />
            </div>
        </div>

        {/* 6. Danger Zone */}
         <div className="bg-red-950/20 border border-red-900/50 rounded-2xl overflow-hidden p-4">
             <div className="flex items-center gap-2 mb-4 text-red-500">
                <AlertTriangle size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">{t('dangerZone')}</h3>
            </div>
             <button 
                onClick={resetProgress}
                className="w-full flex items-center justify-center gap-2 bg-red-900/20 text-red-500 p-3 rounded-xl border border-red-900/50 hover:bg-red-900/40 transition-colors"
            >
                <RotateCcw size={16} />
                <span className="font-bold text-sm">{t('resetProgress')}</span>
            </button>
         </div>

         <div className="text-center">
            <p className="text-[10px] text-neutral-600 font-mono">SYSTEM VERSION 1.2.0 (STABLE)</p>
         </div>

      </div>
    </div>
  );
};

