                    <div className="flex items-center gap-2 mb-2">
                        <span className={`text-[9px] font-black uppercase tracking-[0.2em] px-2 py-0.5 rounded-sm border ${stats.weeklyChallenge.completed ? 'text-green-400 border-green-500/30 bg-green-500/10' : 'text-yellow-500 border-yellow-500/30 bg-yellow-500/10'}`}>
                            {stats.weeklyChallenge.completed ? t('missionComplete') : t('activeMission')}
                        </span>
                    </div>
                    <p className={`font-bold text-sm ${stats.weeklyChallenge.completed ? 'text-game-text-muted line-through' : 'text-game-text'}`}>
                        {stats.weeklyChallenge.title}
                    </p>
                </div>

                {!stats.weeklyChallenge.completed ? (
                    <button 
                        onClick={() => {
                            if(soundEnabled) AudioService.playClick();
                            completeWeeklyChallenge();
                        }}
                        className="relative z-10 bg-game-bg hover:bg-yellow-600 hover:text-black text-game-text-muted p-3 rounded-md transition-all border border-game-border hover:border-yellow-400"
                    >
                        <CheckCircle2 size={24} />
                    </button>
                ) : (
                    <div className="bg-green-500/10 border border-green-500/30 p-2 rounded-full text-green-500">
                        <CheckCircle2 size={24} />
                    </div>
                )}
             </div>
        )}
      </div>

      {/* Stats Grid */}
      <div className="px-4 grid grid-cols-2 gap-3 relative z-10">
        {/* Level Widget (Tall) */}
        <div className="col-span-1 row-span-2">
             <DashboardWidget 
                label={t('level')}
                value={stats.level}
                subValue={t('currentRank')}
                icon={Trophy}
                iconColor="text-yellow-500"
                progress={{
                    current: stats.currentXp,
                    max: stats.maxXp,
                    colorClass: "bg-gradient-to-r from-yellow-600 to-yellow-400"
                }}
                variant="circular"
                borderColor="border-game-border"
            />
        </div>

        {/* Energy Widget */}
        <DashboardWidget 
            label={t('energy')}
            value={stats.energy}
            subValue={`/ ${stats.maxEnergy}`}
            icon={Zap}
            iconColor="text-blue-400"
            progress={{
                current: stats.energy,
                max: stats.maxEnergy,
                colorClass: "bg-gradient-to-r from-blue-600 to-blue-400"
            }}
            borderColor="border-game-border"
        />

        {/* Mini Widgets */}
        <div className="grid grid-cols-2 gap-3">
            <DashboardWidget 
                label={t('streak')}
                value={stats.streak}
                icon={Flame}
                iconColor="text-orange-500"
                borderColor="border-game-border"
            />
             <DashboardWidget 
                label={t('done')}
                value={completedTasksCount}
                icon={Activity}
                iconColor="text-emerald-500"
                borderColor="border-game-border"
            />
        </div>
      </div>

      {/* Quick Nav (The Dock) - Updated to use game-surface/bg */}
      <div className="px-4 relative z-10">
          <div className="bg-game-surface/60 backdrop-blur-md border border-game-border rounded-xl p-1 flex shadow-lg">
             <button onClick={() => onNavigateToTab(AppTab.PLANNER)} className="flex-1 py-3 flex flex-col items-center gap-1 hover:bg-game-bg/50 rounded-lg transition-colors group">
                <CalendarDays size={20} className="text-game-text-muted group-hover:text-game-primary transition-colors" />
                <span className="text-[9px] font-bold text-game-text-muted group-hover:text-game-text uppercase tracking-wider">{t('planner')}</span>
             </button>
             <div className="w-px bg-game-border my-2"></div>
             <button onClick={() => onNavigateToTab(AppTab.COACH)} className="flex-1 py-3 flex flex-col items-center gap-1 hover:bg-game-bg/50 rounded-lg transition-colors group">
                <Bot size={20} className="text-game-text-muted group-hover:text-purple-400 transition-colors" />
                <span className="text-[9px] font-bold text-game-text-muted group-hover:text-game-text uppercase tracking-wider">{t('coach')}</span>
             </button>
             <div className="w-px bg-game-border my-2"></div>
             <button onClick={() => onNavigateToTab(AppTab.STATS)} className="flex-1 py-3 flex flex-col items-center gap-1 hover:bg-game-bg/50 rounded-lg transition-colors group">
                <PieChart size={20} className="text-game-text-muted group-hover:text-green-400 transition-colors" />
                <span className="text-[9px] font-bold text-game-text-muted group-hover:text-game-text uppercase tracking-wider">{t('statistics')}</span>
             </button>
          </div>
      </div>

      {/* Pillars Preview List (Compact) */}
      <div className="px-4 pb-4 space-y-3 relative z-10">
         <div className="flex justify-between items-end border-b border-game-border pb-2 mb-2">
            <h3 className="text-xs font-black text-game-text-muted uppercase tracking-[0.2em]">{t('lifePillars')}</h3>
            <button onClick={() => onNavigateToTab(AppTab.PILLARS)} className="text-[10px] text-game-primary font-bold hover:text-game-accent uppercase tracking-widest">{t('viewAll')}</button>
         </div>

         <div className="grid grid-cols-1 gap-3">
            {/* Show only top 3 active or prioritized pillars to save space? Or all compacted. */}
            {PILLARS.slice(0, 3).map((pillar) => {
                const count = tasks.filter(t => t.pillar === pillar.id && !t.completed).length;
                return (
                    <PillWidget 
                        key={pillar.id}
                        pillarId={pillar.id} 
                        taskCount={count}
                        onClick={() => handleNavigatePillar(pillar.id)}
                        variant="card"
                    />
                );
            })}
         </div>
      </div>

      {/* Quick Add FAB (Floating Action Button) */}
      <button 
        onClick={handleQuickAdd}
        className="fixed bottom-24 left-6 w-14 h-14 bg-game-text text-game-bg rounded-full shadow-[0_0_30px_rgba(255,255,255,0.4)] flex items-center justify-center hover:scale-110 active:scale-90 transition-all z-40 border-4 border-game-surface group"
      >
        <Plus size={28} strokeWidth={3} className="group-hover:rotate-90 transition-transform duration-300" />
      </button>

    </div>
  );
};

import React, { useState, useRef } from 'react';
import { useSettings } from '../context/SettingsContext';
import { useGame } from '../context/GameContext';
import { useToast } from '../context/ToastContext';
import { Globe, Palette, AlertTriangle, Check, RotateCcw, Bell, Lock, User, Volume2, Smartphone, Monitor, ChevronRight, Edit2, Shield, Activity, Save, X, Clock, VolumeX, Download, Upload, FileText, Database } from 'lucide-react';
import { ThemeColor, NotificationDuration } from '../types';
import { AudioService } from '../services/audioService';
import { NotificationService } from '../services/notifications';

export const SettingsScreen: React.FC = () => {
  const { language, themeColor, darkMode, notificationsEnabled, notificationDuration, soundEnabled, soundVolume, hapticsEnabled, updateSettings, toggleNotifications, t } = useSettings();
  const { playerProfile, updateProfile, resetProgress, exportSaveData, importSaveData } = useGame();
  const { addToast } = useToast();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [tempProfile, setTempProfile] = useState({
      name: playerProfile?.name || '',
      age: playerProfile?.age || 0,
      height: playerProfile?.height || 0,
      weight: playerProfile?.weight || 0
  });

  const themes: { id: ThemeColor; color: string; label: string }[] = [
    { id: 'red-black', color: '#ef4444', label: 'Red & Black' },
    { id: 'blue-dark', color: '#3b82f6', label: 'Blue & Dark' },
    { id: 'green-matrix', color: '#00f763', label: 'Matrix Green' },
    { id: 'purple-royal', color: '#d946ef', label: 'Royal Purple' },
    { id: 'pink-white', color: '#ff4d8d', label: 'Pink & White' },
  ];

  const handleNotificationClick = async () => {
    const targetState = !notificationsEnabled;
    if(soundEnabled) AudioService.playToggle(targetState);

    if (targetState) {
        const granted = await NotificationService.requestPermission();
        if (granted) {
            updateSettings({ notificationsEnabled: true });
            NotificationService.sendExternal("Solo Level", "System Online: Notifications Active");
            addToast("تم تفعيل الإشعارات", 'success');
        } else {
            addToast("تم رفض الإذن", 'error');
            updateSettings({ notificationsEnabled: false });
        }
    } else {
        updateSettings({ notificationsEnabled: false });
        addToast("تم إيقاف الإشعارات", 'info');
    }
  };

  const handleDurationChange = (duration: NotificationDuration) => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ notificationDuration: duration });
      setTimeout(() => addToast(`Updated duration to ${duration}`, 'info'), 100);
  };

  const handleHapticsToggle = () => {
      if(soundEnabled) AudioService.playToggle(!hapticsEnabled);
      updateSettings({ hapticsEnabled: !hapticsEnabled });
  };

  const saveProfileChanges = () => {
      if(soundEnabled) AudioService.playClick();
      updateProfile(tempProfile);
      setIsEditingProfile(false);
  };

  const toggleEditProfile = (edit: boolean) => {
      if(soundEnabled) AudioService.playClick();
      setIsEditingProfile(edit);
  };

  const changeTheme = (id: ThemeColor) => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ themeColor: id });
  };

  const changeLanguage = (lang: 'ar' | 'en') => {
      if(soundEnabled) AudioService.playClick();
      updateSettings({ language: lang });
  };

  const handleExport = () => {
      const data = exportSaveData();
      const blob = new Blob([data], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `solotask_backup_${new Date().toISOString().slice(0,10)}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      if(soundEnabled) AudioService.playClick();
      addToast("تم تصدير ملف النسخ الاحتياطي", "success");
  };

  const handleImportClick = () => {
      if(fileInputRef.current) fileInputRef.current.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          const content = event.target?.result as string;
          if (content) {
              if (confirm("تحذير: استعادة النسخة الاحتياطية ستقوم بحذف بياناتك الحالية واستبدالها. هل أنت متأكد؟")) {
                  importSaveData(content);
              }
          }
      };
      reader.readAsText(file);
      e.target.value = '';
  };

  return (
    <div className="h-full overflow-y-auto no-scrollbar pb-24 animate-fade-in bg-game-bg text-game-text">

      {/* Header */}
      <div className="sticky top-0 z-20 bg-game-bg/90 backdrop-blur-md p-4 border-b border-game-border flex items-center gap-3">
          <Monitor className="text-game-primary" size={24} />
          <h2 className="text-2xl font-black text-game-text uppercase tracking-tighter">{t('settingsScreen')}</h2>
      </div>

      <div className="p-4 space-y-6">

        {/* 1. Profile Section */}
        <div className="bg-game-surface border border-game-border rounded-2xl overflow-hidden relative">
            <div className="absolute top-0 right-0 p-4 opacity-10">
                <Shield size={100} />
            </div>

            <div className="p-4 border-b border-game-border flex justify-between items-center relative z-10">
                <div className="flex items-center gap-2 text-game-primary">
                    <User size={18} />
                    <h3 className="font-bold text-sm uppercase tracking-widest">{t('profileSettings')}</h3>
                </div>
                {!isEditingProfile ? (
                    <button onClick={() => toggleEditProfile(true)} className="p-2 bg-game-surface-highlight rounded-lg hover:text-game-text text-game-text-muted transition-colors">
                        <Edit2 size={16} />
                    </button>
                ) : (
                     <div className="flex gap-2">
                        <button onClick={() => toggleEditProfile(false)} className="p-2 bg-game-surface-highlight rounded-lg text-red-400 hover:bg-red-900/20">
                            <X size={16} />
                        </button>
                        <button onClick={saveProfileChanges} className="p-2 bg-green-900/50 rounded-lg text-green-400 hover:bg-green-900/80 border border-green-800">
                            <Save size={16} />
                        </button>
                    </div>
                )}
            </div>

            <div className="p-4 relative z-10">
                <div className="flex items-center gap-4 mb-6">
                    <div className="w-16 h-16 bg-gradient-to-br from-game-surface-highlight to-game-bg rounded-full border-2 border-game-primary flex items-center justify-center shadow-[0_0_15px_rgba(var(--color-primary),0.3)]">
                        <User size={32} className="text-game-primary" />
                    </div>
                    <div className="flex-1">
                        {isEditingProfile ? (
                            <input 
                                type="text" 
                                value={tempProfile.name}
                                onChange={(e) => setTempProfile({...tempProfile, name: e.target.value})}
                                className="bg-game-bg border border-game-border rounded px-2 py-1 text-game-text font-bold w-full focus:border-game-primary outline-none"
                            />
                        ) : (
                            <h2 className="text-xl font-black text-game-text">{playerProfile?.name}</h2>
                        )}
                        <p className="text-xs text-game-primary font-mono uppercase tracking-widest">{t('jobTitle')}</p>
                    </div>
                </div>

                <div className="grid grid-cols-3 gap-2">
                    <div className="bg-game-bg/40 p-2 rounded border border-game-border text-center">
                        <span className="text-[10px] text-game-text-muted uppercase block mb-1">{t('age')}</span>
                        {isEditingProfile ? (
                            <input 
                                type="number" 
                                value={tempProfile.age}
                                onChange={(e) => setTempProfile({...tempProfile, age: Number(e.target.value)})}
                                className="bg-game-surface w-full text-center text-sm font-bold text-game-text outline-none rounded"
                            />
                        ) : (
                            <span className="text-lg font-bold text-game-text">{playerProfile?.age}</span>
                        )}
                    </div>
                    <div className="bg-game-bg/40 p-2 rounded border border-game-border text-center">
                        <span className="text-[10px] text-game-text-muted uppercase block mb-1">{t('height')}</span>
                        {isEditingProfile ? (
                             <input 
                                type="number" 
                                value={tempProfile.height}
                                onChange={(e) => setTempProfile({...tempProfile, height: Number(e.target.value)})}
                                className="bg-game-surface w-full text-center text-sm font-bold text-game-text outline-none rounded"
                            />
                        ) : (
                             <span className="text-lg font-bold text-game-text">{playerProfile?.height} <span className="text-[10px]">cm</span></span>
                        )}
                    </div>
                    <div className="bg-game-bg/40 p-2 rounded border border-game-border text-center">
                        <span className="text-[10px] text-game-text-muted uppercase block mb-1">{t('weight')}</span>
                        {isEditingProfile ? (
                             <input 
                                type="number" 
                                value={tempProfile.weight}
                                onChange={(e) => setTempProfile({...tempProfile, weight: Number(e.target.value)})}
                                className="bg-game-surface w-full text-center text-sm font-bold text-game-text outline-none rounded"
                            />
                        ) : (
                            <span className="text-lg font-bold text-game-text">{playerProfile?.weight} <span className="text-[10px]">kg</span></span>
                        )}
                    </div>
                </div>
            </div>
        </div>

        {/* 2. System Settings */}
        <div className="bg-game-surface border border-game-border rounded-2xl overflow-hidden">
             <div className="p-4 border-b border-game-border flex items-center gap-2 text-game-primary">
                <Activity size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">{t('systemSettings')}</h3>
            </div>

            <div className="divide-y divide-game-border">
                {/* Notifications */}
                <button 
                    onClick={handleNotificationClick}
                    className="w-full p-4 flex items-center justify-between hover:bg-game-surface-highlight transition-colors"
                >
                    <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-lg ${notificationsEnabled ? 'bg-green-900/20 text-green-500' : 'bg-game-surface-highlight text-game-text-muted'}`}>
                            <Bell size={18} />
                        </div>
                        <div className="text-left">
                            <p className="font-bold text-sm text-game-text">{t('notifications')}</p>
                            <p className="text-[10px] text-game-text-muted">{t('notificationsDesc')}</p>
                        </div>
                    </div>
                    <div className={`w-10 h-5 rounded-full p-0.5 transition-colors ${notificationsEnabled ? 'bg-green-600' : 'bg-game-border'}`}>
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${notificationsEnabled ? (language === 'ar' ? '-translate-x-5' : 'translate-x-5') : ''}`} />
                    </div>
                </button>

                {/* Notification Duration */}
                <div className="p-4 flex flex-col gap-3 bg-game-bg/20">
                     <div className="flex items-center gap-3 mb-1">
                        <div className="p-2 rounded-lg bg-game-surface-highlight text-game-text-muted">
                            <Clock size={18} />
                        </div>
                        <p className="font-bold text-sm text-game-text">{t('alertDuration')}</p>
                    </div>
                    <div className="grid grid-cols-4 gap-2">
                        {(['short', 'medium', 'long', 'persistent'] as NotificationDuration[]).map(d => (
                            <button
                                key={d}
                                onClick={() => handleDurationChange(d)}
                                className={`
                                    py-2 rounded-lg text-[10px] font-bold uppercase transition-all border
                                    ${notificationDuration === d 
                                        ? 'bg-game-surface-highlight text-game-text border-game-text' 
                                        : 'bg-game-bg text-game-text-muted border-game-border hover:border-game-text-muted'}
                                `}
                            >
                                {d}
                            </button>
                        ))}
                    </div>
                </div>

                 {/* Volume Control */}
                 <div className="w-full p-4 flex flex-col gap-3">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-game-surface-highlight text-game-text-muted">
                                {soundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
                            </div>
                            <p className="font-bold text-sm text-game-text">{t('soundEffects')}</p>
                        </div>
                        <span className="text-xs font-mono text-game-text-muted">{(soundVolume * 100).toFixed(0)}%</span>
                    </div>

                    <div className="flex items-center gap-4">
                        <button 
                            onClick={() => {
                                if(soundEnabled) AudioService.playToggle(!soundEnabled);
                                updateSettings({ soundEnabled: !soundEnabled });
                            }}
                            className={`w-10 h-5 rounded-full p-0.5 transition-colors ${soundEnabled ? 'bg-game-primary' : 'bg-game-border'}`}
                        >
                            <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${soundEnabled ? (language === 'ar' ? '-translate-x-5' : 'translate-x-5') : ''}`} />
                        </button>
                        <input 
                            type="range" 
                            min="0" 
                            max="1" 
                            step="0.05"
                            value={soundVolume}
                            onChange={(e) => updateSettings({ soundVolume: parseFloat(e.target.value), soundEnabled: true })}
                            className="flex-1 h-2 bg-game-border rounded-lg appearance-none cursor-pointer accent-game-primary"
                        />
                    </div>
                </div>

                {/* Haptics */}
                 <button 
                    onClick={handleHapticsToggle}
                    className="w-full p-4 flex items-center justify-between hover:bg-game-surface-highlight transition-colors"
                >
                    <div className="flex items-center gap-3">
                        <div className="p-2 rounded-lg bg-game-surface-highlight text-game-text-muted">
                            <Smartphone size={18} />
                        </div>
                        <p className="font-bold text-sm text-game-text">{t('hapticFeedback')}</p>
                    </div>
                    <div className={`w-10 h-5 rounded-full p-0.5 transition-colors ${hapticsEnabled ? 'bg-game-primary' : 'bg-game-border'}`}>
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${hapticsEnabled ? (language === 'ar' ? '-translate-x-5' : 'translate-x-5') : ''}`} />
                    </div>
                </button>

                {/* Language */}
                <div className="p-4 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="p-2 rounded-lg bg-game-surface-highlight text-game-text-muted">
                            <Globe size={18} />
                        </div>
                        <p className="font-bold text-sm text-game-text">{t('language')}</p>
                    </div>
                    <div className="flex bg-game-bg rounded-lg p-1 border border-game-border">
                        <button 
                            onClick={() => changeLanguage('ar')}
                            className={`px-3 py-1 rounded text-xs font-bold transition-colors ${language === 'ar' ? 'bg-game-primary text-white' : 'text-game-text-muted hover:text-game-text'}`}
                        >
                            AR
                        </button>
                        <button 
                             onClick={() => changeLanguage('en')}
                             className={`px-3 py-1 rounded text-xs font-bold transition-colors ${language === 'en' ? 'bg-game-primary text-white' : 'text-game-text-muted hover:text-game-text'}`}
                        >
                            EN
                        </button>
                    </div>
                </div>
            </div>
        </div>

        {/* 3. Security */}
        <div className="bg-game-surface border border-game-border rounded-2xl overflow-hidden p-4">
             <div className="flex items-center gap-2 mb-4 text-emerald-500">
                <Lock size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">{t('securitySection')}</h3>
            </div>

            <div className="space-y-4">
                <div className="flex items-start justify-between bg-game-bg/40 p-3 rounded-xl border border-game-border">
                    <div className="flex gap-3">
                        <Bell size={18} className="text-game-text-muted mt-1" />
                        <div>
                            <h4 className="text-xs font-bold text-game-text">{t('permNotificationsTitle')}</h4>
                            <p className="text-[10px] text-game-text-muted leading-tight mt-1 max-w-[200px]">
                                {t('permNotificationsDesc')}
                            </p>
                        </div>
                    </div>
                    <span className={`text-[9px] font-bold px-2 py-1 rounded border uppercase ${notificationsEnabled ? 'text-green-400 border-green-900 bg-green-900/20' : 'text-red-400 border-red-900 bg-red-900/20'}`}>
                        {notificationsEnabled ? t('permGranted') : t('permDenied')}
                    </span>
                </div>

                <div className="flex items-start justify-between bg-game-bg/40 p-3 rounded-xl border border-game-border">
                    <div className="flex gap-3">
                        <FileText size={18} className="text-game-text-muted mt-1" />
                        <div>
                            <h4 className="text-xs font-bold text-game-text">{t('permStorageTitle')}</h4>
                            <p className="text-[10px] text-game-text-muted leading-tight mt-1 max-w-[200px]">
                                {t('permStorageDesc')}
                            </p>
                        </div>
                    </div>
                    <span className="text-[9px] font-bold px-2 py-1 rounded border uppercase text-blue-400 border-blue-900 bg-blue-900/20">
                        {t('permSystem')}
                    </span>
                </div>
            </div>
        </div>

        {/* 4. Visuals */}
        <div className="bg-game-surface border border-game-border rounded-2xl overflow-hidden p-4">
             <div className="flex items-center gap-2 mb-4 text-game-primary">
                <Palette size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">{t('theme')}</h3>
            </div>

            <div className="grid grid-cols-2 gap-3">
                {themes.map(theme => (
                    <button
                        key={theme.id}
                        onClick={() => changeTheme(theme.id)}
                        className={`
                            relative h-16 rounded-xl overflow-hidden transition-all border-2
                            ${themeColor === theme.id ? 'border-white scale-105 shadow-lg' : 'border-transparent opacity-60 hover:opacity-100'}
                        `}
                        style={{ backgroundColor: theme.color }}
                    >
                        <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent flex items-end p-2">
                             <span className="text-white font-bold text-xs">{theme.label}</span>
                             {themeColor === theme.id && <Check size={14} className="ml-auto text-white" />}
                        </div>
                    </button>
                ))}
            </div>
        </div>

        {/* 5. Backup & Data */}
        <div className="bg-game-surface border border-game-border rounded-2xl overflow-hidden p-4">
             <div className="flex items-center gap-2 mb-4 text-blue-400">
                <Save size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">إدارة البيانات</h3>
            </div>

            <div className="grid grid-cols-2 gap-3">
                <button
                    onClick={handleExport}
                    className="flex flex-col items-center justify-center gap-2 bg-game-surface-highlight p-4 rounded-xl hover:bg-game-bg border border-game-border transition-colors"
                >
                    <Download size={20} className="text-blue-400" />
                    <span className="text-xs font-bold text-game-text">تصدير نسخة</span>
                </button>

                <button
                    onClick={handleImportClick}
                    className="flex flex-col items-center justify-center gap-2 bg-game-surface-highlight p-4 rounded-xl hover:bg-game-bg border border-game-border transition-colors"
                >
                    <Upload size={20} className="text-yellow-400" />
                    <span className="text-xs font-bold text-game-text">استعادة نسخة</span>
                </button>
                <input 
                    type="file" 
                    ref={fileInputRef} 
                    onChange={handleFileChange} 
                    className="hidden" 
                    accept=".json"
                />
            </div>
        </div>

        {/* 6. Danger Zone */}
         <div className="bg-red-950/20 border border-red-900/50 rounded-2xl overflow-hidden p-4">
             <div className="flex items-center gap-2 mb-4 text-red-500">
                <AlertTriangle size={18} />
                <h3 className="font-bold text-sm uppercase tracking-widest">{t('dangerZone')}</h3>
            </div>
             <button 
                onClick={resetProgress}
                className="w-full flex items-center justify-center gap-2 bg-red-900/20 text-red-500 p-3 rounded-xl border border-red-900/50 hover:bg-red-900/40 transition-colors"
            >
                <RotateCcw size={16} />
                <span className="font-bold text-sm">{t('resetProgress')}</span>
            </button>
         </div>

         <div className="text-center">
            <p className="text-[10px] text-game-text-muted font-mono">SYSTEM VERSION 1.2.0 (STABLE)</p>
         </div>

      </div>
    </div>
  );
};

import { MOTIVATIONAL_QUOTES } from "../constants";
import { UserStats, Task } from "../types";

const STORAGE_KEY_LAST_SHOWN = 'motivation_last_shown_date';
const STORAGE_KEY_LAST_QUOTE_ID = 'motivation_last_quote_id';

export interface MotivationalQuote {
    id: number;
    text: string;
    category: string;
}

export const MotivationService = {
    /**
     * CORE LOGIC ENGINE:
     * Analyzes the user's current state (Stats, Time, Tasks) and returns a mathematically relevant quote.
     * No AI, just strict conditional logic.
     */
    getSmartAdvice: (stats: UserStats, tasks: Task[]): MotivationalQuote => {
        const hour = new Date().getHours();
        const pendingTasks = tasks.filter(t => !t.completed).length;

        // 1. Critical Energy State (< 20%)
        if (stats.energy <= 20) {
            return MotivationService.getByCategory(['resilience', 'system', 'rest']);
        }

        // 2. High Momentum (Streak > 5)
        if (stats.streak >= 5) {
            return MotivationService.getByCategory(['hunter', 'consistency', 'power']);
        }

        // 3. Broken Streak (Streak 0 but had history)
        // (Logic handled in GameContext mostly, but here we encourage restart)
        if (stats.streak === 0 && stats.level > 1) {
            return MotivationService.getByCategory(['discipline', 'persistence']);
        }

        // 4. Overwhelmed (Many pending tasks)
        if (pendingTasks > 5) {
            return MotivationService.getByCategory(['focus', 'action', 'stoicism']);
        }

        // 5. Time-Based Logic
        // Morning (5 AM - 9 AM) -> Action/Focus
        if (hour >= 5 && hour < 9) {
            return MotivationService.getByCategory(['action', 'focus', 'urgency']);
        }
        // Night (10 PM - 4 AM) -> Reflection/Rest
        if (hour >= 22 || hour < 4) {
            return MotivationService.getByCategory(['wisdom', 'stoicism', 'legacy']);
        }

        // Default: General Growth
        return MotivationService.getRandomQuote();
    },

    /**
     * Helper to filter quotes by specific categories
     */
    getByCategory: (categories: string[]): MotivationalQuote => {
        const pool = MOTIVATIONAL_QUOTES.filter(q => categories.includes(q.category));
        if (pool.length === 0) return MotivationService.getRandomQuote();

        const randomIndex = Math.floor(Math.random() * pool.length);
        return pool[randomIndex];
    },

    /**
     * Fallback: Get a random quote avoiding immediate repetition.
     */
    getRandomQuote: (): MotivationalQuote => {
        const lastId = Number(localStorage.getItem(STORAGE_KEY_LAST_QUOTE_ID) || -1);
        const availableQuotes = MOTIVATIONAL_QUOTES.filter(q => q.id !== lastId);
        const randomIndex = Math.floor(Math.random() * availableQuotes.length);
        const selectedQuote = availableQuotes[randomIndex];
        localStorage.setItem(STORAGE_KEY_LAST_QUOTE_ID, selectedQuote.id.toString());
        return selectedQuote;
    },

    /**
     * Daily System Check (First open of the day).
     */
    checkDailyQuote: (): MotivationalQuote | null => {
        const today = new Date().toISOString().split('T')[0];
        const lastShownDate = localStorage.getItem(STORAGE_KEY_LAST_SHOWN);

        if (lastShownDate !== today) {
            const quote = MotivationService.getRandomQuote(); // Keep daily random for variety
            localStorage.setItem(STORAGE_KEY_LAST_SHOWN, today);
            return quote;
        }
        return null;
    }
};

import React, { useState } from 'react';
import { MotivationService, MotivationalQuote } from '../services/motivationService';
import { Zap, Quote, Terminal, Cpu } from 'lucide-react';
import { useGame } from '../context/GameContext';
import { useSettings } from '../context/SettingsContext';
import { AudioService } from '../services/audioService';

export const AICoach: React.FC = () => {
  const { playerProfile, stats, tasks } = useGame();
  const { soundEnabled, hapticsEnabled, t } = useSettings();
  const [quote, setQuote] = useState<MotivationalQuote | null>(null);
  const [isCooldown, setIsCooldown] = useState(false);
  const [animate, setAnimate] = useState(false);

  const handleBoost = () => {
    if (isCooldown) return;

    // Feedback
    if (hapticsEnabled && navigator.vibrate) navigator.vibrate(50);
    if (soundEnabled) AudioService.playBoost();

    // USE DETERMINISTIC ENGINE
    const newQuote = MotivationService.getSmartAdvice(stats, tasks);

    setQuote(newQuote);
    setAnimate(true);

    // Reset animation class
    setTimeout(() => setAnimate(false), 500);

    // Start Cooldown
    setIsCooldown(true);
    setTimeout(() => setIsCooldown(false), 5000); // 5 seconds cooldown
  };

  return (
    <div className="h-full overflow-y-auto no-scrollbar flex flex-col items-center justify-center p-6 text-center space-y-8 animate-fade-in pb-20 bg-game-black">

      {/* Header */}
      <div className="flex flex-col items-center gap-2">
        <div className="w-20 h-20 bg-neutral-900 rounded-xl flex items-center justify-center border border-game-red shadow-[0_0_20px_rgba(220,38,38,0.2)] relative overflow-hidden">
            {/* Scanline */}
            <div className="absolute inset-0 bg-scanlines opacity-50"></div>
            <Cpu size={40} className="text-game-red animate-pulse relative z-10" />
        </div>
        <h2 className="text-2xl font-black text-white uppercase tracking-tighter mt-2">{t('motivationBooster')}</h2>
        <div className="flex items-center gap-2 bg-neutral-900 px-3 py-1 rounded border border-neutral-800">
            <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
            <p className="text-neutral-400 text-[10px] font-mono tracking-widest">{t('systemActive')}</p>
        </div>
      </div>

      {/* Quote Display Area */}
      <div className="w-full max-w-md min-h-[180px] flex items-center justify-center relative">
        {quote ? (
            <div className={`
                relative bg-neutral-900/80 border border-neutral-700 p-8 rounded-sm shadow-lg 
                transition-all duration-500 backdrop-blur-md
                ${animate ? 'scale-95 opacity-50 blur-sm' : 'scale-100 opacity-100'}
            `}>
                {/* Decorative Terminal Corners */}
                <div className="absolute top-0 left-0 w-2 h-2 border-t border-l border-game-red"></div>
                <div className="absolute top-0 right-0 w-2 h-2 border-t border-r border-game-red"></div>
                <div className="absolute bottom-0 left-0 w-2 h-2 border-b border-l border-game-red"></div>
                <div className="absolute bottom-0 right-0 w-2 h-2 border-b border-r border-game-red"></div>

                <Quote className="absolute top-4 right-4 text-neutral-700 rotate-180" size={24} />

                <div className="mb-4 flex justify-center">
                    <span className="text-[9px] bg-neutral-800 text-game-red px-2 py-0.5 rounded border border-neutral-700 uppercase tracking-widest font-mono">
                        SYSTEM_MSG :: {quote.category.toUpperCase()}
                    </span>
                </div>

                <p className="text-lg font-bold text-white leading-relaxed font-sans direction-rtl">
                    "{quote.text}"
                </p>

                <Quote className="absolute bottom-4 left-4 text-neutral-700" size={24} />
            </div>
        ) : (
            <div className="text-neutral-600 space-y-3 font-mono text-xs border border-neutral-800 p-6 rounded bg-black/40">
                <p>> SYSTEM READY.</p>
                <p>> WAITING FOR INPUT...</p>
                <p className="text-game-red animate-pulse">> {playerProfile?.name || 'USER'} DETECTED.</p>
            </div>
        )}
      </div>

      {/* Interaction Button */}
      <button
        onClick={handleBoost}
        disabled={isCooldown}
        className={`
            group relative flex items-center gap-3 px-8 py-4 rounded-sm font-black text-sm uppercase tracking-widest transition-all duration-300 border
            ${isCooldown 
                ? 'bg-neutral-900 text-neutral-600 border-neutral-800 cursor-not-allowed' 
                : 'bg-white text-black border-white hover:bg-neutral-200 hover:shadow-[0_0_25px_rgba(255,255,255,0.3)]'}
        `}
      >
        {isCooldown ? (
            <span className="flex items-center gap-2">
                <Terminal size={14} className="animate-spin" />
                {t('charging')}
            </span>
        ) : (
            <>
                <span className="font-mono">{t('boostBtn')}</span>
                <Zap className="fill-black group-hover:rotate-12 transition-transform" size={16} />
            </>
        )}
      </button>

      <div className="absolute bottom-24 text-[9px] text-neutral-700 font-mono">
        LOCAL ENGINE v3.0 • NO CLOUD SYNC
      </div>
    </div>
  );
};

